INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'casta-phoi-hop-ubnd-xa-thanh-phu-to-chuc-tap-huan-chuyen-doi-so-va-ung-dung-tri-tue-nhan-tao-cho-can-bo-cong-chuc-cap-xa', N'CASTA phối hợp UBND xã Thạnh Phú tổ chức tập huấn chuyển đổi số và ứng dụng trí tuệ nhân tạo cho cán bộ, công chức cấp xã', N'<p>Thực hiện chương trình hỗ trợ nâng cao năng lực chuyển đổi số tại địa phương, chiều ngày 19/6/2026, Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ (TTUD) đã phối hợp với UBND xã Thạnh Phú tổ chức lớp tập huấn “Cập nhật kiến thức, kỹ năng chuyển đổi số và ứng dụng công nghệ trí tuệ nhân tạo (AI) cho cán bộ, công chức cấp xã năm 2026”.</p><p>Tham dự buổi tập huấn có đại diện lãnh đạo UBND xã Thạnh Phú, thành viên Ban Chỉ đạo phát triển khoa học, công nghệ, đổi mới sáng tạo, chuyển đổi số và Đề án 06 của xã cùng toàn thể cán bộ, công chức địa phương.</p><figure class="image"><img style="aspect-ratio:1280/960;" src="/uploads/tin-su-kien/38b29b3c5b951003.png" width="1280" height="960"><figcaption>Toàn cảnh buổi tập huấn</figcaption></figure><p>Tại buổi tập huấn, đội ngũ tập huấn TTUD đã giới thiệu những nội dung cơ bản về chuyển đổi số trong cơ quan nhà nước, xu hướng phát triển và ứng dụng trí tuệ nhân tạo trong hoạt động quản lý, điều hành, cải cách hành chính và cung cấp dịch vụ công. Bên cạnh đó, các cán bộ, công chức xã được hướng dẫn thực hành một số công cụ AI hỗ trợ công việc chuyên môn như soạn thảo văn bản, tổng hợp thông tin, xây dựng báo cáo, lập kế hoạch công tác và hỗ trợ công tác truyền thông.</p><figure class="image"><img style="aspect-ratio:953/619;" src="/uploads/tin-su-kien/04d1351493eb9f72.png" width="953" height="619"><figcaption>Các đại biểu chụp ảnh lưu niệm, đánh dấu sự phối hợp giữa TTUD và UBND xã Thạnh Phú trong hoạt động nâng cao năng lực chuyển đổi số cho cán bộ, công chức địa phương.</figcaption></figure><p>Thông qua các nội dung trình bày và trao đổi trực tiếp, cán bộ, công chức xã Thạnh Phú đã có cơ hội tiếp cận các công nghệ mới, nâng cao nhận thức về vai trò của chuyển đổi số và ứng dụng AI trong thực hiện nhiệm vụ chuyên môn. Đồng thời, các đại biểu cũng thảo luận, chia sẻ những khó khăn, vướng mắc trong quá trình triển khai chuyển đổi số tại địa phương và đề xuất các giải pháp phù hợp với điều kiện thực tế.</p><p>Buổi tập huấn diễn ra trong không khí sôi nổi, thiết thực và nhận được sự quan tâm của các đại biểu tham dự. Đây là hoạt động góp phần nâng cao năng lực số cho đội ngũ cán bộ, công chức cấp xã, từng bước thúc đẩy quá trình chuyển đổi số trong hoạt động quản lý nhà nước, đáp ứng yêu cầu phát triển kinh tế - xã hội trong giai đoạn mới.</p><p>Trong thời gian tới, TTUD sẽ tiếp tục phối hợp với các địa phương trên địa bàn thành phố Cần Thơ triển khai các hoạt động đào tạo, tập huấn và chuyển giao các giải pháp khoa học công nghệ, góp phần thúc đẩy đổi mới sáng tạo, chuyển đổi số và nâng cao hiệu quả hoạt động của cơ quan, đơn vị.</p>', N'', N'Thực hiện chương trình hỗ trợ nâng cao năng lực chuyển đổi số tại địa phương, chiều ngày 19/6/2026, Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ (TTUD) đã phối hợp với UBND xã Thạnh Phú tổ chức lớ', '/uploads/tin-su-kien/f10d9b485f01cb15.png', '2026-06-20');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'giai-phap-cong-nghe-xanh-tu-pharos-nhan-duoc-su-huong-ung-tich-cuc-tu-cong-dong', N'Giải pháp công nghệ xanh từ PHAROS nhận được sự hưởng ứng tích cực từ cộng đồng', N'<p>Tại nhiều địa phương khu vực Đồng bằng sông Cửu Long, người dân bày tỏ sự phấn khởi khi được tiếp cận các sản phẩm ứng dụng công nghệ xanh, đặc biệt là các giải pháp sử dụng năng lượng sạch trong sản xuất và vận chuyển. Không chỉ mang lại lợi ích kinh tế, các sản phẩm còn góp phần thay đổi nhận thức về sử dụng năng lượng thân thiện với môi trường, hướng tới mô hình phát triển bền vững và giảm phát thải khí nhà kính.</p><figure class="image"><img style="aspect-ratio:5112/3752;" src="/uploads/tin-su-kien/3cd5ac8566d5f725.png" width="5112" height="3752"><figcaption>Bàn giao hệ thống đẩy bằng động cơ điện cho các đơn vị thụ hưởng</figcaption></figure><p>Một trong những hoạt động tiêu biểu là chương trình hỗ trợ hệ thống đẩy bằng động cơ điện cho các hợp tác xã trên địa bàn phường Long Mỹ. Chương trình do Mặt trận Tổ quốc Việt Nam phường Long Mỹ, Hội Nông dân phường Long Mỹ phối hợp cùng Trung tâm Ứng dụng tiến bộ khoa học và công nghệ thành phố Cần Thơ triển khai, trao tặng 04 hệ thống đẩy bằng động cơ điện cho Hợp tác xã Toàn Tâm, Hợp tác xã Dịch vụ nông nghiệp Long Trị A, Hợp tác xã Nhân Giống và Hợp tác xã Quýt Đường. Các hệ thống được trang bị động cơ điện công suất 2,0 kW, sử dụng nguồn pin và bộ điều khiển điện tử hiện đại, giúp vận hành ổn định, giảm chi phí nhiên liệu, hạn chế tiếng ồn và giảm tác động đến môi trường.</p><figure class="image"><img style="aspect-ratio:1280/686;" src="/uploads/tin-su-kien/4da160f9fe1cf615.jpg" width="1280" height="686"><figcaption>Đại diện các đơn vị và hợp tác xã tiếp nhận thiết bị động cơ điện phục vụ sản xuất, vận chuyển.</figcaption></figure><p>Ngay sau khi tiếp nhận và đưa vào sử dụng, các hợp tác xã đã đánh giá cao hiệu quả thực tiễn của giải pháp công nghệ này. Việc ứng dụng động cơ điện không chỉ góp phần giảm chi phí vận hành mà còn phù hợp với định hướng phát triển nông nghiệp xanh, thúc đẩy quá trình chuyển đổi xanh trong sản xuất nông nghiệp và kinh tế tập thể.</p><p>Trung tâm Ứng dụng tiến bộ khoa học và công nghệ thành phố Cần Thơ đánh giá cao sự quan tâm, phối hợp tích cực của Mặt trận Tổ quốc Việt Nam phường Long Mỹ và Hội Nông dân phường Long Mỹ trong việc triển khai chương trình. Sự đồng hành chặt chẽ của các đơn vị đã góp phần đưa những tiến bộ khoa học và công nghệ tiên tiến đến gần hơn với người dân, tạo điều kiện để các hợp tác xã tiếp cận, ứng dụng các giải pháp sản xuất và vận chuyển thân thiện với môi trường. Đồng thời, hoạt động cũng góp phần nâng cao nhận thức của cộng đồng về sử dụng năng lượng sạch, bảo vệ môi trường và phát triển bền vững.</p><p>Sự hưởng ứng tích cực từ các đơn vị thụ hưởng cho thấy nhu cầu ứng dụng công nghệ xanh trong đời sống và sản xuất đang ngày càng gia tăng, đồng thời khẳng định hiệu quả của các chương trình chuyển giao công nghệ khi các giải pháp tiên tiến được triển khai đúng đối tượng, đáp ứng nhu cầu thực tiễn của địa phương. Thông qua các hoạt động hợp tác và chuyển giao công nghệ, Công ty PHAROS MARINE. INC cùng các đơn vị phối hợp đang góp phần đưa những giải pháp đổi mới sáng tạo đến gần hơn với cộng đồng, tạo ra giá trị kinh tế, xã hội và môi trường.</p><p>Trong thời gian tới, Trung tâm Ứng dụng tiến bộ khoa học và công nghệ thành phố Cần Thơ mong muốn tiếp tục nhận được sự phối hợp, đồng hành của các cơ quan, đơn vị và doanh nghiệp để triển khai nhiều hoạt động ứng dụng, chuyển giao công nghệ xanh thiết thực hơn nữa, góp phần thúc đẩy chuyển đổi xanh, xây dựng nền nông nghiệp hiện đại, thân thiện với môi trường và hướng tới mục tiêu phát triển bền vững của khu vực Đồng bằng sông Cửu Long.</p>', N'', N'Tại nhiều địa phương khu vực Đồng bằng sông Cửu Long, người dân bày tỏ sự phấn khởi khi được tiếp cận các sản phẩm ứng dụng công nghệ xanh, đặc biệt là các giải pháp sử dụng năng lượng sạch trong sản ', '/uploads/tin-su-kien/c802cd21e11743f5.jpg', '2026-06-18');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'casta-cau-noi-dua-khoa-hoc-cong-nghe-va-chuyen-doi-so-den-gan-hon-voi-dia-phuong', N'CASTA – Cầu nối đưa khoa học công nghệ và chuyển đổi số đến gần hơn với địa phương', N'<p>Trong bối cảnh chuyển đổi số đang trở thành động lực quan trọng cho phát triển kinh tế - xã hội, Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ thành phố Cần Thơ (CASTA) đang phát huy vai trò là đơn vị ứng dụng, kết nối và chuyển giao khoa học công nghệ, tích cực đồng hành cùng các phường, xã trên địa bàn thành phố trong việc khảo sát nhu cầu thực tiễn, kết nối nguồn lực và tiếp cận các giải pháp chuyển đổi số phù hợp.</p><figure class="image"><img style="aspect-ratio:915/686;" src="/uploads/tin-su-kien/a41a4ab8e07b6c70.png" width="915" height="686"><figcaption>CASTA đồng hành cùng xã Trường Thành trong hành trình chuyển đổi số</figcaption></figure><p>Thời gian qua, CASTA đã triển khai nhiều hoạt động làm việc trực tiếp với các địa phương như xã Thạnh Phú, xã Trường Thành, xã Nhu Gia, xã Đông Hiệp, phường Tân An và nhiều đơn vị khác nhằm tìm hiểu nhu cầu ứng dụng khoa học công nghệ trong quản lý, điều hành và phát triển kinh tế - xã hội.</p><p>Thông qua các chương trình khảo sát, trao đổi chuyên môn và kết nối với doanh nghiệp công nghệ, CASTA xây dựng kế hoạch từng bước hỗ trợ địa phương tiếp cận các giải pháp về chính quyền số, kinh tế số, xã hội số, giáo dục số, truy xuất nguồn gốc, quản lý dữ liệu và các nền tảng công nghệ phục vụ người dân.</p><figure class="image"><img style="aspect-ratio:957/778;" src="/uploads/tin-su-kien/8fcd16f509dab3bb.jpg" width="957" height="778"><figcaption>Lãnh đạo xã Trường Thành chia sẻ nhu cầu và định hướng triển khai chuyển đổi số phù hợp với điều kiện thực tế của địa phương.</figcaption></figure><p>Không chỉ giới thiệu giải pháp, CASTA còn đóng vai trò cầu nối giữa địa phương với các chuyên gia, doanh nghiệp và tổ chức khoa học công nghệ, góp phần lựa chọn những mô hình phù hợp với điều kiện thực tế, nguồn lực và định hướng phát triển của từng địa phương.</p><figure class="image"><img style="aspect-ratio:915/686;" src="/uploads/tin-su-kien/81bd22392186510c.png" width="915" height="686"><figcaption>Toàn cảnh buổi làm việc tại phường Tân An, thành phố Cần Thơ</figcaption></figure><p>Trong chiến lược phát triển khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số của thành phố Cần Thơ, vai trò của các tổ chức trung gian ngày càng được đề cao. Với lợi thế là đơn vị trực thuộc ngành khoa học và công nghệ, CASTA đang từng bước khẳng định vị trí là cầu nối đưa các thành tựu khoa học công nghệ đến gần hơn với chính quyền cơ sở, doanh nghiệp và người dân.</p><p>Với phương châm lấy nhu cầu thực tiễn làm trung tâm, CASTA sẽ tiếp tục đồng hành cùng các địa phương trong việc kết nối nguồn lực khoa học công nghệ, thúc đẩy ứng dụng các giải pháp đổi mới sáng tạo và chuyển đổi số vào thực tiễn. Qua đó góp phần xây dựng chính quyền số, phát triển kinh tế số và nâng cao chất lượng cuộc sống của người dân trên địa bàn thành phố Cần Thơ.</p><p> </p>', N'Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ thành phố Cần Thơ', N'Trong bối cảnh chuyển đổi số đang trở thành động lực quan trọng cho phát triển kinh tế - xã hội, Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ thành phố Cần Thơ (CASTA) đang phát huy vai trò là đơn', '/uploads/tin-su-kien/30d86bbf75e4d436.jpg', '2026-06-17');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'casta-trong-vai-tro-cau-noi-khoa-hoc-cong-nghe-quoc-te', N'CASTA trong vai trò cầu nối khoa học công nghệ quốc tế', N'<p>Trong bối cảnh hội nhập quốc tế ngày càng sâu rộng, khoa học, công nghệ và đổi mới sáng tạo đang trở thành động lực quan trọng thúc đẩy phát triển kinh tế - xã hội bền vững. Với chức năng nghiên cứu, ứng dụng, chuyển giao tiến bộ khoa học và công nghệ phục vụ phát triển địa phương, Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ thành phố Cần Thơ (CASTA) đã và đang khẳng định vai trò là cầu nối hiệu quả giữa các tổ chức khoa học công nghệ trong nước, quốc tế với doanh nghiệp, địa phương và cộng đồng vùng Đồng bằng sông Cửu Long.</p><p>Năng lực triển khai và kết nối khoa học công nghệ</p><p>Là đơn vị sự nghiệp khoa học và công nghệ trực thuộc Sở Khoa học và Công nghệ thành phố Cần Thơ, CASTA sở hữu đội ngũ cán bộ chuyên môn có kinh nghiệm trong nghiên cứu ứng dụng, chuyển giao công nghệ và triển khai các mô hình thực nghiệm phục vụ sản xuất và đời sống.</p><p>Trong nhiều năm qua, Trung tâm đã xây dựng và vận hành các phòng thí nghiệm, khu trình diễn công nghệ, mô hình ứng dụng trong lĩnh vực nông nghiệp công nghệ cao, công nghệ sinh học, công nghệ môi trường, năng lượng tái tạo, chuyển đổi số và đổi mới sáng tạo. Đây là nền tảng quan trọng giúp CASTA tiếp nhận, làm chủ và chuyển giao hiệu quả các công nghệ tiên tiến từ các đối tác trong và ngoài nước.</p><figure class="image"><img style="aspect-ratio:6000/4000;" src="/uploads/tin-su-kien/0fcf670cfbf4982d.jpg" width="6000" height="4000"><figcaption>CASTA đồng hành cùng người nông dân địa phương, chuyển giao những công nghệ tiên tiến đến từ đối tác Hàn Quốc</figcaption></figure><p>Bên cạnh năng lực chuyên môn, Trung tâm còn là đầu mối kết nối giữa các viện nghiên cứu, trường đại học, tổ chức quốc tế, doanh nghiệp và cơ quan quản lý nhà nước nhằm thúc đẩy quá trình thương mại hóa kết quả nghiên cứu và đưa công nghệ mới vào thực tiễn sản xuất.</p><p>Đẩy mạnh hoạt động chuyển giao công nghệ và hợp tác quốc tế</p><p>Những năm gần đây, CASTA không ngừng mở rộng mạng lưới hợp tác với các tổ chức, doanh nghiệp và chuyên gia quốc tế trong nhiều lĩnh vực có tiềm năng ứng dụng tại Đồng bằng sông Cửu Long.</p><p>Thông qua các hội thảo khoa học, diễn đàn công nghệ, chương trình kết nối cung - cầu công nghệ và các dự án hợp tác quốc tế, Trung tâm đã tạo điều kiện để các công nghệ tiên tiến được giới thiệu, thử nghiệm và từng bước triển khai tại địa phương.</p><p>Đặc biệt, việc tham gia thúc đẩy hợp tác quốc tế về ứng dụng công nghệ xanh trong giao thông thủy vùng Đồng bằng sông Cửu Long tiếp tục khẳng định vai trò của CASTA trong việc kết nối các nguồn lực khoa học công nghệ toàn cầu nhằm giải quyết các thách thức phát triển của khu vực.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/3e4f949645d5821f.jpg" width="2560" height="1920"><figcaption>Hội thảo Tổng kết Dự án CTS Seed 1<br>Dự án Xây dựng Cơ sở Thử nghiệm Phương tiện Thủy Thân thiện Môi trường tại Đồng bằng Sông Cửu Long, Việt Nam</figcaption></figure><p>Hướng tới trung tâm kết nối công nghệ của vùng Đồng bằng sông Cửu Long</p><p>Trong thời gian tới, CASTA tiếp tục phát huy vai trò là đầu mối kết nối, tiếp nhận và lan tỏa các tiến bộ khoa học công nghệ tiên tiến từ trong nước và quốc tế. Trung tâm sẽ tập trung mở rộng hợp tác với các tổ chức nghiên cứu, doanh nghiệp công nghệ và đối tác quốc tế nhằm thúc đẩy chuyển giao các giải pháp đổi mới sáng tạo phục vụ phát triển kinh tế xanh, kinh tế tuần hoàn và chuyển đổi số.</p><p>Với định hướng lấy ứng dụng thực tiễn làm trọng tâm, CASTA kỳ vọng sẽ tiếp tục là cầu nối tin cậy giữa khoa học công nghệ và phát triển địa phương, góp phần xây dựng thành phố Cần Thơ trở thành trung tâm khoa học công nghệ của vùng Đồng bằng sông Cửu Long trong giai đoạn mới.</p>', N'Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ thành phố Cần Thơ', N'Trong bối cảnh hội nhập quốc tế ngày càng sâu rộng, khoa học, công nghệ và đổi mới sáng tạo đang trở thành động lực quan trọng thúc đẩy phát triển kinh tế - xã hội bền vững. Với chức năng nghiên cứu, ', '/uploads/tin-su-kien/377a875af1c258e8.jpg', '2026-06-16');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'trung-tam-ung-dung-tien-bo-khoa-hoc-va-cong-nghe-thanh-pho-can-tho-thuc-day-hop-tac-quoc-te-ung-dung-cong-nghe-xanh-trong-giao-thong-thuy-vung-dong-bang-song-cuu-long', N'Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ thành phố Cần Thơ thúc đẩy hợp tác quốc tế, ứng dụng công nghệ xanh trong giao thông thủy vùng Đồng bằng sông Cửu Long', N'<p>Ngày 16/6/2026, tại Cần Thơ đã diễn ra Hội thảo tổng kết Dự án “Xây dựng cơ sở thử nghiệm phương tiện thủy thân thiện môi trường tại Đồng bằng sông Cửu Long” thuộc Chương trình KOICA CTS Seed 1 do Công ty Pharos Marine (Hàn Quốc) chủ trì thực hiện. Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ TP. Cần Thơ là đơn vị phối hợp triển khai các hoạt động kết nối, hỗ trợ thử nghiệm, đào tạo và chuyển giao công nghệ tại địa phương. Dự án được triển khai với mục tiêu giảm thiểu ô nhiễm môi trường và phát thải khí nhà kính từ các phương tiện thủy sử dụng động cơ đốt trong truyền thống, đồng thời góp phần xây dựng hệ sinh thái giao thông thủy xanh, thông minh và bền vững tại khu vực Đồng bằng sông Cửu Long.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/693a61e228d693d6.png" width="2560" height="1920"><figcaption>Hội thảo Tổng kết Dự án CTS Seed 1</figcaption></figure><p>Một trong những kết quả nổi bật của dự án là hoạt động chuyển giao công nghệ động cơ điện cho phương tiện thủy giữa Công ty Pharos Marine và các hợp tác xã, cá nhân thụ hưởng tại thành phố Cần Thơ. Thông qua chương trình, 100 bộ động cơ điện ngoài thân thuyền cùng hệ thống pin và các trang thiết bị hỗ trợ đã được bàn giao cho các tổ chức, cá nhân tham gia mô hình thí điểm.</p><p>Hoạt động chuyển giao không chỉ dừng lại ở việc cung cấp thiết bị mà còn bao gồm đào tạo vận hành, hướng dẫn bảo trì, hỗ trợ kỹ thuật và đánh giá hiệu quả ứng dụng trong điều kiện thực tế. Đây là quy trình chuyển giao công nghệ hoàn chỉnh, góp phần giúp người sử dụng từng bước tiếp cận, làm chủ và khai thác hiệu quả công nghệ mới.</p><figure class="image"><img style="aspect-ratio:1920/2560;" src="/uploads/tin-su-kien/cc4cb298f09df89c.png" width="1920" height="2560"><figcaption>Bộ hệ thống đẩy bằng động cơ điện</figcaption></figure><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/cf3b380dd49e064d.png" width="2560" height="1920"><figcaption>Kỹ sư đang chạy vận hành thử trên sông bằng hệ thống đẩy bằng động cơ điện</figcaption></figure><p>Việc tiếp nhận và vận hành thành công các hệ thống động cơ điện trên phương tiện thủy là minh chứng cho hiệu quả của mô hình hợp tác quốc tế trong lĩnh vực khoa học, công nghệ và đổi mới sáng tạo; đồng thời góp phần thúc đẩy quá trình chuyển đổi xanh, ứng dụng công nghệ tiên tiến vào hoạt động giao thông thủy tại khu vực Đồng bằng sông Cửu Long.</p><p>Thông qua dự án, Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ TP. Cần Thơ đã phát huy vai trò là cầu nối giữa doanh nghiệp công nghệ quốc tế với địa phương trong hoạt động chuyển giao và ứng dụng tiến bộ khoa học công nghệ. Việc triển khai thử nghiệm công nghệ động cơ điện trên phương tiện thủy không chỉ góp phần đánh giá hiệu quả thực tiễn của giải pháp mà còn tạo tiền đề cho việc xây dựng các mô hình ứng dụng công nghệ xanh phục vụ phát triển kinh tế và bảo vệ môi trường. Đồng thời, đây cũng là hoạt động thiết thực hưởng ứng các chương trình chuyển đổi số và chuyển đổi xanh của thành phố Cần Thơ, hướng tới xây dựng đô thị sinh thái, hiện đại và thích ứng với biến đổi khí hậu. </p><p>Kết quả bước đầu từ dự án cho thấy công nghệ động cơ điện hoàn toàn có tiềm năng ứng dụng rộng rãi trong lĩnh vực giao thông thủy nội địa, du lịch sinh thái và vận tải thủy quy mô nhỏ. Đây là cơ sở quan trọng để các cơ quan quản lý, doanh nghiệp và địa phương tiếp tục nghiên cứu, hoàn thiện cơ chế hỗ trợ và mở rộng mô hình trong thời gian tới. Trong giai đoạn tiếp theo, Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ thành phố Cần Thơ sẽ tiếp tục đẩy mạnh hợp tác với các tổ chức, doanh nghiệp trong và ngoài nước nhằm tìm kiếm, tiếp nhận và chuyển giao các công nghệ tiên tiến; đồng thời xây dựng các mô hình trình diễn, thử nghiệm và nhân rộng những giải pháp khoa học công nghệ có hiệu quả, góp phần hiện thực hóa các mục tiêu phát triển khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số trên địa bàn thành phố.</p>', N'', N'Ngày 16/6/2026, tại Cần Thơ đã diễn ra Hội thảo tổng kết Dự án “Xây dựng cơ sở thử nghiệm phương tiện thủy thân thiện môi trường tại Đồng bằng sông Cửu Long” thuộc Chương trình KOICA CTS Seed 1 do Côn', '/uploads/tin-su-kien/90f4606d94c54b58.jpg', '2026-06-16');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'truy-xuat-nguon-goc-chia-khoa-nang-cao-gia-tri-san-pham-ocop-va-san-pham-chu-luc-trong-thoi-ky-chuyen-doi-so', N'Truy xuất nguồn gốc – Chìa khóa nâng cao giá trị sản phẩm OCOP và sản phẩm chủ lực trong thời kỳ chuyển đổi số', N'<p>Trong bối cảnh hội nhập kinh tế quốc tế ngày càng sâu rộng, yêu cầu của người tiêu dùng đối với chất lượng, độ an toàn và tính minh bạch của sản phẩm ngày càng cao. Không chỉ quan tâm đến chất lượng sản phẩm, người tiêu dùng còn muốn biết sản phẩm được sản xuất ở đâu, quy trình sản xuất như thế nào, đơn vị nào chịu trách nhiệm và các tiêu chuẩn chất lượng đã được áp dụng. Chính vì vậy, truy xuất nguồn gốc đang trở thành một công cụ quan trọng giúp nâng cao năng lực cạnh tranh của sản phẩm, đặc biệt là các sản phẩm chủ lực và sản phẩm OCOP của địa phương.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/c1c52625918df498.JPG" width="6720" height="4480"></figure><p>Nhằm thúc đẩy ứng dụng khoa học công nghệ, đổi mới sáng tạo và chuyển đổi số trong sản xuất, kinh doanh, thành phố Cần Thơ đã tổ chức hoạt động “Kết nối cung cầu công nghệ - Sản phẩm chủ lực, OCOP gắn với truy xuất nguồn gốc thành phố Cần Thơ năm 2026”. Đây là sự kiện có ý nghĩa quan trọng, tạo diễn đàn kết nối giữa các nhà khoa học, viện nghiên cứu, trường đại học với doanh nghiệp, hợp tác xã và các chủ thể OCOP; đồng thời thúc đẩy việc ứng dụng công nghệ truy xuất nguồn gốc vào quản lý chất lượng, quảng bá và tiêu thụ sản phẩm.</p><p>Truy xuất nguồn gốc là quá trình theo dõi và xác định toàn bộ hành trình của sản phẩm từ khâu sản xuất, thu hoạch, chế biến, đóng gói, vận chuyển đến tay người tiêu dùng. Thông qua mã QR, mã số mã vạch, tem điện tử và các nền tảng số, người tiêu dùng có thể dễ dàng kiểm tra các thông tin liên quan đến sản phẩm chỉ bằng một thiết bị điện thoại thông minh. Điều này góp phần nâng cao tính minh bạch, tạo dựng niềm tin của khách hàng và bảo vệ quyền lợi người tiêu dùng.</p><p>Đối với các sản phẩm OCOP và sản phẩm chủ lực của thành phố Cần Thơ, truy xuất nguồn gốc không chỉ là công cụ quản lý mà còn là giải pháp nâng cao giá trị thương hiệu. Khi sản phẩm được minh bạch hóa thông tin, người tiêu dùng có thể dễ dàng nhận diện nguồn gốc, chất lượng và các chứng nhận liên quan. Đây là yếu tố quan trọng giúp các sản phẩm địa phương tạo dựng uy tín trên thị trường, mở rộng hệ thống phân phối, từng bước tiếp cận các thị trường lớn trong nước và quốc tế.</p><p>Bên cạnh đó, hệ thống truy xuất nguồn gốc còn hỗ trợ các cơ sở sản xuất, doanh nghiệp và hợp tác xã quản lý hiệu quả quy trình sản xuất. Các dữ liệu được số hóa giúp theo dõi chất lượng sản phẩm, kiểm soát nguyên liệu đầu vào, nâng cao hiệu quả quản trị và đáp ứng các yêu cầu ngày càng khắt khe của thị trường. Đây cũng là nền tảng quan trọng để thúc đẩy chuyển đổi số trong lĩnh vực nông nghiệp và chế biến nông sản.</p><p>Thành phố Cần Thơ hiện đang triển khai nhiều giải pháp nhằm xây dựng và phát triển hệ thống truy xuất nguồn gốc sản phẩm giai đoạn 2026 – 2030, từng bước chuẩn hóa công tác truy xuất bằng mã số, mã vạch, tem điện tử và nền tảng số. Việc đẩy mạnh ứng dụng công nghệ trong truy xuất nguồn gốc góp phần nâng cao hiệu quả quản lý nhà nước, hỗ trợ doanh nghiệp phát triển sản xuất kinh doanh, đồng thời tạo điều kiện thuận lợi cho hoạt động xúc tiến thương mại và xuất khẩu sản phẩm.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/f9fdfa206bb24f37.JPG" width="6720" height="4480"></figure><p>Trong khuôn khổ sự kiện “Kết nối cung cầu công nghệ - Sản phẩm chủ lực, OCOP gắn với truy xuất nguồn gốc thành phố Cần Thơ năm 2026”, nhiều mô hình, giải pháp và công nghệ mới về truy xuất nguồn gốc đã được giới thiệu đến các doanh nghiệp, hợp tác xã và chủ thể OCOP. Các hoạt động hội thảo, kết nối giao thương, trưng bày sản phẩm và tư vấn công nghệ đã góp phần nâng cao nhận thức về vai trò của truy xuất nguồn gốc trong phát triển sản phẩm bền vững, đồng thời mở ra nhiều cơ hội hợp tác giữa các đơn vị cung cấp công nghệ và các cơ sở sản xuất kinh doanh.</p><p>Trong thời gian tới, việc tiếp tục đẩy mạnh ứng dụng khoa học công nghệ và chuyển đổi số trong truy xuất nguồn gốc sẽ là một trong những giải pháp trọng tâm nhằm nâng cao chất lượng, giá trị gia tăng và sức cạnh tranh của các sản phẩm chủ lực, sản phẩm OCOP của thành phố Cần Thơ. Qua đó góp phần xây dựng thương hiệu sản phẩm địa phương, phát triển kinh tế nông nghiệp hiện đại, bền vững và đáp ứng yêu cầu của thị trường trong thời kỳ hội nhập.</p>', N'Trung tâm ứng dụng', N'Trong bối cảnh hội nhập kinh tế quốc tế ngày càng sâu rộng, yêu cầu của người tiêu dùng đối với chất lượng, độ an toàn và tính minh bạch của sản phẩm ngày càng cao. Không chỉ quan tâm đến chất lượng s', '/uploads/tin-su-kien/0b46c1a0cc3cffd0.JPG', '2026-05-31');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'hoi-thao-khoa-hoc-ket-noi-cung-cau-cong-nghe-ho-tro-phat-trien-san-pham-ocop-va-nong-san-chu-luc-dap-ung-yeu-cau-thi-truong-thuc-day-doi-moi-cong-nghe-nang-cao-nang-luc-canh-tranh-', N'Hội thảo khoa học “Kết nối cung cầu công nghệ hỗ trợ phát triển sản phẩm OCOP và nông sản chủ lực đáp ứng yêu cầu thị trường” – Thúc đẩy đổi mới công nghệ, nâng cao năng lực cạnh tranh cho nông sản Đồng bằng sông Cửu Long', N'<p>Sáng ngày 29/5/2026, tại Trung tâm Ứng dụng tiến bộ khoa học và công nghệ Cần Thơ, Hội thảo khoa học với chủ đề <strong>“Kết nối cung cầu công nghệ hỗ trợ phát triển sản phẩm OCOP và nông sản chủ lực đáp ứng yêu cầu thị trường”</strong> đã diễn ra thành công tốt đẹp với sự tham gia của đại diện các cơ quan quản lý nhà nước, viện, trường, doanh nghiệp, hợp tác xã, chủ thể OCOP cùng các chuyên gia trong lĩnh vực nông nghiệp, thương mại và công nghệ.</p><p>Hội thảo là một trong những hoạt động trọng tâm thuộc chuỗi sự kiện <strong>“Kết nối cung cầu công nghệ - Sản phẩm chủ lực, OCOP gắn với truy xuất nguồn gốc thành phố Cần Thơ năm 2026”</strong>, nhằm tạo diễn đàn kết nối giữa các nhà khoa học, doanh nghiệp cung ứng công nghệ, đơn vị sản xuất và cơ quan quản lý để cùng trao đổi, chia sẻ giải pháp công nghệ phục vụ phát triển sản phẩm OCOP và nông sản chủ lực theo hướng hiện đại, bền vững và đáp ứng yêu cầu ngày càng cao của thị trường trong nước và quốc tế.</p><p>Trong bối cảnh hội nhập kinh tế sâu rộng, các sản phẩm nông nghiệp không chỉ cạnh tranh về chất lượng mà còn phải đáp ứng các tiêu chuẩn kỹ thuật, yêu cầu an toàn thực phẩm, bảo vệ môi trường và truy xuất nguồn gốc. Do đó, việc ứng dụng khoa học công nghệ, chuyển đổi số và đổi mới quy trình sản xuất đang trở thành yếu tố then chốt giúp nâng cao giá trị gia tăng và năng lực cạnh tranh cho nông sản Việt Nam.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/012857a60bbe37f8.JPG" width="6720" height="4480"><figcaption>Ông Bùi Minh Châu - Phó Giám đốc Sở Khoa học và Công nghệ Thành phố Cần Thơ</figcaption></figure><p>Tại hội thảo, các đại biểu đã được cập nhật những thông tin mới nhất về xu hướng thị trường xuất khẩu nông sản và các yêu cầu kỹ thuật của nhiều quốc gia nhập khẩu. Chuyên gia thương mại quốc tế đã phân tích những thay đổi trong các quy định liên quan đến kiểm dịch thực vật, tiêu chuẩn chất lượng, phát thải carbon, trách nhiệm môi trường và đặc biệt là yêu cầu về truy xuất nguồn gốc sản phẩm. Đây được xem là những thách thức nhưng cũng là cơ hội để doanh nghiệp và hợp tác xã nâng cao năng lực quản lý, chuẩn hóa quy trình sản xuất và từng bước tham gia sâu hơn vào chuỗi giá trị toàn cầu.</p><p>Một trong những nội dung thu hút sự quan tâm của đại biểu là chuyên đề về ứng dụng nông nghiệp số trong quản lý sản xuất và phát triển sản phẩm OCOP. Đại diện doanh nghiệp cung cấp giải pháp nông nghiệp số đã giới thiệu các nền tảng công nghệ hỗ trợ giám sát vùng trồng, quản lý nhật ký sản xuất điện tử, truy xuất nguồn gốc, quản lý chất lượng và kết nối dữ liệu chuỗi cung ứng. Những giải pháp này không chỉ giúp nâng cao hiệu quả sản xuất mà còn góp phần xây dựng hệ sinh thái nông nghiệp thông minh, minh bạch và bền vững.</p><p>Các đại biểu tham dự cũng đặc biệt quan tâm đến các mô hình ứng dụng công nghệ số trong quản lý vùng nguyên liệu, kiểm soát chất lượng sản phẩm và tối ưu hóa quy trình sản xuất. Việc ứng dụng dữ liệu số trong sản xuất nông nghiệp được đánh giá là giải pháp quan trọng giúp doanh nghiệp và hợp tác xã nâng cao năng suất, giảm chi phí, đồng thời đáp ứng tốt hơn các yêu cầu của thị trường hiện đại.</p><p>Bên cạnh đó, nội dung về công nghệ chế biến sâu và bảo quản sau thu hoạch cho nông sản chủ lực vùng Đồng bằng sông Cửu Long đã mang đến nhiều thông tin hữu ích cho các doanh nghiệp và cơ sở sản xuất. Các chuyên gia đã chia sẻ những tiến bộ mới trong công nghệ sấy, cấp đông, cô đặc, chiết xuất, lên men và chế biến thực phẩm giá trị gia tăng nhằm kéo dài thời gian bảo quản, giảm tổn thất sau thu hoạch và nâng cao giá trị thương mại của sản phẩm.</p><p>TS. Thái Phương Vũ, Trường Đại học Tài nguyên và Môi trường Thành phố Hồ Chí Minh, đã trình bày nhiều giải pháp công nghệ phù hợp với điều kiện sản xuất của khu vực Đồng bằng sông Cửu Long, đồng thời nhấn mạnh vai trò của đổi mới sáng tạo trong phát triển chuỗi giá trị nông sản theo hướng xanh, tuần hoàn và thích ứng với biến đổi khí hậu.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/bf896a4dcfa84c24.JPG" width="6720" height="4480"><figcaption>TS. Thái Phương Vũ, Trường Đại học Tài nguyên và Môi trường Thành phố Hồ Chí Minh</figcaption></figure><p>Không chỉ dừng lại ở các báo cáo chuyên đề, hội thảo còn là dịp để các doanh nghiệp công nghệ, hợp tác xã, chủ thể OCOP và đơn vị sản xuất nông nghiệp trực tiếp trao đổi nhu cầu, tìm kiếm đối tác và cơ hội hợp tác chuyển giao công nghệ. Nhiều giải pháp mới trong lĩnh vực quản lý sản xuất, chế biến, bảo quản và truy xuất nguồn gốc đã được giới thiệu, mở ra nhiều hướng đi mới cho hoạt động đổi mới công nghệ trong nông nghiệp địa phương.</p><p>Trong khuôn khổ sự kiện, các đại biểu cũng đã tham quan khu vực trưng bày sản phẩm OCOP, sản phẩm chủ lực và các giải pháp công nghệ phục vụ sản xuất nông nghiệp. Hoạt động này góp phần tăng cường kết nối giữa bên cung và bên cầu công nghệ, tạo điều kiện để các doanh nghiệp, hợp tác xã tiếp cận những giải pháp phù hợp nhằm nâng cao chất lượng sản phẩm và mở rộng thị trường tiêu thụ.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/de680ba65c7414b5.JPG" width="6720" height="4480"><figcaption>Toàn cảnh Hội thảo</figcaption></figure><p>Hội thảo “Kết nối cung cầu công nghệ hỗ trợ phát triển sản phẩm OCOP và nông sản chủ lực đáp ứng yêu cầu thị trường” đã khép lại với nhiều kết quả tích cực, cung cấp những thông tin chuyên sâu, thiết thực và mang tính định hướng cho các đơn vị sản xuất kinh doanh nông nghiệp. Qua đó, góp phần thúc đẩy ứng dụng khoa học công nghệ, chuyển đổi số và đổi mới sáng tạo vào thực tiễn sản xuất, từng bước nâng cao giá trị sản phẩm OCOP và nông sản chủ lực của thành phố Cần Thơ nói riêng, vùng Đồng bằng sông Cửu Long nói chung.</p><p>Thành công của hội thảo tiếp tục khẳng định vai trò của khoa học và công nghệ trong phát triển nông nghiệp hiện đại, đồng thời tạo động lực thúc đẩy sự liên kết giữa các chủ thể trong hệ sinh thái đổi mới sáng tạo, hướng tới xây dựng nền nông nghiệp xanh, bền vững và có khả năng cạnh tranh cao trên thị trường trong nước và quốc tế.</p>', N'Trung tâm ứng dụng', N'Sáng ngày 29/5/2026, tại Trung tâm Ứng dụng tiến bộ khoa học và công nghệ Cần Thơ, Hội thảo khoa học với chủ đề “Kết nối cung cầu công nghệ hỗ trợ phát triển sản phẩm OCOP và nông sản chủ lực đáp ứng ', '/uploads/tin-su-kien/450e2a592380f6a0.JPG', '2026-05-29');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'day-manh-truy-xuat-nguon-goc-san-pham-ocop-gan-voi-chuyen-doi-so-va-thuong-mai-dien-tu', N'ĐẨY MẠNH TRUY XUẤT NGUỒN GỐC SẢN PHẨM OCOP GẮN VỚI CHUYỂN ĐỔI SỐ VÀ THƯƠNG MẠI ĐIỆN TỬ', N'<p>Trong khuôn khổ Hoạt động “Kết nối cung cầu công nghệ – Sản phẩm chủ lực, OCOP gắn với truy xuất nguồn gốc TP. Cần Thơ năm 2026”, chiều 28/5, tại Trung tâm Ứng dụng tiến bộ khoa học và công nghệ TP. Cần Thơ đã diễn ra Hội thảo khoa học với chủ đề “Truy xuất nguồn gốc sản phẩm OCOP gắn với chuyển đổi số và thương mại điện tử”.</p><p>Hội thảo dưới sự chủ trì của ông Bùi Minh Châu – Phó Giám đốc Sở Khoa học và Công nghệ TP. Cần Thơ, thu hút sự tham gia của đông đảo chuyên gia, nhà quản lý, doanh nghiệp và các cơ sở sản xuất OCOP trên địa bàn thành phố. Đây là hoạt động nhằm tăng cường kết nối giữa khoa học công nghệ với sản xuất, kinh doanh; đồng thời thúc đẩy ứng dụng chuyển đổi số trong phát triển sản phẩm OCOP theo hướng hiện đại và bền vững.</p><figure class="image"><img style="aspect-ratio:586/391;" src="/uploads/tin-su-kien/0a82cf2151ab9588.jpeg" alt="Description: C:\Users\admin\Downloads\LDP_8655.JPG" width="586" height="391"><figcaption><i>Ông Bùi Minh Châu – Phó Giám đốc Sở Khoa học và Công nghệ TP. Cần Thơ phát biểu tại hội thảo.</i></figcaption></figure><p>Phát biểu khai mạc hội thảo, ông Bùi Minh Châu nhấn mạnh vai trò quan trọng của truy xuất nguồn gốc trong việc nâng cao giá trị, chất lượng và sức cạnh tranh cho sản phẩm OCOP trong bối cảnh chuyển đổi số đang diễn ra mạnh mẽ. Theo đó, việc ứng dụng công nghệ hiện đại không chỉ góp phần minh bạch thông tin sản phẩm mà còn tạo dựng niềm tin với người tiêu dùng, mở rộng cơ hội tiếp cận thị trường trong và ngoài nước.</p><p>Tại hội thảo, nhiều tham luận chuyên sâu đã được trình bày, tập trung vào các giải pháp ứng dụng công nghệ số trong truy xuất nguồn gốc sản phẩm. Các đại biểu đã chia sẻ nhiều kinh nghiệm thực tiễn trong quá trình triển khai hệ thống truy xuất nguồn gốc nhằm nâng cao hiệu quả sản xuất, quản lý và tiêu thụ sản phẩm OCOP.</p><figure class="image"><img style="aspect-ratio:295/201;" src="/uploads/tin-su-kien/b0b0526f66a08b04.jpeg" alt="Description: C:\Users\admin\Downloads\LDP_8550.JPG" width="295" height="201"><figcaption>PGS.TS Nguyễn Duy Đạt, báo cáo viên tại Hội thảo</figcaption></figure><p>Đáng chú ý, bà Bùi Ngọc Lê – Giám đốc điều hành Công ty Cổ phần Tập đoàn Deep Pro – đã giới thiệu các giải pháp ứng dụng công nghệ Blockchain kết hợp mã QR trong truy xuất nguồn gốc nông sản và sản phẩm OCOP. Theo bà, việc ứng dụng công nghệ số sẽ góp phần tăng tính minh bạch, chống hàng giả và nâng cao hiệu quả quản lý chuỗi cung ứng.</p><p>Bên cạnh đó, PGS.TS Nguyễn Duy Đạt trình bày tham luận về việc đưa sản phẩm OCOP Cần Thơ lên các sàn thương mại điện tử. Nội dung tham luận tập trung phân tích những cơ hội, thách thức cũng như đề xuất nhiều giải pháp tích hợp truy xuất nguồn gốc nhằm gia tăng năng lực cạnh tranh cho sản phẩm OCOP trên môi trường số.</p><p>Một nội dung thu hút nhiều sự quan tâm là tham luận của TS. Mai Thanh Huyền, Trường Đại học Thương mại, liên quan đến các yêu cầu kỹ thuật và truy xuất nguồn gốc của thị trường Trung Quốc đối với trái cây tươi xuất khẩu. Tham luận đã đưa ra nhiều định hướng giúp TP. Cần Thơ thích ứng với những tiêu chuẩn ngày càng khắt khe của thị trường quốc tế.</p><p>Phần thảo luận diễn ra sôi nổi với nhiều ý kiến đóng góp từ các chuyên gia, doanh nghiệp và đại biểu tham dự. Các ý kiến đều thống nhất rằng việc đẩy mạnh ứng dụng công nghệ số và xây dựng hệ thống truy xuất nguồn gốc đồng bộ là xu hướng tất yếu nhằm nâng cao giá trị sản phẩm OCOP, góp phần thúc đẩy phát triển kinh tế địa phương trong thời kỳ chuyển đổi số.</p><p>Hội thảo kết thúc lúc 17 giờ cùng ngày, mở ra nhiều cơ hội hợp tác giữa cơ quan quản lý, doanh nghiệp và các đơn vị nghiên cứu trong việc ứng dụng khoa học công nghệ vào phát triển sản phẩm OCOP theo hướng bền vững.</p>', N'Huỳnh Thành', N'Trong khuôn khổ Hoạt động “Kết nối cung cầu công nghệ – Sản phẩm chủ lực, OCOP gắn với truy xuất nguồn gốc TP. Cần Thơ năm 2026”, chiều 28/5, tại Trung tâm Ứng dụng tiến bộ khoa học và công nghệ TP. C', '/uploads/tin-su-kien/842f33cb9c27d5b3.JPG', '2026-05-29');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'khong-gian-trung-bay-san-pham-ocop-va-giai-phap-khoa-hoc-cong-nghe-diem-nhan-noi-bat-tai-su-kien-ket-noi-cung-cau-cong-nghe-san-pham-chu-luc-ocop-gan-voi-truy-xuat-nguon-goc-thanh-', N'Không gian trưng bày sản phẩm OCOP và giải pháp khoa học công nghệ – Điểm nhấn nổi bật tại sự kiện “Kết nối cung cầu công nghệ - Sản phẩm chủ lực, OCOP gắn với truy xuất nguồn gốc thành phố Cần Thơ năm 2026”', N'<p>Trong khuôn khổ sự kiện <strong>“Kết nối cung cầu công nghệ - Sản phẩm chủ lực, OCOP gắn với truy xuất nguồn gốc thành phố Cần Thơ năm 2026”</strong>, hoạt động trưng bày, giới thiệu sản phẩm OCOP, sản phẩm chủ lực và các giải pháp khoa học công nghệ đã thu hút sự quan tâm của đông đảo đại biểu, doanh nghiệp, hợp tác xã, nhà khoa học và người dân đến tham quan, tìm hiểu.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/1b4df12b002ee68e.JPG" width="6720" height="4480"></figure><p>Với mục tiêu tăng cường kết nối giữa các đơn vị nghiên cứu, doanh nghiệp cung ứng công nghệ, cơ sở sản xuất và các chủ thể OCOP, khu vực trưng bày đã trở thành không gian giao lưu, quảng bá và xúc tiến thương mại hiệu quả, góp phần lan tỏa các thành tựu khoa học công nghệ ứng dụng vào thực tiễn sản xuất và kinh doanh.</p><p>Tại sự kiện, nhiều sản phẩm OCOP tiêu biểu, sản phẩm đặc trưng và nông sản chủ lực của thành phố Cần Thơ cùng các tỉnh, thành khu vực Đồng bằng sông Cửu Long đã được giới thiệu đến khách tham quan. Các sản phẩm đa dạng từ nhóm thực phẩm chế biến, đồ uống, nông sản tươi, sản phẩm thủ công mỹ nghệ đến các mặt hàng có giá trị gia tăng cao đã góp phần phản ánh tiềm năng, thế mạnh và bản sắc đặc trưng của từng địa phương.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/3fadfc36d46c3e22.JPG" width="6720" height="4480"></figure><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/70ae1394649778da.JPG" width="6720" height="4480"></figure><p>Bên cạnh các sản phẩm OCOP, khu vực triển lãm còn trưng bày nhiều giải pháp khoa học và công nghệ tiên tiến phục vụ sản xuất nông nghiệp, chế biến, bảo quản sau thu hoạch, chuyển đổi số, thương mại điện tử và truy xuất nguồn gốc sản phẩm. Các doanh nghiệp công nghệ đã giới thiệu nhiều mô hình, thiết bị và nền tảng số hiện đại, mang đến những giải pháp thiết thực giúp nâng cao hiệu quả sản xuất, quản lý chất lượng và mở rộng thị trường tiêu thụ.</p><p>Một trong những nội dung được khách tham quan đặc biệt quan tâm là các hệ thống truy xuất nguồn gốc sản phẩm bằng mã QR và công nghệ số. Thông qua việc quét mã truy xuất, người tiêu dùng có thể dễ dàng tiếp cận các thông tin liên quan đến sản phẩm như vùng nguyên liệu, quy trình sản xuất, tiêu chuẩn chất lượng và các chứng nhận liên quan. Đây là giải pháp quan trọng giúp nâng cao tính minh bạch, gia tăng niềm tin của người tiêu dùng và đáp ứng yêu cầu ngày càng cao của thị trường.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/3c2c61815e6d1369.JPG" width="6720" height="4480"></figure><p>Không gian trưng bày cũng là nơi diễn ra nhiều hoạt động kết nối, trao đổi trực tiếp giữa các đơn vị cung ứng công nghệ với doanh nghiệp, hợp tác xã và cơ sở sản xuất. Thông qua các hoạt động tư vấn, giới thiệu công nghệ và kết nối giao thương, nhiều cơ hội hợp tác đã được mở ra, góp phần thúc đẩy quá trình chuyển giao công nghệ và ứng dụng các tiến bộ khoa học kỹ thuật vào thực tiễn sản xuất.</p><p>Đặc biệt, sự kiện đã tạo điều kiện để các chủ thể OCOP giới thiệu sản phẩm, quảng bá thương hiệu, tìm kiếm đối tác và mở rộng thị trường tiêu thụ. Đây cũng là cơ hội để các doanh nghiệp tiếp cận những giải pháp công nghệ mới nhằm nâng cao năng suất, chất lượng sản phẩm và năng lực cạnh tranh trong bối cảnh chuyển đổi số đang diễn ra mạnh mẽ.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/f40b08c9f05b4a10.JPG" width="6720" height="4480"></figure><p>Thông qua hoạt động trưng bày và giới thiệu sản phẩm, sự kiện không chỉ góp phần quảng bá các sản phẩm OCOP và sản phẩm chủ lực của địa phương mà còn khẳng định vai trò quan trọng của khoa học và công nghệ trong phát triển kinh tế nông nghiệp hiện đại. Việc gắn kết giữa sản phẩm OCOP với truy xuất nguồn gốc, chuyển đổi số và đổi mới công nghệ đang mở ra những cơ hội mới cho doanh nghiệp, hợp tác xã và người sản xuất trong quá trình hội nhập và phát triển bền vững.</p><p>Không gian trưng bày sản phẩm OCOP và giải pháp khoa học công nghệ tại sự kiện đã để lại nhiều ấn tượng tốt đẹp đối với các đại biểu và khách tham quan, góp phần vào thành công chung của chương trình “Kết nối cung cầu công nghệ - Sản phẩm chủ lực, OCOP gắn với truy xuất nguồn gốc thành phố Cần Thơ năm 2026”, đồng thời tiếp tục lan tỏa tinh thần đổi mới sáng tạo và ứng dụng khoa học công nghệ vào phát triển kinh tế - xã hội của thành phố Cần Thơ và khu vực Đồng bằng sông Cửu Long.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/6d29d665472b146f.JPG" width="6720" height="4480"></figure>', N'Trung tâm ứng dụng', N'Trong khuôn khổ sự kiện “Kết nối cung cầu công nghệ - Sản phẩm chủ lực, OCOP gắn với truy xuất nguồn gốc thành phố Cần Thơ năm 2026” , hoạt động trưng bày, giới thiệu sản phẩm OCOP, sản phẩm chủ lực v', '/uploads/tin-su-kien/22e9d75dfd419abd.JPG', '2026-05-28');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'hoi-thao-khoa-hoc-truy-xuat-nguon-goc-san-pham-ocop-gan-voi-chuyen-doi-so-va-thuong-mai-dien-tu-gop-phan-thuc-day-phat-trien-san-pham-ocop-thanh-pho-can-tho', N'Hội thảo khoa học “Truy xuất nguồn gốc sản phẩm OCOP gắn với chuyển đổi số và thương mại điện tử” góp phần thúc đẩy phát triển sản phẩm OCOP thành phố Cần Thơ', N'<p>Trong khuôn khổ sự kiện <strong>“Kết nối cung cầu công nghệ - Sản phẩm chủ lực, OCOP gắn với truy xuất nguồn gốc thành phố Cần Thơ năm 2026”</strong>, chiều ngày 28/5/2026, tại Trung tâm Ứng dụng tiến bộ khoa học và công nghệ Cần Thơ, Hội thảo khoa học với chủ đề <strong>“Truy xuất nguồn gốc sản phẩm OCOP gắn với chuyển đổi số và thương mại điện tử”</strong> đã diễn ra thành công tốt đẹp với sự tham dự của đại diện các sở, ngành, địa phương, doanh nghiệp, hợp tác xã, cơ sở sản xuất OCOP cùng các chuyên gia trong và ngoài nước.</p><p>Hội thảo là diễn đàn quan trọng nhằm chia sẻ kinh nghiệm, cập nhật xu hướng công nghệ mới và đề xuất các giải pháp nâng cao hiệu quả quản lý, phát triển thị trường cho sản phẩm OCOP thông qua ứng dụng công nghệ truy xuất nguồn gốc, chuyển đổi số và thương mại điện tử. Đây cũng là một trong những hoạt động trọng tâm của sự kiện kết nối cung cầu công nghệ năm 2026, góp phần hỗ trợ doanh nghiệp, hợp tác xã và các chủ thể OCOP nâng cao năng lực cạnh tranh trong bối cảnh kinh tế số đang phát triển mạnh mẽ.</p><p>Phát biểu tại hội thảo, ông Bùi Minh Châu - Phó Giám đốc Sở khoa học và công nghệ TP.Cần Thơ nhận định rằng truy xuất nguồn gốc không chỉ là công cụ quản lý chất lượng sản phẩm mà còn là giải pháp quan trọng giúp gia tăng niềm tin của người tiêu dùng, nâng cao giá trị thương hiệu và đáp ứng các yêu cầu ngày càng khắt khe của thị trường trong nước và quốc tế. Việc ứng dụng công nghệ số trong truy xuất nguồn gốc đang trở thành xu hướng tất yếu đối với các sản phẩm nông nghiệp, thực phẩm và sản phẩm OCOP.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/d579c4d84e9b536d.JPG" width="6720" height="4480"><figcaption>Ông Bùi Minh Châu - Phó Giám đốc Sở khoa học và công nghệ TP.Cần Thơ</figcaption></figure><p>Tại chương trình, Bà Bùi Ngọc Lê -  Giám đốc điều hành Công ty CP Deep Pro đã trình bày những giải pháp công nghệ tiên tiến trong quản lý dữ liệu sản phẩm, truy xuất nguồn gốc và kết nối thông tin trên nền tảng số. Những mô hình ứng dụng thực tiễn đã cho thấy hiệu quả trong việc minh bạch hóa thông tin sản phẩm, hỗ trợ doanh nghiệp xây dựng lòng tin với khách hàng và nâng cao khả năng quản lý chuỗi cung ứng.</p><p>Các doanh nghiệp OCOP đang triển khai hệ thống truy xuất nguồn gốc cũng chia sẻ những kinh nghiệm thực tế trong quá trình xây dựng thương hiệu, quản lý vùng nguyên liệu, kiểm soát chất lượng sản phẩm và tiếp cận thị trường. Những câu chuyện thành công từ thực tiễn đã mang đến nhiều bài học quý giá cho các hợp tác xã và cơ sở sản xuất đang trong quá trình chuyển đổi số.</p><p>Một trong những nội dung nhận được nhiều sự quan tâm là chuyên đề về ứng dụng công nghệ Blockchain và mã QR Code trong truy xuất nguồn gốc nông sản, sản phẩm OCOP. Các chuyên gia đã phân tích những ưu điểm nổi bật của công nghệ blockchain trong việc đảm bảo tính minh bạch, khả năng xác thực và chống gian lận dữ liệu. Khi kết hợp với mã QR, người tiêu dùng có thể dễ dàng tiếp cận toàn bộ thông tin về sản phẩm, từ nguồn gốc nguyên liệu, quy trình sản xuất đến các chứng nhận chất lượng thông qua điện thoại thông minh.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/8f827f512492ffe6.JPG" width="6720" height="4480"><figcaption>Bà Bùi Ngọc Lê - Bà Bùi Ngọc Lê -  Giám đốc điều hành Công ty CP Deep Pro </figcaption></figure><p>Bên cạnh đó, nội dung đưa sản phẩm OCOP lên các sàn thương mại điện tử và tích hợp hệ thống truy xuất nguồn gốc đã thu hút sự quan tâm đặc biệt của các doanh nghiệp và hợp tác xã. Các chuyên gia đã chia sẻ nhiều giải pháp giúp nâng cao khả năng tiếp cận khách hàng, mở rộng thị trường tiêu thụ và gia tăng giá trị sản phẩm thông qua việc kết hợp giữa thương mại điện tử và dữ liệu truy xuất nguồn gốc minh bạch.</p><p>Đặc biệt, hội thảo còn có sự tham gia trực tiếp của PGS.TS. Nguyễn Duy Đạt – Trưởng khoa Kinh tế và Kinh doanh Quốc tế, Trường Đại học Thương mại. Các báo cáo đã mang đến góc nhìn quốc tế về ứng dụng blockchain trong xây dựng chuỗi cung ứng bền vững, kinh tế tuần hoàn và phát triển nông nghiệp hiện đại. Những kinh nghiệm từ các quốc gia phát triển cho thấy việc số hóa dữ liệu và minh bạch hóa thông tin sản phẩm đang trở thành nền tảng quan trọng để nâng cao năng lực cạnh tranh và đáp ứng các tiêu chuẩn toàn cầu.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/9973649d419d27bf.JPG" width="6720" height="4480"><figcaption>PGS.TS. Nguyễn Duy Đạt – Trưởng khoa Kinh tế và Kinh doanh Quốc tế, Trường Đại học Thương mại</figcaption></figure><p>Trong phần thảo luận, các đại biểu đã trao đổi sôi nổi về những khó khăn, thách thức cũng như cơ hội trong quá trình triển khai truy xuất nguồn gốc đối với sản phẩm OCOP. Nhiều ý kiến đề xuất tăng cường hỗ trợ doanh nghiệp, hợp tác xã tiếp cận công nghệ mới, đào tạo nguồn nhân lực số và xây dựng hệ sinh thái kết nối giữa sản xuất, truy xuất nguồn gốc và thương mại điện tử.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/d5766ff92c9f7cb4.JPG" width="6720" height="4480"><figcaption>Đại biểu thảo luận tại Hội thảo</figcaption></figure><p>Hội thảo đã góp phần cung cấp những kiến thức, kinh nghiệm và giải pháp thiết thực nhằm thúc đẩy quá trình chuyển đổi số trong lĩnh vực nông nghiệp, hỗ trợ phát triển các sản phẩm OCOP theo hướng hiện đại, minh bạch và bền vững. Đồng thời, đây cũng là cơ hội để các doanh nghiệp, hợp tác xã và cơ quan quản lý kết nối, trao đổi thông tin, tìm kiếm cơ hội hợp tác và mở rộng thị trường.</p><figure class="image"><img></figure><p>Sự thành công của hội thảo tiếp tục khẳng định vai trò của khoa học công nghệ và đổi mới sáng tạo trong phát triển kinh tế địa phương, góp phần nâng cao giá trị các sản phẩm chủ lực, sản phẩm OCOP của thành phố Cần Thơ, hướng tới xây dựng nền nông nghiệp hiện đại, bền vững và hội nhập quốc tế.</p>', N'Trung tâm ứng dụng', N'Trong khuôn khổ sự kiện “Kết nối cung cầu công nghệ - Sản phẩm chủ lực, OCOP gắn với truy xuất nguồn gốc thành phố Cần Thơ năm 2026” , chiều ngày 28/5/2026, tại Trung tâm Ứng dụng tiến bộ khoa học và ', '/uploads/tin-su-kien/b93eacf2ed690dfa.JPG', '2026-05-28');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'khai-mac-hoat-dong-ket-noi-cung-cau-cong-nghe-san-pham-chu-luc-ocop-gan-voi-truy-xuat-nguon-goc-thanh-pho-can-tho-nam-2026', N'Khai mạc hoạt động “Kết nối cung cầu công nghệ - Sản phẩm chủ lực, OCOP gắn với truy xuất nguồn gốc thành phố Cần Thơ năm 2026”', N'<p>Sáng ngày 28/5/2026, tại Trung tâm Ứng dụng tiến bộ khoa học và công nghệ thành phố Cần Thơ, Sở Khoa học và Công nghệ thành phố Cần Thơ tổ chức khai mạc hoạt động “Kết nối cung cầu công nghệ - Sản phẩm chủ lực, OCOP gắn với truy xuất nguồn gốc thành phố Cần Thơ năm 2026”.</p><p>Phát biểu khai mạc chương trình, bà Nguyễn Thị Ngọc Điệp - Phó Chủ tịch Ủy ban nhân dân thành phố Cần Thơ nhấn mạnh ý nghĩa của hoạt động trong việc thúc đẩy ứng dụng khoa học công nghệ, đổi mới sáng tạo và chuyển đổi số vào sản xuất, kinh doanh; góp phần nâng cao chất lượng, giá trị và sức cạnh tranh của sản phẩm địa phương.</p><figure class="image"><img style="aspect-ratio:624/416;" src="/uploads/tin-su-kien/3c1b317fad8af8e3.jpeg" width="624" height="416"><figcaption><i>Bà Nguyễn Thị Ngọc Điệp - Phó Chủ tịch Ủy ban nhân dân thành phố Cần Thơ</i></figcaption></figure><p>Tại chương trình, ông Nguyễn Phương Tuấn - Phó Chủ nhiệm Ủy ban Khoa học, Công nghệ và Môi trường của Quốc hội đã có phát biểu định hướng, ghi nhận vai trò của hoạt động kết nối cung cầu công nghệ trong việc đưa tiến bộ khoa học kỹ thuật vào thực tiễn, đồng thời nhấn mạnh yêu cầu tăng cường liên kết giữa cơ quan quản lý, viện, trường, doanh nghiệp và người sản xuất.</p><figure class="image"><img style="aspect-ratio:6720/4480;" src="/uploads/tin-su-kien/4bd931d95f02cbcb.JPG" width="6720" height="4480"><figcaption><i>Ông Nguyễn Phương Tuấn - Phó Chủ nhiệm Ủy ban Khoa học, Công nghệ và Môi trường của Quốc hội</i></figcaption></figure><p>Điểm nhấn của chương trình là hoạt động ký kết hợp tác, kết nối cung cầu công nghệ giữa các đơn vị, doanh nghiệp, hợp tác xã và chủ thể sản xuất. Thông qua ký kết, các bên có thêm cơ hội tiếp cận, trao đổi và ứng dụng các giải pháp khoa học công nghệ vào thực tiễn, góp phần chuẩn hóa quy trình, nâng cao chất lượng sản phẩm và mở rộng thị trường tiêu thụ.</p><p>Hoạt động diễn ra từ ngày 28 đến 30/5/2026, tạo không gian kết nối giữa cơ quan quản lý, viện, trường, doanh nghiệp, hợp tác xã, chủ thể OCOP và các đơn vị cung cấp giải pháp công nghệ. Trong khuôn khổ chương trình, Ban Tổ chức giới thiệu Sàn Giao dịch công nghệ thành phố Cần Thơ phiên bản điện tử, nền tảng hỗ trợ kết nối cung cầu công nghệ, giới thiệu thiết bị, giải pháp kỹ thuật, chuyển giao tiến bộ khoa học và thương mại hóa kết quả nghiên cứu.</p><figure class="image"><img style="aspect-ratio:624/416;" src="/uploads/tin-su-kien/fb7ad1e349c876a2.png" width="624" height="416"></figure><p>Bên cạnh hoạt động ký kết và ra mắt nền tảng kết nối công nghệ, sự kiện còn có các khu vực trưng bày sản phẩm chủ lực, sản phẩm OCOP, thiết bị tiên tiến, mô hình chuyển đổi số, thương mại điện tử và hệ thống truy xuất nguồn gốc. Khách tham quan có thể trực tiếp trải nghiệm quét mã QR để tra cứu thông tin sản phẩm, góp phần nâng cao tính minh bạch và xây dựng niềm tin với người tiêu dùng.</p><p>Chương trình cũng tổ chức các hội thảo chuyên đề về truy xuất nguồn gốc, chuyển đổi số, thương mại điện tử và kết nối cung cầu công nghệ phục vụ phát triển sản phẩm OCOP, nông sản chủ lực đáp ứng yêu cầu thị trường.</p><p>Thông qua hoạt động này, Trung tâm Ứng dụng tiến bộ khoa học và công nghệ thành phố Cần Thơ tiếp tục phát huy vai trò cầu nối trong ứng dụng, chuyển giao tiến bộ khoa học kỹ thuật vào thực tiễn. Các hoạt động ký kết hợp tác tại chương trình là cơ sở quan trọng để tăng cường liên kết giữa nhà quản lý, nhà khoa học, doanh nghiệp và người sản xuất, góp phần hỗ trợ sản phẩm chủ lực, sản phẩm OCOP của thành phố nâng cao giá trị, mở rộng thị trường và phát triển bền vững.</p><p> </p>', N'', N'Sáng ngày 28/5/2026, tại Trung tâm Ứng dụng tiến bộ khoa học và công nghệ thành phố Cần Thơ, Sở Khoa học và Công nghệ thành phố Cần Thơ tổ chức khai mạc hoạt động “Kết nối cung cầu công nghệ - Sản phẩ', '/uploads/tin-su-kien/6a69678e510f5b69.png', '2026-05-28');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'tp-can-tho-to-chuc-su-kien-ket-noi-cung-cau-cong-nghe-san-pham-chu-luc-ocop-gan-voi-truy-xuat-nguon-goc', N'TP. CẦN THƠ tổ chức sự kiện “Kết nối cung cầu công nghệ – Sản phẩm chủ lực OCOP gắn với truy xuất nguồn gốc”', N'<p>Từ ngày <strong>28/05/2026 đến 30/05/2026</strong>, tại <strong>Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ TP. Cần Thơ</strong>, sự kiện <strong>“Kết nối cung cầu công nghệ – Sản phẩm chủ lực OCOP gắn với truy xuất nguồn gốc” TP. Cần Thơ năm 2026</strong> sẽ được tổ chức với nhiều hoạt động thiết thực, hướng đến mục tiêu thúc đẩy ứng dụng khoa học công nghệ, nâng cao giá trị sản phẩm địa phương và mở rộng kết nối thị trường.</p><p>    Sự kiện là không gian gặp gỡ, trao đổi và hợp tác giữa các cơ quan quản lý, doanh nghiệp, hợp tác xã, cơ sở sản xuất, tổ chức khoa học công nghệ, nhà phân phối và người tiêu dùng. Thông qua đó, các giải pháp công nghệ, mô hình sản xuất hiệu quả, sản phẩm chủ lực và sản phẩm OCOP của địa phương sẽ được giới thiệu, quảng bá và kết nối đến nhiều đối tượng quan tâm.</p><p><strong>Thúc đẩy kết nối cung cầu công nghệ</strong></p><p>    Một trong những nội dung trọng tâm của sự kiện là hoạt động <strong>kết nối cung cầu công nghệ</strong>. Đây là cầu nối giúp các doanh nghiệp, hợp tác xã và cơ sở sản xuất tiếp cận những giải pháp khoa học công nghệ phù hợp với nhu cầu thực tế trong sản xuất, chế biến, bảo quản, quảng bá, phân phối và thương mại hóa sản phẩm.</p><p>    Bên cạnh việc giới thiệu các giải pháp công nghệ, sự kiện còn tạo điều kiện để các đơn vị trao đổi trực tiếp, chia sẻ nhu cầu, tìm kiếm đối tác và mở rộng cơ hội hợp tác. Qua đó, công nghệ không chỉ dừng lại ở hoạt động trưng bày, mà từng bước đi vào thực tiễn sản xuất, kinh doanh và phát triển thị trường.</p><p><strong>Quảng bá sản phẩm chủ lực, sản phẩm OCOP</strong></p><figure class="image"><img style="aspect-ratio:729/547;" src="/uploads/tin-su-kien/499474e244c74a98.png" width="729" height="547"></figure><p>    Sự kiện cũng là dịp để các tổ chức, cá nhân tham gia trưng bày giới thiệu những sản phẩm chủ lực, sản phẩm OCOP và sản phẩm đặc trưng của địa phương. Các sản phẩm được giới thiệu không chỉ thể hiện thế mạnh sản xuất của TP. Cần Thơ, mà còn góp phần lan tỏa hình ảnh sản phẩm địa phương đến với đối tác, nhà phân phối và người tiêu dùng.</p><p>    Thông qua hoạt động triển lãm, trưng bày và quảng bá, các đơn vị có thêm cơ hội nâng cao nhận diện thương hiệu, giới thiệu câu chuyện sản phẩm, tìm kiếm kênh tiêu thụ mới và tăng khả năng cạnh tranh trên thị trường.</p><figure class="image"><img style="aspect-ratio:730/547;" src="/uploads/tin-su-kien/c90b93aefa237746.png" width="730" height="547"></figure><p><strong>Gắn truy xuất nguồn gốc với niềm tin người tiêu dùng</strong></p><p>    Điểm nhấn quan trọng của sự kiện là việc gắn sản phẩm với hoạt động <strong>truy xuất nguồn gốc</strong>. Thông qua mã QR, người tham quan có thể dễ dàng tìm hiểu thông tin về nguồn gốc xuất xứ, đơn vị sản xuất, quy trình sản xuất, tiêu chuẩn chất lượng và các thông tin liên quan đến sản phẩm.</p><p>    Hoạt động này góp phần nâng cao tính minh bạch, tạo niềm tin cho người tiêu dùng và hỗ trợ các doanh nghiệp, hợp tác xã, cơ sở sản xuất chuyên nghiệp hóa hoạt động quảng bá, kinh doanh. Đây cũng là bước đi phù hợp với xu hướng chuyển đổi số, tiêu dùng an toàn và phát triển bền vững.</p><p><strong>Nhiều hoạt động thiết thực trong khuôn khổ sự kiện</strong></p><p>    Trong thời gian diễn ra, sự kiện dự kiến tổ chức nhiều hoạt động nổi bật như: <strong>Lễ khai mạc; triển lãm công nghệ – sản phẩm chủ lực OCOP; hội thảo, tọa đàm – kết nối cung cầu; livestream quảng bá – thương mại; trải nghiệm công nghệ – quét mã QR truy xuất nguồn gốc</strong>.</p><p>    Các hoạt động được thiết kế nhằm tạo không gian kết nối đa chiều, vừa giới thiệu sản phẩm, vừa thúc đẩy ứng dụng công nghệ, đồng thời mở rộng kênh quảng bá và tiêu thụ sản phẩm trên nền tảng số.</p><p><strong>Hướng đến phát triển bền vững</strong></p><p>    Sự kiện <strong>“Kết nối cung cầu công nghệ – Sản phẩm chủ lực OCOP gắn với truy xuất nguồn gốc” TP. Cần Thơ năm 2026</strong> góp phần khẳng định vai trò của khoa học công nghệ trong phát triển kinh tế địa phương. Đồng thời, sự kiện cũng tạo động lực để các sản phẩm chủ lực, sản phẩm OCOP của TP. Cần Thơ từng bước nâng cao chất lượng, minh bạch thông tin, mở rộng thị trường và phát triển theo hướng hiện đại, bền vững.</p><p><strong>Đăng ký tham gia sự kiện</strong></p><p>    Ban Tổ chức trân trọng kính mời các doanh nghiệp, hợp tác xã, cơ sở sản xuất, tổ chức khoa học công nghệ, nhà phân phối, đơn vị cung ứng giải pháp và các cá nhân quan tâm đăng ký tham gia sự kiện. Đây là cơ hội để các đơn vị giới thiệu sản phẩm, quảng bá thương hiệu, kết nối đối tác, tiếp cận giải pháp công nghệ và mở rộng thị trường tiêu thụ.</p><p>    Các tổ chức, cá nhân có nhu cầu tham gia trưng bày, kết nối cung cầu công nghệ hoặc tìm hiểu thêm thông tin về sự kiện vui lòng liên hệ:</p><p>    <strong>Điện thoại:</strong> 0292 3907 037.<br>    <strong>Email:</strong> <a href="mailto:trungtamungdung@cantho.gov.vn">trungtamungdung@cantho.gov.vn</a>.<br><strong>    Đăng ký tham gia trưng bày và kết nối: TẠI ĐÂY</strong></p><p><strong>Thông tin sự kiện:</strong></p><p>    <strong>Thời gian:</strong> 28/05/2026 – 30/05/2026.<br>    <strong>Địa điểm:</strong> Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ TP. Cần Thơ, 166 phường An Bình, TP. Cần Thơ.<br>    <strong>Chủ đề:</strong> Kết nối cung cầu công nghệ – Sản phẩm chủ lực OCOP gắn với truy xuất nguồn gốc.</p><p>    <strong>Kết nối công nghệ – Minh bạch nguồn gốc – Nâng tầm sản phẩm địa phương.</strong></p>', N'Phòng Dịch vụ - Giao dịch công nghệ', N'Từ ngày 28/05/2026 đến 30/05/2026 , tại Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ TP. Cần Thơ , sự kiện “Kết nối cung cầu công nghệ – Sản phẩm chủ lực OCOP gắn với truy xuất nguồn gốc” TP. Cần ', '/uploads/tin-su-kien/8fb6a61b3f955766.jpg', '2026-05-22');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'can-tho-tao-dau-an-cong-nghe-tai-tuan-le-san-pham-ocop-va-thuong-mai-tinh-tay-ninh-nam-2026', N'Cần Thơ tạo dấu ấn công nghệ tại Tuần lễ Sản phẩm OCOP và Thương mại tỉnh Tây Ninh năm 2026', N'<p>Trong khuôn khổ "Tuần lễ Sản phẩm OCOP, Nông nghiệp tiêu biểu và Thương mại tỉnh Tây Ninh lần thứ I - năm 2026" diễn ra từ ngày 15/4 đến 21/4/2026, gian hàng của Sở Khoa học và Công nghệ TP. Cần Thơ đã trở thành điểm đến thu hút đông đảo khách tham quan nhờ sự kết hợp giữa đặc sản truyền thống và giải pháp công nghệ hiện đại.</p><p>Ngay từ ngày khai mạc 15/4, không gian trưng bày chung của TP. Cần Thơ đã gây ấn tượng với thiết kế mang đậm bản sắc văn hóa Tây Đô nhưng vẫn toát lên vẻ hiện đại của một thành phố năng động. Tại đây, các nhóm sản phẩm được bố trí khoa học theo từng lĩnh vực chuyên biệt.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/5c3ef2e8a6bd33c3.png" width="2560" height="1920"><figcaption><strong>Gian hàng chung của Sở KH&amp;CN TP. Cần Thơ</strong></figcaption></figure><p>Trọng tâm của gian hàng là các sản phẩm đạt chứng nhận OCOP, sản phẩm chủ lực và đặc sản thế mạnh của thành phố như gạo, trái cây sấy và thủy sản chế biến. Tất cả đều được chăm chút kỹ lưỡng về bao bì, nhãn mác, thể hiện sự chuyên nghiệp của các doanh nghiệp và hợp tác xã Cần Thơ.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/c999f20993bae9a4.png" width="2560" height="1920"><figcaption><strong>Các sản phẩm OCOP tiêu biểu</strong></figcaption></figure><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/16d9126e72f41dc2.png" width="2560" height="1920"><figcaption><strong>Các sản phẩm OCOP tiêu biểu</strong></figcaption></figure><h3>Điểm sáng từ công nghệ truy xuất nguồn gốc</h3><p>Khác biệt với các gian hàng nông sản thông thường, TP. Cần Thơ  quảng bá các sản phẩm đã áp dụng hệ thống truy xuất nguồn gốc. Khách tham quan không chỉ xem sản phẩm bằng mắt mà còn được tương tác trực tiếp qua các giải pháp công nghệ.</p><ul><li><strong>Trải nghiệm quét mã QR:</strong> Các viên chức từ Trung tâm Ứng dụng tiến bộ khoa học và công nghệ thành phố đã trực tiếp hướng dẫn khách tham quan cách sử dụng hệ thống để kiểm tra nguồn gốc, quy trình sản xuất của từng mặt hàng.</li><li><strong>Trình diễn công nghệ:</strong> Gian hàng sử dụng màn hình tương tác giúp người tham quan có thể tham khảo cũng như trải nghiệm các video về hệ thống Truy xuất nguồn gốc của thành phố Cần Thơ và quy trình đăng ký, nhập liệu vào hệ thống truy xuất nguồn gốc của thành phố.</li></ul><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/f6837007887b911c.png" width="2560" height="1920"><figcaption>Sản phẩm Truy xuất nguồn gốc</figcaption></figure><h3>Kết nối cung - cầu và thúc đẩy đổi mới sáng tạo</h3><p>Bên cạnh mục tiêu quảng bá, sự kiện là cơ hội vàng để các doanh nghiệp khởi nghiệp và đơn vị nghiên cứu của Cần Thơ giới thiệu các kết quả nhiệm vụ khoa học công nghệ trong lĩnh vực nông nghiệp và công nghệ sinh học.</p><p>Việc tham gia đầy đủ các hoạt động từ khai mạc đến bế mạc giúp đoàn công tác Cần Thơ thắt chặt mối quan hệ hợp tác với tỉnh Tây Ninh và các địa phương vùng Đồng bằng sông Cửu Long, mở ra những thị trường tiêu thụ bền vững cho nông sản thành phố.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/a030bf6cc50e9ac4.png" width="2560" height="1920"></figure><p>Sự hiện diện tại Tây Ninh lần này không chỉ dừng lại ở việc trưng bày sản phẩm, mà còn khẳng định vị thế của Cần Thơ là trung tâm tiên phong trong việc ứng dụng khoa học công nghệ vào sản xuất và thương mại nông nghiệp, góp phần xây dựng niềm tin vững chắc cho người tiêu dùng.</p>', N'Kim Anh', N'Trong khuôn khổ "Tuần lễ Sản phẩm OCOP, Nông nghiệp tiêu biểu và Thương mại tỉnh Tây Ninh lần thứ I - năm 2026" diễn ra từ ngày 15/4 đến 21/4/2026, gian hàng của Sở Khoa học và Công nghệ TP. Cần Thơ đ', '/uploads/tin-su-kien/b936c0eba1b97959.jpg', '2026-04-16');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'tuoi-tre-trung-tam-ung-dung-tien-bo-kh-cn-can-tho-hanh-trinh-ve-nguon-va-tim-hieu-van-hoa-tai-bao-tang-thanh-pho', N'TUỔI TRẺ TRUNG TÂM ỨNG DỤNG TIẾN BỘ KH&CN CẦN THƠ: HÀNH TRÌNH VỀ NGUỒN VÀ TÌM HIỂU VĂN HÓA TẠI BẢO TÀNG THÀNH PHỐ', N'<p>Chiều ngày 12/03/2026, Chi đoàn Trung tâm Ứng dụng tiến bộ khoa học và công nghệ Cần Thơ đã có một buổi sinh hoạt chuyên đề đầy cảm xúc tại Bảo tàng thành phố Cần Thơ. Vượt ra khỏi khuôn khổ của một buổi tham quan thông thường, đây là hành trình để các bạn trẻ chạm tay vào ký ức, thấu hiểu bản sắc và thắp sáng trách nhiệm công dân trước thềm kỳ bầu cử mới.</p><h3><strong>1. Ngược dòng thời gian, chạm vào linh hồn vùng đất chín rồng</strong></h3><p>Trong sắc áo xanh thanh niên đầy sức sống , đoàn đã bắt đầu hành trình tại tầng 1 – nơi lưu giữ những "mảnh ghép" đầu tiên của vùng đất Cần Thơ xưa và nay.</p><ul><li><strong>Dấu ấn cổ xưa:</strong> Những hiện vật khảo cổ từ văn hóa Óc Eo tại di chỉ Nhơn Thành đã mở ra một không gian đô thị sông nước cổ đầy huyền bí.</li><li><strong>Bản sắc đa dạng:</strong> Sự giao thoa văn hóa giữa ba dân tộc Kinh – Hoa – Khmer được tái hiện sinh động qua các mô hình nhà ở, nhạc cụ và tín ngưỡng.</li><li><strong>Hình ảnh đặc trưng:</strong> Các bạn trẻ đặc biệt ấn tượng với mô hình Đình Bình Thủy cổ kính, những bộ trang phục cưới truyền thống và chiếc ghe Ngo hiên ngang của người Khmer</li></ul><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/442baacc5aafe0ff.jpg" width="2560" height="1920"></figure><h3><strong>2. Hào khí Tây Đô và bài học về lòng yêu nước</strong></h3><p>Tiến lên tầng 2, không gian trở nên trang trọng hơn với những thước phim tư liệu và kỷ vật chiến trường.</p><ul><li><strong>Ký ức kháng chiến:</strong> Những khẩu súng, giáo mác và quân trang thấm đẫm mồ hôi, xương máu của quân dân Cần Thơ – Hậu Giang đã kể lại câu chuyện về một thời kỳ chống Pháp và Mỹ gian khổ nhưng vô cùng oanh liệt.</li><li><strong>Niềm tự hào dân tộc:</strong> Qua lời thuyết minh truyền cảm, thế hệ trẻ của Trung tâm thêm trân trọng giá trị của độc lập, hòa bình hôm nay.</li></ul><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/d8ecc6e1094034d2.jpg" width="2560" height="1920"></figure><h3><strong>3. "Ý Đảng - Lòng Dân": Từ lịch sử đến trách nhiệm hiện tại</strong></h3><p>Điểm nhấn đặc biệt nhất của chuyến đi chính là không gian trưng bày chuyên đề về Quốc hội và Hội đồng nhân dân (HĐND).</p><ul><li><strong>Hơn 140 hình ảnh và tư liệu quý:</strong> Phản ánh sinh động chặng đường 80 năm hình thành và phát triển của cơ quan quyền lực nhà nước cao nhất.</li><li><strong>Tư tưởng dân chủ:</strong> Đoàn viên được tìm hiểu sâu về tư tưởng dân chủ của Chủ tịch Hồ Chí Minh – nền tảng cốt lõi trong việc xây dựng chính quyền của dân, do dân và vì dân.</li><li><strong>Trách nhiệm công dân:</strong> Hoạt động đã kịp thời tuyên truyền về cuộc bầu cử đại biểu Quốc hội khóa XVI và HĐND các cấp nhiệm kỳ 2026 – 2031, thôi thúc mỗi bạn trẻ nâng cao ý thức trách nhiệm trong việc lựa chọn người đại diện cho ý chí và nguyện vọng của mình.</li></ul><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/2191549b59da2c5a.jpg" width="2560" height="1920"></figure><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/fff5a89c4c850fde.jpg" width="2568" height="1926"></figure><p>Chuyến đi kết thúc nhưng những giá trị về văn hóa, lịch sử và tinh thần dân chủ vẫn còn đọng lại sâu sắc trong mỗi đoàn viên. Đây chính là "nguồn năng lượng" tinh thần để tuổi trẻ Trung tâm tiếp tục cống hiến, sáng tạo và thực hiện tốt quyền, nghĩa vụ công dân trong thời kỳ mới.</p>', N'Kim Anh', N'Chiều ngày 12/03/2026, Chi đoàn Trung tâm Ứng dụng tiến bộ khoa học và công nghệ Cần Thơ đã có một buổi sinh hoạt chuyên đề đầy cảm xúc tại Bảo tàng thành phố Cần Thơ. Vượt ra khỏi khuôn khổ của một b', '/uploads/tin-su-kien/8ae25b900151c3c4.jpg', '2026-04-13');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'hop-tac-trien-khai-thu-nghiem-ha-tang-tram-sac-dien-thong-minh-buoc-tien-trong-chuyen-doi-nang-luong-xanh-tai-can-tho', N'HỢP TÁC TRIỂN KHAI THỬ NGHIỆM HẠ TẦNG TRẠM SẠC ĐIỆN THÔNG MINH: BƯỚC TIẾN TRONG CHUYỂN ĐỔI NĂNG LƯỢNG XANH TẠI CẦN THƠ', N'<p>Trong bối cảnh Chiến lược quốc gia về tăng trưởng xanh và Quyết định số 876/QĐ-TTg của Thủ tướng Chính phủ về chuyển đổi năng lượng xanh đang được đẩy mạnh, việc phát triển hạ tầng trạm sạc cho phương tiện giao thông điện là một yêu cầu cấp thiết về mặt công nghệ và quy hoạch đô thị.</p><p>Với vai trò là tổ chức khoa học và công nghệ, đóng vai trò cầu nối trong việc thúc đẩy ứng dụng tiến bộ kỹ thuật vào thực tiễn , Trung tâm Ứng dụng tiến bộ khoa học và công nghệ thành phố Cần Thơ (CASTA) hợp tác cùng Công ty Cổ phần Tập đoàn EVG triển khai vận hành thử nghiệm trạm sạc điện phương tiện giao thông.</p><p>Triển khai hạ tầng kỹ thuật tại trụ sở Trung tâm</p><p>Hệ thống trạm sạc thử nghiệm đã được lắp đặt và vận hành tại địa điểm: Số 166 Nguyễn Văn Cừ, phường An Bình, thành phố Cần Thơ (trụ sở của Trung tâm Ứng dụng) </p><p>Dự án này không chỉ đơn thuần là việc lắp đặt thiết bị mà còn là một mô hình nghiên cứu triển khai, nhằm đánh giá tính khả thi và hiệu quả của việc ứng dụng công nghệ xanh vào hạ tầng giao thông đô thị.</p><p>Thông số kỹ thuật và công nghệ sạc</p><p>Hệ thống được triển khai thử nghiệm sử dụng thiết bị sạc EVG DC 60kW, đại diện cho thế hệ sạc nhanh hiện đại với các thông số kỹ thuật tối ưu cho việc vận hành an toàn và hiệu suất cao. Các đặc tính công nghệ nổi bật bao gồm:</p><ul><li>Công suất và Hiệu suất: Trụ sạc có công suất đầu ra tối đa 60kW với thiết kế súng đôi (2 súng sạc), cho phép sạc đồng thời đa phương tiện.</li><li>Dải điện áp rộng: Thiết bị hỗ trợ điện áp đầu vào AC380V±15% và cung cấp điện áp đầu ra DC dao động từ 200V đến 1000V, phù hợp với hầu hết các hệ pin của xe điện hiện hành.</li><li>Kết nối thông minh (IoT): Trạm sạc được tích hợp các chuẩn kết nối 4G/Wifi/Ethernet và hỗ trợ phương pháp xác thực hiện đại qua quét mã QR Code hoặc thẻ từ.</li><li>Giao thức chuẩn hóa: Hệ thống vận hành trên giao thức OCPP 1.6J (Open Charge Point Protocol), đảm bảo khả năng tương thích mở và quản lý dữ liệu sạc tập trung, một tiêu chuẩn quan trọng trong quản lý mạng lưới trạm sạc thông minh.</li></ul><p>Mục tiêu Khoa học và Môi trường</p><p>Việc hợp tác thử nghiệm này hướng tới mục tiêu phát triển giao thông bền vững, giảm phát thải khí Carbon và khí Methane ngành giao thông vận tải.</p><p>Thông qua việc thu thập dữ liệu từ Báo cáo vận hành , Trung tâm Ứng dụng tiến bộ khoa học và công nghệ thành phố Cần Thơ và đối tác sẽ có cơ sở thực tiễn để đánh giá, hoàn thiện quy trình công nghệ, từ đó đề xuất các giải pháp nhân rộng mô hình giao thông xanh, thân thiện với môi trường trong tương lai.</p><figure class="image"><img style="aspect-ratio:974/731;" src="/uploads/tin-su-kien/9a0551ff5a50f893.png" width="974" height="731"></figure><p>Trụ điện được hợp tác lắp đặt tại trụ sở Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/74f8fecb06f97f94.jpg" width="2560" height="1920"></figure>', N'Nguyễn Năng Tiến', N'Trong bối cảnh Chiến lược quốc gia về tăng trưởng xanh và Quyết định số 876/QĐ-TTg của Thủ tướng Chính phủ về chuyển đổi năng lượng xanh đang được đẩy mạnh, việc phát triển hạ tầng trạm sạc cho phương', '/uploads/tin-su-kien/8489b590cc39ed36.jpg', '2026-04-09');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'day-manh-ung-dung-khoa-hoc-cong-nghe-vao-phat-trien-kinh-te-xa-hoi-tai-xa-phong-dien', N'Đẩy mạnh ứng dụng Khoa học & Công nghệ vào phát triển kinh tế - xã hội tại xã Phong Điền', N'<p><strong>Vừa qua, ngày 07/04/2026, Đoàn công tác của Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ (KH&amp;CN) đã có buổi làm việc trực tiếp tại UBND xã Phong Điền nhằm khảo sát nhu cầu và thúc đẩy chuyển giao công nghệ tại địa phương.</strong></p><p>Nhằm thực hiện mục tiêu đưa các thành tựu khoa học vào thực tiễn sản xuất và quản lý, buổi làm việc tập trung vào việc giới thiệu các dịch vụ KH&amp;CN trọng điểm, đồng thời lắng nghe những trăn trở thực tế từ phía chính quyền và nhân dân xã Phong Điền. Đoàn công tác do Bà <strong>Đoàn Thị Hồng Quyên</strong> – Phó Giám đốc Trung tâm làm trưởng đoàn cùng đội ngũ chuyên viên từ các phòng: Dịch vụ - Giao dịch công nghệ, Công nghệ sinh học và Ứng dụng &amp; Chuyển giao công nghệ đã trực tiếp khảo sát và làm việc tại xã Phong Điền. Tiếp đoàn có Ông <strong>Trần Thiện Triết</strong> – Phó Chủ tịch thường trực UBND xã cCùng đại diện các phòng văn hóa, phòng kinh tế, trung tâm dịch vụ hành chính công và trung tâm dịch vụ tổng hợp.</p><p>Tại buổi làm việc, đoàn công tác đã giới thiệu hệ sinh thái các dịch vụ KH&amp;CN thế mạnh mà Trung tâm đang triển khai, có khả năng ứng dụng ngay vào điều kiện đặc thù của địa phương, bao gồm:</p><ul><li><strong>Dịch vụ Truy xuất nguồn gốc (TXNG):</strong> Hỗ trợ minh bạch hóa thông tin sản phẩm, giúp nông sản địa phương khẳng định thương hiệu trên thị trường.</li><li><strong>Tư vấn phát triển sản phẩm OCOP:</strong> Định hướng và hỗ trợ kỹ thuật để các sản phẩm đặc trưng của xã đạt chuẩn "Mỗi xã một sản phẩm".</li><li><strong>Dịch vụ Chuyển đổi số:</strong> Giải pháp hiện đại hóa quy trình quản lý hành chính và sản xuất kinh doanh.</li><li><strong>Ứng dụng KH&amp;CN vào mô hình sản xuất:</strong> Chuyển giao các quy trình kỹ thuật mới, giúp tăng năng suất và chất lượng cây trồng, vật nuôi.</li></ul><p>Ông <strong>Trần Thiện Triết</strong> – Phó Chủ tịch thường trực UBND xã Phong Điền đánh giá cao những giải pháp mà Trung tâm đề xuất. Trong bối cảnh địa phương đang đẩy mạnh phát triển nông nghiệp bền vững và hiện đại hóa hành chính, việc ứng dụng KH&amp;CN được xem là "chìa khóa" quan trọng.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/e2bbaf635a4b2a21.jpg" width="2560" height="1920"><figcaption>Ông <strong>Trần Thiện Triết</strong> – Phó Chủ tịch thường trực UBND xã Phong Điền</figcaption></figure><p>Hai bên đã có những thảo luận sôi nổi, thẳng thắn về khả năng thích ứng của công nghệ với điều kiện thổ nhưỡng và trình độ canh tác của người dân. Kết thúc buổi làm việc, đại diện Trung tâm và UBND xã đã thống nhất các nội dung ưu tiên hợp tác và đề xuất các nhiệm vụ KH&amp;CN cụ thể trong thời gian tới.</p><p>Chuyến công tác không chỉ mở ra cơ hội hợp tác giữa hai đơn vị mà còn góp phần quan trọng trong việc đưa khoa học kỹ thuật rời khỏi phòng thí nghiệm để thực sự "bén rễ" trên đồng ruộng, hỗ trợ bà con nông dân và chính quyền xã Phong Điền phát triển bền vững.</p>', N'Kim Anh', N'Vừa qua, ngày 07/04/2026, Đoàn công tác của Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ (KH&amp;CN) đã có buổi làm việc trực tiếp tại UBND xã Phong Điền nhằm khảo sát nhu cầu và thúc đẩy chuyển g', '/uploads/tin-su-kien/b32d5dfd0eeb1ef3.jpg', '2026-04-07');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'hop-mat-nha-khoa-hoc-tri-thuc-tieu-bieu-dau-xuan-2026', N'Họp mặt nhà khoa học, trí thức tiêu biểu dầu Xuân 2026', N'<p>Ngày 5-2, Thành ủy, HÐND, UBND, Ủy ban MTTQVN TP Cần Thơ tổ chức họp mặt các nhà khoa học, trí thức nhân dịp Xuân Bính Ngọ 2026. Ông Nguyễn Tuấn Anh, Phó Bí thư Thành ủy, Trưởng Đoàn đại biểu Quốc hội TP Cần Thơ; ông Trương Cảnh Tuyên, Phó Bí thư Thành ủy, Chủ tịch UBND TP Cần Thơ; lãnh đạo các sở, ban, ngành cùng đông đảo nhà khoa học, trí thức đến dự.</p><figure class="image"><img style="aspect-ratio:800/441;" src="/uploads/tin-su-kien/d5b5752155e7b2b4.webp" alt="" width="800" height="441"><figcaption><i>Lãnh đạo thành phố chụp hình lưu niệm cùng các nhà khoa học, trí thức tiêu biểu tại buổi họp mặt.</i></figcaption></figure><p>Tại buổi họp mặt, các đại biểu cùng nghe ông Vũ Hải Quân, Thứ trưởng Thường trực Bộ Khoa học và Công nghệ (tham dự trực tuyến), chia sẻ những thành tựu nổi bật của ngành Khoa học và Công nghệ trong năm 2025, cũng như định hướng lớn trong thời gian tới. Các đại biểu trao đổi, thảo luận về khơi thông nguồn lực, thúc đẩy phát triển khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số, chung tay xây dựng TP Cần Thơ sớm trở thành trung tâm động lực khoa học công nghệ, đổi mới sáng tạo của vùng ĐBSCL. Lãnh đạo Sở Khoa học và Công nghệ thành phố thông tin các hoạt động khoa học và công nghệ nổi bật của thành phố năm 2025 cùng những chương trình, dự án quy mô đã, đang và sắp triển khai thực hiện.</p><figure class="image"><img style="aspect-ratio:800/483;" src="/uploads/tin-su-kien/4a3277127e27e17b.webp" alt="" width="800" height="483"><figcaption><i>Ông Trương Cảnh Tuyên, Phó Bí thư Thành ủy, Chủ tịch UBND TP Cần Thơ, phát biểu tại buổi họp mặt.</i></figcaption></figure><p>Phát biểu tại buổi họp mặt, ông Trương Cảnh Tuyên gửi lời chúc Tết đến toàn thể đại biểu, các nhà khoa học, trí thức. Ðồng thời, kêu gọi các nhà khoa học, trí thức tiếp tục đồng hành cùng thành phố, tập trung vào các nhiệm vụ trọng tâm: ổn định và phát triển sau khi hợp nhất các tỉnh, thành bằng cách nghiên cứu, đề xuất các mô hình quản trị đô thị, nông thôn, bảo đảm bộ máy vận hành thông suốt; tiên phong nghiên cứu, ứng dụng các công nghệ mới như trí tuệ nhân tạo, dữ liệu lớn, chuỗi khối, robot… vào các lĩnh vực trọng điểm. Thành phố cam kết tạo môi trường thuận lợi, cơ chế thông thoáng và ưu tiên nguồn lực để các ý tưởng sáng tạo sớm được thực hiện.</p><figure class="image"><img style="aspect-ratio:800/534;" src="/uploads/tin-su-kien/868a1d5ba21bd71f.webp" alt="" width="800" height="534"><figcaption><i>Đại diện 2 Ban chủ nhiệm đề tại đạt loại xuất sắc được nhận Bằng khen của UBND thành phố.</i></figcaption></figure><p>Dịp này, UBND TP Cần Thơ tặng Bằng khen đến 2 tập thể Ban Chủ nhiệm đề tài khoa học và công nghệ được Hội đồng nghiệm thu, đánh giá xếp loại xuất sắc: đề tài “Nghiên cứu đa dạng hóa sản phẩm chế biến từ trái mít (Artocarpus heterophyllus LAM)”, đề tài “Nghiên cứu quy trình sản xuất bột không gluten (gluten free) từ trái sa kê và ứng dụng trong sản xuất bánh và bún”.</p><p><em>Nguồn: <a href="https://baocantho.com.vn/hop-mat-nha-khoa-hoc-tri-thuc-tieu-bieu-dau-xuan-2026-a198203.html?gidzl=U938IgjL9KL-YC1DhaicHNo1mq-r5294C870JU4HB11dXymVjan-HcY8cXZi6IyIRzxDI3RdyzG_hb4aHm" target="_blank" rel="noopener">https://baocantho.com.vn/hop-mat-nha-khoa-hoc-tri-thuc-tieu-bieu-dau-xuan-2026-a198203.html?gidzl=U938IgjL9KL-YC1DhaicHNo1mq-r5294C870JU4HB11dXymVjan-HcY8cXZi6IyIRzxDI3RdyzG_hb4aHm</a></em></p>', N'Lệ Thu', N'Ngày 5-2, Thành ủy, HÐND, UBND, Ủy ban MTTQVN TP Cần Thơ tổ chức họp mặt các nhà khoa học, trí thức nhân dịp Xuân Bính Ngọ 2026. Ông Nguyễn Tuấn Anh, Phó Bí thư Thành ủy, Trưởng Đoàn đại biểu Quốc hội', '/uploads/tin-su-kien/f8c128e287bc5da2.webp', '2026-04-06');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'hoi-thao-khoa-hoc-ung-dung-cong-nghe-trong-bao-ve-tai-nguyen-moi-truong-huong-den-san-xuat-xanh-va-ben-vung', N'Hội thảo khoa học: Ứng dụng công nghệ trong bảo vệ tài nguyên, môi trường hướng đến  sản xuất xanh và bền vững', N'<p><strong>Cần Thơ, ngày 19 tháng 11 năm 2025</strong> – Sáng nay, tại Trung tâm Ứng dụng Tiến bộ khoa học và công nghệ TP. Cần Thơ, Hội thảo khoa học cấp thành phố với chủ đề <strong>“Ứng dụng công nghệ trong bảo vệ tài nguyên, môi trường hướng đến sản xuất xanh và bền vững”</strong> đã diễn ra thành công tốt đẹp.</p><p>Hội thảo thu hút sự tham gia của các nhà khoa học, chuyên gia hàng đầu từ các trường đại học lớn, cùng đại diện lãnh đạo Sở Khoa học và Công nghệ (KH&amp;CN) TP. Cần Thơ và đông đảo đại biểu tham dự.</p><h3><strong>I. KHAI MẠC VÀ ĐỊNH HƯỚNG CHIẾN LƯỢC</strong></h3><p>Phát biểu Khai mạc Hội thảo, <strong>Ông Bùi Minh Châu - Phó Giám đốc</strong> <strong>đạo Sở KH&amp;CN TP. Cần Thơ</strong> nhấn mạnh vai trò chiến lược của khoa học công nghệ trong việc giải quyết các thách thức môi trường hiện nay. Hội thảo là diễn đàn quan trọng nhằm tìm kiếm các giải pháp công nghệ khả thi, thúc đẩy chuyển đổi mô hình sản xuất truyền thống sang <strong>sản xuất xanh và bền vững</strong>, phù hợp với định hướng phát triển bền vững của Thành phố và khu vực Đồng bằng sông Cửu Long.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/4c701a1e1ff881d1.png" width="2560" height="1920"><figcaption>Ông Bùi Minh Châu - Phó Giám đốc sở Khoa học và công nghệ thành phố Cần Thơ</figcaption></figure><h3><strong>II. CÁC THAM LUẬN KHOA HỌC CHUYÊN SÂU</strong></h3><p>Phiên tham luận đã mang đến những báo cáo có giá trị thực tiễn và học thuật cao, tập trung vào các lĩnh vực nóng hiện nay:</p><ul><li><strong>Giám sát Khí hậu và Nông nghiệp:</strong> TS. Thái Phương Vũ (Trường Đại học Tài nguyên và Môi trường TP. Hồ Chí Minh) đã trình bày tham luận về <strong>“Ứng dụng công nghệ giám sát khí thải nhà kính trong canh tác nông nghiệp”</strong>, mở ra hướng đi mới trong việc đo lường và giảm thiểu dấu chân carbon từ hoạt động nông nghiệp.</li></ul><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/a0ce61b49dfc8544.jpg" width="2568" height="1926"><figcaption>TS. Thái Phương Vũ</figcaption></figure><ul><li><strong>Xử lý Ô nhiễm và Tái chế Phụ phẩm:</strong><ul><li>TS. Châu Thị Đa (Trường Đại học Tôn Đức Thắng) trình bày về <strong>“Ứng dụng công nghệ trong xử lý và tái sử dụng bùn thải thủy sản và phụ phẩm nông nghiệp”</strong>, đưa ra các kỹ thuật biến chất thải thành tài nguyên.</li></ul></li></ul><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/5e8946422246ee4f.jpg" width="2568" height="1926"><figcaption>TS. Châu Thị Đa</figcaption></figure><ul><li>TS. Nguyễn Điền Châu - Công ty TNHH MTV Xây dựng Bình Minh đã chia sẻ về <strong>“Giải pháp nâng cao hiệu quả tái sử dụng chất thải rắn xây dựng”</strong>, nhấn mạnh vai trò của công nghệ trong quản lý rác thải và vật liệu xây dựng.</li></ul><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/dd6a8f644ae3eca4.jpg" width="2560" height="1920"><figcaption>TS. Nguyễn Điền Châu</figcaption></figure><h3><strong>III. TRƯNG BÀY SẢN PHẨM CÔNG NGHỆ VÀ TRUY XUẤT NGUỒN GỐC</strong></h3><p>Trong thời gian giải lao, các đại biểu đã có dịp tham quan khu vực trưng bày đặc biệt, thể hiện rõ tính ứng dụng của khoa học công nghệ trong thực tiễn:</p><ul><li><strong>Gian hàng của Trung tâm Ứng dụng Tiến bộ KH&amp;CN TP. Cần Thơ</strong> và <strong>Trung Tâm Thông Tin và ứng Dụng Khoa Học Công Nghệ Hậu Giang</strong> đã giới thiệu các kết quả nghiên cứu, sản phẩm công nghệ mới nhất được chuyển giao cho các doanh nghiệp địa phương như: rượu nấm linh chi hoặc các sản phẩm liên quan cũng như các sản phẩm nông nghiệp chế biến như sầu riêng sấy, nhãn sấy nhân hột sen…</li></ul><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/f010826769b8dea5.jpg" width="2560" height="1920"></figure><ul><li>Điểm nhấn là khu vực giới thiệu các sản phẩm chủ lực của Cần Thơ <strong>đã được áp dụng thành công Hệ thống Quản lý Truy xuất Nguồn gốc Sản phẩm Hàng hóa</strong> của Thành phố. Qua việc quét mã QR, đại biểu trực tiếp kiểm tra tính minh bạch của chuỗi cung ứng, từ đó thấy rõ hiệu quả của công nghệ trong việc nâng cao giá trị và niềm tin cho sản phẩm nông sản, thực phẩm địa phương. Các sản phẩm này chính là minh chứng sinh động cho việc <strong>biến công nghệ thành giá trị xanh</strong> trong sản xuất.</li></ul><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/745277d68e24c173.jpg" width="2560" height="1920"></figure><h3><strong>IV. TRAO ĐỔI VÀ ĐỊNH HƯỚNG HỢP TÁC</strong></h3><p>Phần <strong>Trao đổi và Thảo luận</strong> là điểm nhấn quan trọng nhất của Hội thảo, diễn ra hết sức sôi nổi dưới sự điều hành của Lãnh đạo Sở KH&amp;CN TP. Cần Thơ cùng sự tham gia của các chuyên gia và đại biểu.</p><p>Các đại biểu đã đặt nhiều câu hỏi sâu về <strong>tính khả thi về mặt kinh tế</strong> khi áp dụng các công nghệ mới, đặc biệt trong bối cảnh các doanh nghiệp địa phương còn nhiều hạn chế về vốn đầu tư. Các nhà khoa học đã cung cấp phân tích chi tiết về <strong>chi phí đầu tư và thời gian hoàn vốn</strong> cho các công nghệ giám sát và xử lý ô nhiễm, đồng thời đề xuất các mô hình chuyển giao công nghệ phù hợp với quy mô sản xuất tại Cần Thơ. Sự tương tác hai chiều này đã làm rõ được những rào cản thực tiễn và mở ra nhiều hướng hợp tác tiềm năng giữa cơ quan quản lý, các viện nghiên cứu và cộng đồng doanh nghiệp trong thời gian tới.</p><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/916790453bb85f68.jpg" width="2568" height="1926"></figure><figure class="image"><img style="aspect-ratio:1920/2560;" src="/uploads/tin-su-kien/d56f76b8b36daab2.jpg" width="1920" height="2560"></figure><h3><strong>V. BẾ MẠC VÀ TRIỂN KHAI HÀNH ĐỘNG</strong></h3><p>Hội thảo đã kết thúc vào lúc <strong>11 giờ 00</strong> cùng ngày. Ban Tổ chức đã ghi nhận các kiến nghị khoa học quan trọng và cam kết tổng hợp kết quả để tham mưu cho Lãnh đạo Thành phố trong việc xây dựng các chương trình hành động và đầu tư công nghệ trong lĩnh vực bảo vệ môi trường và sản xuất bền vững.</p><p>Thành công của Hội thảo là bước đệm quan trọng, khẳng định quyết tâm của Cần Thơ trong việc sử dụng khoa học công nghệ làm động lực chính để đạt được mục tiêu <strong>phát triển kinh tế xanh và bền vững</strong> trong thời gian tới.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/27edd250b6abdeab.jpg" width="2560" height="1920"></figure>', N'', N'Cần Thơ, ngày 19 tháng 11 năm 2025 – Sáng nay, tại Trung tâm Ứng dụng Tiến bộ khoa học và công nghệ TP. Cần Thơ, Hội thảo khoa học cấp thành phố với chủ đề “Ứng dụng công nghệ trong bảo vệ tài nguyên,', '/uploads/tin-su-kien/09cd1d052d5a9399.jpg', '2025-11-19');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'giai-the-thao-dien-tu-chau-a-eca-2025-chinh-thuc-do-bo-tai-dong-bang-song-cuu-long', N'GIẢI THỂ THAO ĐIỆN TỬ CHÂU Á (ECA) 2025 CHÍNH THỨC ĐỔ BỘ TẠI ĐỒNG BẰNG SÔNG CỬU LONG!', N'<h2>🔥 <strong>CẦN THƠ RỰC LỬA! GIẢI THỂ THAO ĐIỆN TỬ CHÂU Á (ECA) 2025 CHÍNH THỨC ĐỔ BỘ TẠI ĐỒNG BẰNG SÔNG CỬU LONG!</strong> 🔥</h2><p>Năm 2025 sẽ là một năm đáng nhớ đối với cộng đồng Esports Việt Nam và khu vực! Thành phố Cần Thơ tự hào là đơn vị đăng cai tổ chức sự kiện thể thao điện tử lớn nhất khu vực: <strong>ESPORTS CHAMPIONSHIPS ASIA (ECA) CAN THO 2025!</strong></p><h3><strong>🌏 Tầm Vóc Châu Lục – Tâm Điểm Công Nghệ</strong></h3><p>ECA 2025 không chỉ là một giải đấu, mà là nơi hội tụ của những tài năng Esports xuất sắc nhất đến từ các cường quốc trong khu vực, bao gồm: <strong>Trung Quốc, Nhật Bản, Hàn Quốc, Lào, Philippines, Thái Lan, và Việt Nam!</strong></p><p>Đây là cơ hội vàng để người hâm mộ Việt Nam được chứng kiến tận mắt những trận đấu đỉnh cao, những pha xử lý mãn nhãn và tinh thần cạnh tranh không ngừng nghỉ của các đội tuyển Châu Á.</p><h3><strong>🎮 Sân Chơi Của Những Huyền Thoại</strong></h3><p>Giải đấu sẽ tranh tài tại hai bộ môn Esports được yêu thích nhất toàn cầu:</p><ul><li><strong>League of Legends (Liên Minh Huyền Thoại):</strong> Chiến thuật đỉnh cao, đồng đội hoàn hảo!</li><li><strong>Crossfire:</strong> Những pha đấu súng nghẹt thở, kỹ năng cá nhân quyết định!</li></ul><h3><strong>📅 Thông Tin Sự Kiện (Phải Biết!)</strong></h3><ul><li><strong>Thời gian:</strong> <strong>Ngày 20 – 21.11.2025</strong></li><li><strong>Địa điểm:</strong> <strong>SÀN GIAO DỊCH CÔNG NGHỆ CẦN THƠ</strong><ul><li><i>Địa chỉ:</i> 166 đường Nguyễn Văn Cừ Nối Dài, An Bình, Cần Thơ.</li></ul></li></ul><p>Hãy sẵn sàng hòa mình vào không khí cuồng nhiệt, cổ vũ cho đội tuyển Việt Nam và chứng kiến lịch sử Esports Châu Á được viết nên ngay tại Cần Thơ!</p><h3><strong>🤝 Cùng Đồng Hành Kiến Tạo Lịch Sử</strong></h3><p>Sự kiện được tổ chức bởi <strong>CAMT</strong> và tự hào có sự đồng hành chiến lược từ các đối tác lớn như <strong>VNGAMES, VTC Online, SIDEWALK, STEPIN, MIRONE Entertainment</strong> cùng các đối tác cung ứng uy tín như <strong>Viettel, Charmant Lights, Agon, Evnia, CASTA, FPT Play.</strong></p><p>📢 <strong>THÔNG ĐIỆP GỬI ĐẾN FANS:</strong></p><p>Hãy đánh dấu ngay lịch trình của bạn, chuẩn bị tinh thần và đến Sàn Giao Dịch Công Nghệ Cần Thơ để cảm nhận sức nóng của ECA 2025! <strong>Đây là sân nhà của chúng ta!</strong></p><p><strong>#ECA2025 #EsportsAsia #CanTho #LeagueOfLegends #Crossfire #VietnamEsports</strong></p><figure class="image"><img style="aspect-ratio:467/940;" src="/uploads/tin-su-kien/7fabaada03546de9.jpg" width="467" height="940"></figure>', N'', N'🔥 CẦN THƠ RỰC LỬA! GIẢI THỂ THAO ĐIỆN TỬ CHÂU Á (ECA) 2025 CHÍNH THỨC ĐỔ BỘ TẠI ĐỒNG BẰNG SÔNG CỬU LONG! 🔥 Năm 2025 sẽ là một năm đáng nhớ đối với cộng đồng Esports Việt Nam và khu vực! Thành phố Cần ', '/uploads/tin-su-kien/a1657b77d72dcf47.jpg', '2025-11-17');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'thanh-pho-can-tho-diem-den-moi-cua-giai-the-thao-dien-tu-chau-a-2025', N'THÀNH PHỐ CẦN THƠ – ĐIỂM ĐẾN MỚI CỦA GIẢI THỂ THAO ĐIỆN TỬ CHÂU Á 2025', N'<p>THÀNH PHỐ CẦN THƠ – ĐIỂM ĐẾN MỚI CỦA GIẢI THỂ THAO ĐIỆN TỬ CHÂU Á 2025</p><p>Sẵn sàng bùng nổ – Sẵn sàng đón bạn!</p><p>Tự hào là trung tâm năng động bậc nhất của vùng Đồng bằng sông Cửu Long, TP. Cần Thơ chính thức được lựa chọn làm địa điểm đăng cai Giải Thể thao Điện tử Châu Á 2025 (ECA 2025) – sự kiện eSports đẳng cấp khu vực, quy tụ những tuyển thủ xuất sắc cùng hàng ngàn người hâm mộ từ khắp nơi hội tụ.</p><p>Với vị trí chiến lược chỉ cách TP. Hồ Chí Minh khoảng 170 km, hạ tầng đô thị hiện đại và nhịp sống trẻ trung, Cần Thơ đang vươn mình mạnh mẽ trở thành trung tâm thể thao – công nghệ – giải trí quốc tế của miền Tây Nam Bộ. ECA 2025 chính là cột mốc quan trọng đánh dấu bước tiến mới trong hành trình đưa hình ảnh Cần Thơ ra bản đồ eSports châu Á.</p><p><img src="/uploads/tin-su-kien/39eb22f1af1ccee8.png" alt="📍" width="16" height="16"> Toàn bộ các hoạt động, chương trình và trận thi đấu chính thức sẽ diễn ra tại:</p><p>Sàn Giao dịch Công nghệ Cần Thơ</p><p><img src="/uploads/tin-su-kien/a22adde508f569b8.png" alt="📌" width="16" height="16"> 166 đường Nguyễn Văn Cừ nối dài, phường An Bình, quận Ninh Kiều, TP. Cần Thơ.</p><p>Không gian hiện đại – trang thiết bị đạt chuẩn – sẵn sàng chào đón hàng loạt trận đấu cực mãn nhãn cùng những trải nghiệm công nghệ ấn tượng.</p><p><img src="/uploads/tin-su-kien/11a6192f5544284c.png" alt="🌟" width="16" height="16"> Và đặc biệt hơn thế!</p><p>Bên cạnh những màn đối đầu đỉnh cao giữa các vận động viên thể thao điện tử hàng đầu châu lục, người hâm mộ còn được hòa mình vào chuỗi hoạt động bên lề hấp dẫn:</p><p><img src="/uploads/tin-su-kien/3cb0484981a40776.png" alt="🎯" width="16" height="16"> Khu trải nghiệm công nghệ – gaming gear</p><p><img src="/uploads/tin-su-kien/3cb0484981a40776.png" alt="🎯" width="16" height="16"> Gian hàng thương mại – giải trí sáng tạo</p><p><img src="/uploads/tin-su-kien/3cb0484981a40776.png" alt="🎯" width="16" height="16"> Watch Party cổ vũ cùng cộng đồng</p><p><img src="/uploads/tin-su-kien/3cb0484981a40776.png" alt="🎯" width="16" height="16"> Sự kiện mở cửa HOÀN TOÀN MIỄN PHÍ</p><p>Đây không chỉ là giải đấu, mà còn là lễ hội công nghệ – thể thao điện tử lớn nhất miền Tây, mang đến bầu không khí cuồng nhiệt, trẻ trung và tràn đầy năng lượng.</p><p><img src="/uploads/tin-su-kien/3f5cc1e83e685c70.png" alt="🔥" width="16" height="16"> Cần Thơ đã sẵn sàng. Còn bạn thì sao?</p><p>Hãy đánh dấu lịch, rủ “đồng đội”, chuẩn bị cháy hết mình tại ECA 2025 – nơi cảm xúc bùng nổ, nơi kết nối đam mê và nơi khẳng định vị thế mới của thành phố Cần Thơ trên sân chơi châu Á!</p><figure class="image"><img style="aspect-ratio:2560/2560;" src="/uploads/tin-su-kien/1c0c49e96886816a.jpg" width="2560" height="2560"></figure>', N'', N'THÀNH PHỐ CẦN THƠ – ĐIỂM ĐẾN MỚI CỦA GIẢI THỂ THAO ĐIỆN TỬ CHÂU Á 2025 Sẵn sàng bùng nổ – Sẵn sàng đón bạn! Tự hào là trung tâm năng động bậc nhất của vùng Đồng bằng sông Cửu Long, TP. Cần Thơ chính t', '/uploads/tin-su-kien/9ff44e6c1542cecd.jpg', '2025-11-14');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'don-dau-ky-nguyen-so-tai-thuan-hoa-tap-huan-ung-dung-cong-nghe-so-a-i-trong-phat-trien-thuong-mai-va-quan-ly-hanh-chinh', N'ĐÓN ĐẦU KỶ NGUYÊN SỐ TẠI THUẬN HÒA: TẬP HUẤN ỨNG DỤNG CÔNG NGHỆ SỐ & A.I. TRONG PHÁT TRIỂN THƯƠNG MẠI VÀ QUẢN LÝ HÀNH CHÍNH', N'<h3><strong>I. Mục Tiêu Chiến Lược: Nâng Cấp Kỹ Năng Số Toàn Diện</strong></h3><p>Buổi tập huấn được tổ chức với mục tiêu kép: <strong>thúc đẩy kinh tế số</strong> thông qua thương mại điện tử và <strong>tối ưu hóa hiệu suất</strong> trong quản lý hành chính công. Sự kiện đã thu hút đông đảo cán bộ, công chức, đại diện các doanh nghiệp, hợp tác xã và hộ kinh doanh trên địa bàn xã Thuận Hòa tham gia.</p><p>Sự hiện diện của Lãnh đạo UBND xã Thuận Hòa và Lãnh đạo Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ TP. Cần Thơ đã khẳng định quyết tâm của chính quyền Thành phố trong việc đưa công nghệ số và A.I. vào phục vụ đời sống và phát triển kinh tế địa phương.</p><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/81300958865a8205.jpg" width="2568" height="1926"></figure><h3><strong>II. Nội Dung Đột Phá: Từ Kinh Doanh Trực Tuyến Đến Quản Lý Thông Minh</strong></h3><p>Chương trình tập huấn được chia thành hai phiên chuyên đề chuyên sâu, mang tính thực hành cao:</p><h4><strong>Phần 1: Ứng Dụng Công Nghệ Số Trong Thương Mại và Bán Hàng Trực Tuyến</strong></h4><p>Phiên sáng tập trung vào việc trang bị "vũ khí số" cho cộng đồng doanh nghiệp, giúp họ khai thác hiệu quả thị trường trực tuyến:</p><ul><li><strong>Truy Xuất Nguồn Gốc và Niềm Tin Khách Hàng:</strong> Học viên được giới thiệu và hướng dẫn áp dụng <strong>Hệ thống Quản lý Truy xuất Nguồn gốc Sản phẩm Hàng hóa TP. Cần Thơ</strong>. Đây là bước đi quan trọng giúp minh bạch hóa thông tin, xây dựng uy tín thương hiệu và tăng khả năng cạnh tranh.</li><li><strong>Xu Hướng Thương Mại Điện Tử:</strong> Cung cấp tổng quan về kinh tế số, xu hướng Livestream bán hàng và cách xây dựng thương hiệu số cá nhân/doanh nghiệp trên các nền tảng lớn.</li></ul><p><strong>Thực hành Livestream Chuyên nghiệp:</strong> Dưới sự hướng dẫn của đội ngũ kỹ thuật viên từ Học viện Design24, các học viên đã được trải nghiệm thực tế các thiết bị công nghệ và tự mình thực hành Livestream bán hàng, tạo ra những phiên giao lưu trực tuyến sôi nổi và hiệu quả.</p><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/29dc1453755fcc03.jpg" width="2568" height="1926"></figure><h4><strong>Phần 2: Ứng Dụng Trí Tuệ Nhân Tạo (A.I.) Trong Quản Lý Hành Chính</strong></h4><p>Phiên chiều tập trung vào việc hiện đại hóa quy trình công tác hành chính, giúp cán bộ công chức nâng cao năng suất:</p><ul><li><strong>A.I. trong Tác nghiệp Hành chính:</strong> Học viên được hướng dẫn sử dụng các công cụ A.I. (như ChatGPT, Copilot, Notion AI,...) để giải quyết các tác vụ thường ngày như: <strong>tổng hợp báo cáo nhanh</strong>, <strong>soạn thảo văn bản chuẩn hóa</strong>, và <strong>lập kế hoạch công việc</strong> một cách khoa học.</li><li><strong>Sáng tạo Nội dung Số:</strong> Trải nghiệm bộ công cụ sáng tạo <strong>Design24 A.I.</strong>, giúp cán bộ có thể tự thiết kế ấn phẩm truyền thông, poster thông báo, hoặc video ngắn phục vụ cho công tác tuyên truyền và dịch vụ công.</li></ul><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/ad23f7bad6cc22b8.jpg" width="2560" height="1920"></figure><h3><strong>III. Yếu Tố Thành Công và Cam Kết Thực Hành</strong></h3><p>Buổi tập huấn đã diễn ra thành công tốt đẹp nhờ vào sự chuẩn bị kỹ lưỡng về cơ sở vật chất (hội trường rộng, Wifi ổn định) và sự nhiệt tình, chuyên nghiệp của đội ngũ Giảng viên (Ths. Nguyễn Hoài Anh, NCS. Ths Nguyễn Văn Cường, Nguyễn Quốc Tuấn) cùng các Kỹ thuật viên livestream của Học viện Design24.</p><p>Đặc biệt, sự chủ động của các học viên – mang theo laptop và điện thoại thông minh, cài đặt sẵn các ứng dụng như Canva, CapCut, và A.I. Tools – đã giúp quá trình thực hành trực tiếp diễn ra suôn sẻ, đảm bảo <strong>tính thực hành cao</strong> theo đúng yêu cầu đề ra.</p><p>Buổi tập huấn này là bước khởi đầu quan trọng, góp phần hình thành một đội ngũ cán bộ và doanh nghiệp địa phương tiên phong trong việc nắm bắt công nghệ, tạo động lực mạnh mẽ cho công cuộc <strong>Chuyển đổi số</strong> toàn diện tại xã Thuận Hòa và Thành phố Cần Thơ.</p><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/17dced1693c72996.jpg" width="2568" height="1926"></figure>', N'', N'I. Mục Tiêu Chiến Lược: Nâng Cấp Kỹ Năng Số Toàn Diện Buổi tập huấn được tổ chức với mục tiêu kép: thúc đẩy kinh tế số thông qua thương mại điện tử và tối ưu hóa hiệu suất trong quản lý hành chính côn', '/uploads/tin-su-kien/901ed159e1b1bde9.jpg', '2025-11-07');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'ho-tro-doanh-nghiep-to-chuc-ca-nhan-phat-trien-tai-san-tri-tue', N'Hỗ trợ doanh nghiệp, tổ chức, cá nhân phát triển tài sản trí tuệ', N'<p>Theo Sở Khoa học và Công nghệ TP Cần Thơ, thực hiện chương trình Phát triển tài sản trí tuệ TP Cần Thơ đến năm 2030, thành phố đã hỗ trợ kinh phí đăng ký bảo hộ tài sản trí tuệ cho 38 tổ chức, cá nhân bao gồm 60 nhãn hiệu trong nước, 2 nhãn hiệu nước ngoài, 16 sáng chế. Đồng thời, hỗ trợ triển khai thực hiện 9 nhiệm vụ nhằm thúc đẩy các hoạt động tạo ra tài sản trí tuệ, nâng cao năng lực cạnh tranh, giữ gìn uy tín, tạo dựng thương hiệu cho sản phẩm, dịch vụ và thúc đẩy phát triển kinh tế, xã hội địa phương; tuyên truyền, phổ biến kiến thức về sở hữu trí tuệ và phát triển thương hiệu; xác lập quyền sở hữu trí tuệ các giống lúa OM của Viện Lúa ĐBSCL; xây dựng, khai thác và phát triển giá trị tài sản trí tuệ sản phẩm thuộc Chương trình OCOP năm 2022-2025; phát triển thương hiệu du lịch cộng đồng Cồn Sơn; phát triển tài sản trí tuệ cho các doanh nghiệp và các sản phẩm tại tỉnh Hậu Giang (trước hợp nhất) giai đoạn 2024-2027…</p><p> </p><figure class="image"><img style="aspect-ratio:600/450;" src="/uploads/tin-su-kien/675247854db7947d.webp" alt="" width="600" height="450"><figcaption><i>Phát triển thương hiệu du lịch cộng đồng Cồn Sơn là một trong những nhiệm vụ được hỗ trợ từ chương trình Phát triển tài sản trí tuệ TP Cần Thơ. Trong ảnh: Du khách tham quan một điểm du lịch tại Cồn Sơn</i></figcaption></figure><p>Ngoài ra, TP Cần Thơ còn có 5 tổ chức trung gian hỗ trợ các dịch vụ tư vấn, đăng ký bảo hộ sở hữu trí tuệ đã kịp thời tư vấn hỗ trợ các tổ chức, cá nhân thực hiện thủ tục đăng ký bảo hộ quyền sở hữu trí tuệ.</p><p><em>Nguồn: <a href="https://baocantho.com.vn/ho-tro-doanh-nghiep-to-chuc-ca-nhan-phat-trien-tai-san-tri-tue-a193540.html" target="_blank" rel="noopener">https://baocantho.com.vn/ho-tro-doanh-nghiep-to-chuc-ca-nhan-phat-trien-tai-san-tri-tue-a193540.html</a></em></p>', N'Sưu tầm', N'Theo Sở Khoa học và Công nghệ TP Cần Thơ, thực hiện chương trình Phát triển tài sản trí tuệ TP Cần Thơ đến năm 2030, thành phố đã hỗ trợ kinh phí đăng ký bảo hộ tài sản trí tuệ cho 38 tổ chức, cá nhân', '/uploads/tin-su-kien/74d2f2c2d26f1999.jpg', '2025-11-06');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'giai-phap-ho-tro-quan-ly-va-phat-trien-nhan-hieu-tap-the-nhan-hieu-chung-nhan-chi-dan-dia-ly-cho-cac-san-pham-chu-luc-cua-dia-phuong-trong-boi-canh-chuyen-doi-so', N'Giải pháp hỗ trợ quản lý và phát triển nhãn hiệu tập thể, nhãn hiệu chứng nhận, chỉ dẫn địa lý cho các sản phẩm chủ lực của địa phương trong bối cảnh chuyển đổi số', N'<p>Ngày 31/10/2025, Sở Khoa học và Công nghệ (KH&amp;CN) TP. Cần Thơ tổ chức Hội thảo “Giải pháp hỗ trợ quản lý và phát triển nhãn hiệu tập thể, nhãn hiệu chứng nhận, chỉ dẫn địa lý cho các sản phẩm chủ lực trong bối cảnh chuyển đổi số” tại Khách sạn TTC Cần Thơ.</p><p>Hội thảo có sự tham dự của ông Phạm Trường Giang – Phó Giám đốc Sở KH&amp;CN TP. Cần Thơ, cùng đại diện Sở KH&amp;CN các tỉnh, Cục Sở hữu trí tuệ, Viện Sở hữu trí tuệ quốc gia, Trường Đại học Cần Thơ, cùng các doanh nghiệp, hợp tác xã, tổ chức và cá nhân sở hữu, quản lý thương hiệu sản phẩm địa phương.</p><p> </p><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/e1085617d3e8ed6b.png" width="2568" height="1926"></figure><p>Ông Phạm Trường Giang – Phó Giám đốc Sở Khoa học và Công nghệ TP. Cần Thơ phát biểu tại Hội thảo.</p><p>Phát biểu khai mạc, ông Phạm Trường Giang nhấn mạnh tầm quan trọng của việc xây dựng, quản lý và phát triển tài sản trí tuệ trong thời kỳ hội nhập và chuyển đổi số, coi đây là yếu tố then chốt nâng cao giá trị, uy tín và năng lực cạnh tranh cho sản phẩm địa phương. Thành phố Cần Thơ hiện có 03 chỉ dẫn địa lý, 08 nhãn hiệu chứng nhận và 41 nhãn hiệu tập thể, với nhiều sản phẩm đặc trưng như cá thát lát Hậu Giang, hành tím Vĩnh Châu, khóm Cầu Đúc, gạo ST….</p><p>Tại hội thảo, các chuyên gia trình bày nhiều nội dung thiết thực như giải pháp hỗ trợ bảo hộ, quản lý, phát triển nhãn hiệu và chỉ dẫn địa lý trong bối cảnh chuyển đổi số, cùng ứng dụng công nghệ số và truy xuất nguồn gốc cho sản phẩm nông nghiệp và OCOP.</p><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/a94fff39ce2f16a4.png" width="2568" height="1926"></figure><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/aca0b0cee14a9a2a.png" width="2568" height="1926"></figure><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/ed78842b59f00a1f.png" width="2568" height="1926"></figure><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/2bda0a783c1c6daf.png" width="2568" height="1926"></figure><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/c21854a70095f86b.png" width="2568" height="1926"></figure><p>Các báo cáo viên báo cáo tại Hội thảo.</p><p> </p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/6b816b2324353b57.png" width="2560" height="1920"></figure><p>Toàn cảnh hội thảo</p><figure class="image"><img style="aspect-ratio:2560/1440;" src="/uploads/tin-su-kien/ab70cdacb060db1b.png" width="2560" height="1440"></figure><p>Chụp hình lưu niệm giữa các đại biểu</p><p>Phát biểu bế mạc, ông Phạm Trường Giang khẳng định Sở KH&amp;CN Cần Thơ sẽ tăng cường kết<strong> </strong>nối giữa cơ quan quản lý – doanh nghiệp – hợp tác xã – nông dân, phát huy vai trò của hệ thống sở hữu trí tuệ như công cụ chiến lược để nâng cao giá trị và sức cạnh tranh của sản phẩm Cần Thơ trên thị trường trong nước và quốc tế.</p>', N'Nguyễn Năng Tiến', N'Ngày 31/10/2025, Sở Khoa học và Công nghệ (KH&amp;CN) TP. Cần Thơ tổ chức Hội thảo “Giải pháp hỗ trợ quản lý và phát triển nhãn hiệu tập thể, nhãn hiệu chứng nhận, chỉ dẫn địa lý cho các sản phẩm chủ ', '/uploads/tin-su-kien/211965ea762183d6.jpg', '2025-10-31');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'hoi-thao-khoa-hoc-quoc-gia-phat-trien-khu-kinh-te-ven-bien-tran-de-va-van-de-dat-ra-voi-nguon-nhan-luc', N'HỘI THẢO KHOA HỌC QUỐC GIA:  “PHÁT TRIỂN KHU KINH TẾ VEN BIỂN TRẦN ĐỀ VÀ VẤN ĐỀ ĐẶT RA VỚI NGUỒN NHÂN LỰC”', N'<p>Chiều ngày <strong>24 tháng 10 năm 2025</strong>, <strong>Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ thành phố Cần Thơ</strong>, đã diễn ra <strong>Hội thảo khoa học quốc gia với chủ đề “Phát triển khu kinh tế ven biển Trần Đề và vấn đề đặt ra với nguồn nhân lực”</strong>.<br>Chương trình do <strong>Sở Khoa học và Công nghệ thành phố Cần Thơ</strong> phối hợp với các đơn vị nghiên cứu, trường đại học và doanh nghiệp trong khu vực đồng bằng sông Cửu Long tổ chức.</p><p>Buổi hội thảo diễn ra từ <strong>13h00 đến 17h00</strong>, thu hút sự tham dự của các nhà khoa học, chuyên gia, nhà quản lý cùng đại diện các viện, trường, doanh nghiệp quan tâm đến chiến lược phát triển kinh tế biển và đào tạo nhân lực chất lượng cao phục vụ khu kinh tế ven biển Trần Đề.</p><p>Phát biểu khai mạc, <strong>Lãnh đạo Sở Khoa học và Công nghệ thành phố Cần Thơ</strong> nhấn mạnh tầm quan trọng của việc hình thành và phát triển khu kinh tế ven biển Trần Đề – một trong những dự án động lực thúc đẩy tăng trưởng kinh tế vùng ĐBSCL, gắn liền với yêu cầu cấp bách về <strong>nguồn nhân lực chất lượng cao, ổn định và có năng lực hội nhập</strong>.</p><p>Chủ trì phiên thảo luận là <strong>PGS.TS. Nguyễn Xuân Trung</strong>, cùng sự tham gia của đại diện lãnh đạo Sở KH&amp;CN Cần Thơ. Ba báo cáo tham luận tiêu biểu được trình bày gồm:</p><ol><li><strong>“Triển vọng phát triển Cảng biển Trần Đề và dự báo nhu cầu nhân lực”</strong><br>– do <strong>ThS. Trần Thị Lan Phương</strong>, đại diện <strong>Tổng Công ty Tân cảng Sài Gòn</strong>, trình bày.<br>Báo cáo tập trung vào tầm nhìn chiến lược của cảng biển Trần Đề trong chuỗi logistics khu vực, đồng thời phân tích nhu cầu nhân lực kỹ thuật và quản lý trong giai đoạn hình thành – vận hành cảng.</li><li><strong>“Mô hình đào tạo và hợp tác nhà trường – doanh nghiệp – chính quyền địa phương thúc đẩy phát triển kinh tế biển Trần Đề”</strong><br>– do <strong>nhóm tác giả Phước Minh Hiệp và TS. Nguyễn Thanh Liêm (Trường Đại học Trà Vinh)</strong> trình bày.<br>Tham luận nêu rõ vai trò của mô hình “ba nhà” trong việc gắn kết đào tạo với thực tiễn, nhằm đáp ứng kịp thời nhu cầu nhân lực cho khu kinh tế.</li><li><strong>“Phát triển nguồn nhân lực du lịch chất lượng cao phục vụ đô thị cảng biển Trần Đề: Cơ hội, thách thức và định hướng chính sách”</strong><br>– nhóm tác giả <strong>Nguyễn Ánh Minh, Lê Nguyễn Đoàn Khôi (Đại học Cần Thơ)</strong> trình bày.<br>Báo cáo đề cập giải pháp xây dựng lực lượng lao động du lịch – dịch vụ chuyên nghiệp, góp phần tạo sức hút cho đô thị cảng biển trong tương lai.</li></ol><p>Các chuyên gia tập trung đánh giá hiện trạng phát triển kinh tế biển khu vực Trần Đề, định hướng quy hoạch nguồn nhân lực, cũng như đề xuất <strong>các chính sách hỗ trợ liên kết vùng</strong>, chuyển giao công nghệ, và <strong>ứng dụng khoa học – đổi mới sáng tạo</strong> vào thực tiễn quản lý, khai thác bền vững tài nguyên biển.</p><p>Hội thảo là <strong>diễn đàn quan trọng</strong> để các nhà khoa học, cơ quan quản lý và doanh nghiệp <strong>chia sẻ thông tin, đề xuất giải pháp</strong> nhằm phát triển khu kinh tế ven biển Trần Đề theo hướng <strong>hiện đại, bền vững và hội nhập quốc tế</strong>, đồng thời xác định <strong>nguồn nhân lực là yếu tố then chốt</strong> quyết định thành công của khu kinh tế trong tương lai.</p><figure class="image"><img style="aspect-ratio:2560/1880;" src="/uploads/tin-su-kien/6fa3048741ed4c39.png" width="2560" height="1880"></figure><figure class="image"><img style="aspect-ratio:2568/1926;" src="/uploads/tin-su-kien/b4f55403db428aba.png" width="2568" height="1926"></figure>', N'', N'Chiều ngày 24 tháng 10 năm 2025 , Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ thành phố Cần Thơ , đã diễn ra Hội thảo khoa học quốc gia với chủ đề “Phát triển khu kinh tế ven biển Trần Đề và vấn ', '/uploads/tin-su-kien/dd08f378f72d6cad.jpg', '2025-10-24');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'tap-huan-dang-ky-xac-lap-quyen-so-huu-tri-tue-va-quy-trinh-cong-nhan-quan-ly-sang-kien-tai-can-tho', N'Tập huấn Đăng ký xác lập quyền sở hữu trí tuệ và quy trình công nhận quản lý sáng kiến tại Cần Thơ', N'<p>Ngày 17/10/2025, <strong>Sở Khoa học và Công nghệ thành phố Cần Thơ</strong> phối hợp với <strong>Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ thành phố Cần Thơ</strong> tổ chức <strong>buổi làm việc giới thiệu các dịch vụ Sở hữu trí tuệ (SHTT), Truy xuất nguồn gốc (TXNG) và tư vấn xây dựng thương hiệu riêng cho doanh nghiệp</strong>. Tham dự buổi làm việc có đại diện lãnh đạo Sở, Trung tâm, cùng các doanh nghiệp, hợp tác xã, cơ sở sản xuất – kinh doanh và đơn vị khởi nghiệp trên địa bàn thành phố.</p><p>Buổi làm việc nhằm <strong>tăng cường kết nối giữa cơ quan quản lý nhà nước và doanh nghiệp</strong>, đồng thời <strong>hỗ trợ doanh nghiệp địa phương tiếp cận, ứng dụng các công cụ khoa học – công nghệ trong phát triển thương hiệu, nâng cao năng lực cạnh tranh và minh bạch hóa chuỗi cung ứng</strong>.</p><p>Phát biểu khai mạc, đại diện lãnh đạo <strong>Sở Khoa học và Công nghệ thành phố Cần Thơ</strong> nhấn mạnh: Trong bối cảnh thị trường ngày càng cạnh tranh gay gắt và yêu cầu về truy xuất nguồn gốc ngày càng chặt chẽ, việc <strong>đăng ký bảo hộ quyền SHTT, áp dụng hệ thống TXNG và xây dựng thương hiệu riêng</strong> không chỉ giúp doanh nghiệp khẳng định uy tín, mà còn tạo nền tảng phát triển bền vững, đủ sức tham gia sâu vào thị trường trong và ngoài nước.</p><p>Tại buổi làm việc, <strong>Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ</strong> đã giới thiệu đến các đại biểu <strong>hệ thống truy xuất nguồn gốc điện tử</strong> do Trung tâm phát triển và vận hành. Hệ thống cho phép doanh nghiệp, hợp tác xã gắn <strong>tem điện tử chứa mã QR</strong> cho từng sản phẩm, giúp người tiêu dùng dễ dàng kiểm tra thông tin về nguồn gốc, quy trình sản xuất, chứng nhận chất lượng và tiêu chuẩn an toàn. Song song đó, Trung tâm cũng trình bày <strong>các dịch vụ tư vấn, đăng ký bảo hộ nhãn hiệu, kiểu dáng công nghiệp, sáng chế, chỉ dẫn địa lý</strong>, và <strong>hướng dẫn doanh nghiệp xây dựng chiến lược phát triển thương hiệu riêng gắn với đặc trưng sản phẩm địa phương</strong>.</p><p>Các đại biểu đã cùng nhau <strong>thảo luận, chia sẻ khó khăn và đề xuất giải pháp</strong> trong quá trình đăng ký bảo hộ quyền sở hữu trí tuệ, quản lý thông tin truy xuất nguồn gốc, cũng như chiến lược quảng bá thương hiệu. Nhiều doanh nghiệp bày tỏ mong muốn được <strong>Sở và Trung tâm hỗ trợ trực tiếp trong việc xây dựng hình ảnh nhận diện, phát triển thương hiệu sản phẩm đặc trưng</strong> như nông sản, thủy sản chế biến, thực phẩm, hàng thủ công mỹ nghệ và sản phẩm OCOP.</p><p>Buổi làm việc là <strong>hoạt động thiết thực góp phần lan tỏa tinh thần đổi mới sáng tạo và ứng dụng khoa học – công nghệ trong sản xuất, kinh doanh</strong>, giúp doanh nghiệp địa phương <strong>nâng cao năng lực cạnh tranh, củng cố niềm tin của người tiêu dùng và khẳng định vị thế trên thị trường</strong>.</p><p>Trong thời gian tới, <strong>Sở Khoa học và Công nghệ</strong> cùng <strong>Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ thành phố Cần Thơ</strong> sẽ tiếp tục <strong>triển khai các chương trình hỗ trợ doanh nghiệp về đăng ký bảo hộ SHTT, áp dụng hệ thống TXNG và phát triển thương hiệu riêng</strong>, góp phần xây dựng <strong>hệ sinh thái đổi mới sáng tạo, thúc đẩy phát triển kinh tế địa phương theo hướng xanh, minh bạch và bền vững.</strong></p><p>Sáng ngày <strong>17/10/2025</strong>, <strong>Sở Khoa học và Công nghệ thành phố Cần Thơ</strong> phối hợp với <strong>Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ</strong> tổ chức <strong>tập huấn “Đăng ký xác lập quyền sở hữu trí tuệ và quy trình công nhận, quản lý sáng kiến tại cơ sở”</strong>.</p><p>Chương trình có sự tham dự của <strong>bà Lê Mỹ Hạnh – Phó Giám đốc Sở Khoa học và Công nghệ thành phố Cần Thơ</strong>, đại diện các phòng chuyên môn của Sở, cùng lãnh đạo <strong>phòng Văn hóa – Xã hội phường Vị Thanh</strong>, đại diện các cơ quan, đơn vị, doanh nghiệp, hợp tác xã và cá nhân quan tâm đến lĩnh vực sở hữu trí tuệ trên địa bàn.</p><p>Phát biểu khai mạc, <strong>bà Lê Mỹ Hạnh</strong> nhấn mạnh: Trong bối cảnh hội nhập và đổi mới sáng tạo mạnh mẽ hiện nay, việc <strong>xác lập quyền sở hữu trí tuệ và quản lý sáng kiến khoa học tại cơ sở</strong> có vai trò rất quan trọng, giúp các tổ chức, cá nhân <strong>bảo vệ kết quả nghiên cứu, nâng cao giá trị thương mại của sản phẩm và khuyến khích phong trào sáng tạo trong cộng đồng.</strong></p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/410b694a11c409ab.png" width="2560" height="1920"></figure><p>Tại buổi tập huấn, các báo cáo viên đến từ Sở và Trung tâm đã chia sẻ nhiều nội dung thiết thực, bao gồm:</p><ul><li><strong>Quyền và lợi ích của việc đăng ký bảo hộ tài sản trí tuệ, hướng dẫn thủ tục đăng ký bảo hộ sáng chế, nhãn hiệu, kiểu dáng công nghiệp</strong> (do bà Trần Thị Thanh Điệp – Trưởng phòng Sở hữu trí tuệ, Sở KH&amp;CN trình bày)</li></ul><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/96f4b339b44cdc57.png" width="2560" height="1920"></figure><ul><li><strong>Giới thiệu hệ thống truy xuất nguồn gốc sản phẩm, hàng hóa trên địa bàn thành phố Cần Thơ</strong>, góp phần minh bạch thông tin sản phẩm và nâng cao niềm tin người tiêu dùng (do ông Nghiêm Phong Vũ – Giám đốc Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ trình bày).</li></ul><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/3b7b6507faa97d06.png" width="2560" height="1920"></figure><ul><li><strong>Giải pháp phát triển thương hiệu cho sản phẩm và dịch vụ địa phương</strong>, hướng đến nâng cao năng lực cạnh tranh và giá trị gia tăng (do ông Nguyễn Văn Kha – Chuyên viên Phòng Sở hữu trí tuệ, Sở KH&amp;CN báo cáo).</li><li><strong>Hướng dẫn quy trình, thủ tục công nhận sáng kiến và quản lý sáng kiến tại cơ sở</strong>, giúp các đơn vị triển khai đúng quy định và hiệu quả hơn (do bà Trần Thị Thanh Điệp trình bày).</li></ul><p>Trong phần <strong>thảo luận</strong>, các đại biểu đã trao đổi sôi nổi về những vướng mắc khi thực hiện hồ sơ đăng ký bảo hộ quyền sở hữu trí tuệ, quản lý sáng kiến, cũng như nhu cầu được hỗ trợ tư vấn trong việc xây dựng và phát triển thương hiệu sản phẩm đặc trưng của địa phương.</p><p>Buổi tập huấ<strong>n đã mang lại nhiều kiến thức bổ ích và kinh nghiệm thực tiễn,</strong> góp phần nâng cao năng lực cho cán bộ, doanh nghiệp và tổ chức cơ sở trong công tác quản lý sáng kiến, sở hữu trí tuệ và truy xuất nguồn gốc sản phẩm.</p><p>Hoạt động này nằm tron<strong>g chuỗi chương trình hỗ trợ đổi mới sáng tạo và phát triển tài sản trí tuệ do Sở </strong>Khoa học và Công nghệ thành phố Cần Thơ triển khai, hướng đến mục tiêu xây dựng môi trường sáng tạo, phát triển thương hiệu địa phương và thúc đẩy nền kinh tế tri thức của thành phố.<strong> </strong>Trong thời gian tới, <strong>Sở Khoa học và Công nghệ</strong> cùng <strong>Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ thành phố Cần Thơ</strong> sẽ tiếp tục <strong>triển khai các chương trình hỗ trợ doanh nghiệp về đăng ký bảo hộ SHTT, áp dụng hệ thống TXNG và phát triển thương hiệu riêng</strong>, góp phần xây dựng <strong>hệ sinh thái đổi mới sáng tạo, thúc đẩy phát triển kinh tế địa phương theo hướng xanh, minh bạch và bền vững.</strong></p>', N'', N'Ngày 17/10/2025, Sở Khoa học và Công nghệ thành phố Cần Thơ phối hợp với Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ thành phố Cần Thơ tổ chức buổi làm việc giới thiệu các dịch vụ Sở hữu trí tuệ ', '/uploads/tin-su-kien/24706b6c549ae8de.jpg', '2025-10-17');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'tham-va-tang-qua-trung-thu-cho-cac-be-tai-co-so-bao-tro-xa-hoi-thien-an', N'Thăm và tặng quà Trung thu cho các bé tại Cơ sở Bảo trợ Xã hội Thiên Ân', N'<p>🌕 Chi Đoàn Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ TP. Cần Thơ tổ chức chương trình “Vì Đàn Em Thân Yêu” tại Cơ sở Bảo trợ Xã hội Thiên Ân</p><p>Hưởng ứng chương trình “Vì đàn em thân yêu” do Đoàn cấp trên phát động, Chi Đoàn Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ TP. Cần Thơ đã tổ chức hoạt động ý nghĩa với chủ đề “Thăm và tặng quà Trung thu cho các bé tại Cơ sở Bảo trợ Xã hội Thiên Ân”.</p><p>Trong chương trình, các đoàn viên Chi đoàn đã chuẩn bị những phần bánh Trung thu gửi tặng các em nhỏ, với mong muốn mang đến cho các em một mùa Trung thu đầm ấm, vui tươi và tràn đầy yêu thương. Bên cạnh việc trao quà, đoàn viên còn cùng các em giao lưu, chia sẻ và tạo nên bầu không khí thân mật, gần gũi.</p><p>Hoạt động là dịp để tuổi trẻ Trung tâm thể hiện tinh thần xung kích, tình nguyện vì cộng đồng, lan tỏa yêu thương đến những hoàn cảnh kém may mắn. Chương trình khép lại trong niềm vui và những nụ cười hồn nhiên của các em nhỏ – minh chứng cho ý nghĩa nhân văn sâu sắc của phong trào “Vì đàn em thân yêu”.</p><figure class="image"><img style="aspect-ratio:2560/1440;" src="/uploads/tin-su-kien/d2d8884b8e585a45.png" width="2560" height="1440"></figure>', N'', N'🌕 Chi Đoàn Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ TP. Cần Thơ tổ chức chương trình “Vì Đàn Em Thân Yêu” tại Cơ sở Bảo trợ Xã hội Thiên Ân Hưởng ứng chương trình “Vì đàn em thân yêu” do Đoàn ', '/uploads/tin-su-kien/53c4b3c33c498e1f.jpg', '2025-10-06');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'tu-hao-80-nam-quoc-khanh-2-9-chung-suc-gop-phan-xay-dung-dat-nuoc', N'🌺 TỰ HÀO 80 NĂM QUỐC KHÁNH 2/9 – CHUNG SỨC GÓP PHẦN XÂY DỰNG ĐẤT NƯỚC 🌺', N'<p>Trải qua 80 năm kể từ ngày Bác Hồ đọc bản Tuyên ngôn Độc lập tại Quảng trường Ba Đình lịch sử, tinh thần bất khuất, ý chí kiên cường và khát vọng độc lập – tự do của dân tộc Việt Nam luôn được gìn giữ, phát huy qua nhiều thế hệ.</p><p>Hòa cùng niềm vui chung của cả nước, tập thể Trung tâm Ứng dụng tiến bộ khoa học và công nghệ Cần Thơ bày tỏ niềm tự hào và lòng biết ơn sâu sắc đến các thế hệ đi trước đã hi sinh vì Tổ quốc. Đồng thời, chúng tôi quyết tâm tiếp tục <strong>đẩy mạnh hoạt động nghiên cứu, ứng dụng, chuyển giao công nghệ</strong>, đồng hành cùng doanh nghiệp, nông dân, hợp tác xã trong đổi mới sáng tạo, nâng cao chất lượng sản phẩm, thúc đẩy phát triển kinh tế – xã hội bền vững.</p><p>🇻🇳 Kỷ niệm 80 năm Quốc khánh, mỗi thành viên Trung tâm nguyện phấn đấu không ngừng để góp phần xây dựng một Việt Nam <strong>phồn vinh, hạnh phúc</strong>.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/6d0b5fca8d3912b9.jpg" width="2560" height="1920"></figure><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/72a82c2832d89e92.jpg" width="2560" height="1920"></figure><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/d89ebb7e6e06d973.jpg" width="2560" height="1920"></figure><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/bf30c1a7f3c07524.jpg" width="2560" height="1920"></figure>', N'Kim Anh', N'Trải qua 80 năm kể từ ngày Bác Hồ đọc bản Tuyên ngôn Độc lập tại Quảng trường Ba Đình lịch sử, tinh thần bất khuất, ý chí kiên cường và khát vọng độc lập – tự do của dân tộc Việt Nam luôn được gìn giữ', '/uploads/tin-su-kien/a6c782244a89ace1.jpg', '2025-08-29');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'huong-ung-ky-niem-80-nam-cach-mang-thang-tam-thanh-cong-19-8-1945-19-8-2025', N'Hưởng ứng Kỷ niệm 80 năm Cách mạng Tháng Tám thành công (19/8/1945 – 19/8/2025)', N'<figure class="image"><img style="aspect-ratio:639/365;" src="/uploads/tin-su-kien/5526d2733bc3bfe4.jpg" width="639" height="365"></figure><p>Cách đây tròn 80 năm, dưới sự lãnh đạo sáng suốt của Đảng Cộng sản Việt Nam và Chủ tịch Hồ Chí Minh, dân tộc ta đã làm nên thắng lợi vĩ đại của <strong>Cách mạng Tháng Tám năm 1945</strong>, mở ra một kỷ nguyên mới – kỷ nguyên độc lập dân tộc gắn liền với chủ nghĩa xã hội. Sự kiện trọng đại này đã làm thay đổi vận mệnh đất nước, đưa nhân dân ta từ thân phận nô lệ trở thành người làm chủ, khai sinh Nhà nước công nông đầu tiên ở Đông Nam Á.</p><p>Thắng lợi của Cách mạng Tháng Tám là kết tinh của <strong>ý chí kiên cường, khát vọng độc lập, tự do của toàn dân tộc</strong>, đồng thời khẳng định sự lãnh đạo đúng đắn, sáng tạo của Đảng. Tinh thần bất khuất, khát vọng vươn lên và sức mạnh đoàn kết toàn dân từ mùa Thu lịch sử năm 1945 đến nay vẫn luôn soi sáng con đường xây dựng và phát triển đất nước.</p><p>Hưởng ứng Kỷ niệm <strong>80 năm Cách mạng Tháng Tám thành công (1945 – 2025)</strong>, tập thể cán bộ, viên chức và người lao động Trung tâm Ứng dụng tiến bộ Khoa học và Công nghệ Cần Thơ nguyện tiếp tục phát huy truyền thống cách mạng, kiên định mục tiêu đổi mới sáng tạo, góp phần đưa khoa học và công nghệ trở thành động lực quan trọng trong phát triển kinh tế - xã hội của thành phố và vùng Đồng bằng sông Cửu Long.</p><p>Trung tâm xác định rõ trách nhiệm trong việc <strong>đẩy mạnh nghiên cứu, ứng dụng, chuyển giao các tiến bộ khoa học và công nghệ</strong>, hỗ trợ doanh nghiệp, hợp tác xã và người dân nâng cao năng suất, chất lượng sản phẩm, bảo vệ môi trường, hướng đến phát triển bền vững. Đồng thời, tập thể Trung tâm luôn nỗ lực xây dựng môi trường làm việc đoàn kết, sáng tạo, xứng đáng là một đơn vị sự nghiệp khoa học – công nghệ tiên phong, góp phần hiện thực hóa khát vọng xây dựng đất nước Việt Nam phồn vinh, hạnh phúc.</p><p>Kỷ niệm 80 năm Cách mạng Tháng Tám thành công là dịp để mỗi chúng ta tri ân công lao to lớn của các thế hệ cha anh đã hy sinh vì độc lập, tự do của Tổ quốc; đồng thời là động lực thôi thúc mỗi cán bộ, viên chức Trung tâm quyết tâm cống hiến trí tuệ, sức lực, đoàn kết cùng toàn Đảng, toàn dân và toàn quân xây dựng quê hương Cần Thơ ngày càng văn minh, giàu đẹp, xứng đáng là trung tâm khoa học, công nghệ và đổi mới sáng tạo của vùng Đồng bằng sông Cửu Long.</p><p><strong>Cách mạng Tháng Tám – Mãi mãi là niềm tự hào dân tộc, là động lực cho sự nghiệp xây dựng và bảo vệ Tổ quốc Việt Nam xã hội chủ nghĩa!</strong></p>', N'Kim Anh', N'Cách đây tròn 80 năm, dưới sự lãnh đạo sáng suốt của Đảng Cộng sản Việt Nam và Chủ tịch Hồ Chí Minh, dân tộc ta đã làm nên thắng lợi vĩ đại của Cách mạng Tháng Tám năm 1945 , mở ra một kỷ nguyên mới –', '/uploads/tin-su-kien/0fe06e073035fc68.jpg', '2025-08-19');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'chao-mung-dai-hoi-dai-bieu-dang-bo-uy-ban-nhan-dan-thanh-pho-can-tho-lan-thu-i-nhiem-ky-2025-2030', N'🎉 CHÀO MỪNG ĐẠI HỘI ĐẠI BIỂU ĐẢNG BỘ ỦY BAN NHÂN DÂN THÀNH PHỐ CẦN THƠ LẦN THỨ I, NHIỆM KỲ 2025 – 2030 🎉', N'<p>Trong không khí phấn khởi, đoàn kết và đổi mới, Đại hội đại biểu Đảng bộ Ủy ban nhân dân thành phố Cần Thơ lần thứ I, nhiệm kỳ 2025 – 2030 chính thức diễn ra. Đây là dấu mốc quan trọng, thể hiện tinh thần quyết tâm xây dựng chính quyền thành phố vững mạnh, hiệu lực, hiệu quả; đồng thời khẳng định vai trò lãnh đạo trong phát triển kinh tế – xã hội, giữ vững ổn định chính trị, nâng cao đời sống Nhân dân.<br><br>💡Bên cạnh đó, tại đại hội lần này giới thiệu các sản phẩm khoa học – công nghệ tiêu biểu cùng sản phẩm chất lượng của các doanh nghiệp. Hoạt động này không chỉ tôn vinh những thành tựu nghiên cứu, đổi mới sáng tạo, mà còn tạo cầu nối giữa nhà quản lý – nhà khoa học – doanh nghiệp, góp phần thúc đẩy phát triển kinh tế tri thức và hội nhập quốc tế.<br><br>💪 Với phương châm “Đoàn kết – Dân chủ – Kỷ cương – Sáng tạo – Phát triển”, Đại hội sẽ tổng kết chặng đường đã qua, đề ra mục tiêu, giải pháp chiến lược cho giai đoạn mới, đưa Cần Thơ trở thành trung tâm phát triển của vùng Đồng bằng sông Cửu Long – đô thị văn minh, hiện đại, đậm đà bản sắc.<br><br>✨ Xin chúc Đại hội đại biểu Đảng bộ Ủy ban nhân dân thành phố Cần Thơ lần thứ I, nhiệm kỳ 2025 – 2030 thành công rực rỡ, mở ra một giai đoạn phát triển mới – năng động, bền vững và sáng tạo!</p><p>#CầnThơ #ĐạiHộiĐảngBộUBNDTP #KhoaHọcCôngNghệ #DoanhNghiệpĐồngHành #NhiệmKỳ2025_2030 #ĐoànKếtPhátTriển</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/36437daba1f11c09.jpg" width="2560" height="1920"></figure><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/314f0ca8d728f5c0.jpg" width="2560" height="1920"></figure><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/f4140c06990f8e51.jpg" width="2560" height="1920"></figure><figure class="image"><img style="aspect-ratio:1920/2560;" src="/uploads/tin-su-kien/49ebfdd659e8bf58.jpg" width="1920" height="2560"></figure>', N'Kim Anh', N'Trong không khí phấn khởi, đoàn kết và đổi mới, Đại hội đại biểu Đảng bộ Ủy ban nhân dân thành phố Cần Thơ lần thứ I, nhiệm kỳ 2025 – 2030 chính thức diễn ra. Đây là dấu mốc quan trọng, thể hiện tinh ', '/uploads/tin-su-kien/4b8f96850ec1bc56.jpg', '2025-08-15');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'tham-hoi-tang-qua-cuu-chien-binh-nhan-dip-ky-niem-78-nam-ngay-thuong-binh-liet-si-27-7-1947-27-7-2024', N'Thăm hỏi,  tặng quà cựu chiến binh  nhân dịp kỷ niệm 78 năm Ngày Thương Binh – Liệt sĩ (27/7/1947 – 27/7/2024)', N'<p>🎗 <strong>Chi đoàn Trung tâm Ứng dụng Tiến bộ KH&amp;CN Cần Thơ tổ chức thăm hỏi cựu chiến binh nhân kỷ niệm 27/7</strong> 🎗</p><p>Nhân dịp kỷ niệm 78 năm Ngày Thương binh – Liệt sĩ (27/7/1947 – 27/7/2025), sáng ngày 25/7, Chi đoàn Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ Cần Thơ đã tổ chức hoạt động thăm hỏi và tặng quà cho cựu chiến binh Nguyễn Văn An tại phường Ninh Kiều, TP. Cần Thơ.</p><p>Chương trình là dịp để tuổi trẻ Trung tâm thể hiện lòng biết ơn sâu sắc đến những người đã hy sinh, cống hiến vì nền độc lập dân tộc, qua đó lan tỏa truyền thống “Uống nước nhớ nguồn”, “Đền ơn đáp nghĩa” đến từng đoàn viên, thanh niên.</p><p>Tham gia chương trình có các đoàn viên thanh niên, cán bộ viên chức của Trung tâm. Tại buổi gặp mặt, đoàn đã ân cần thăm hỏi sức khỏe, đời sống và gửi tặng phần quà.</p><p>Hoạt động không chỉ góp phần tri ân các thế hệ đi trước mà còn là dịp giáo dục tư tưởng chính trị, khơi dậy trách nhiệm cộng đồng trong đoàn viên, thanh niên – những người đang tiếp nối truyền thống và dựng xây quê hương bằng sức trẻ và trí tuệ.</p>', N'Nguyễn Năng Tiến', N'🎗 Chi đoàn Trung tâm Ứng dụng Tiến bộ KH&amp;CN Cần Thơ tổ chức thăm hỏi cựu chiến binh nhân kỷ niệm 27/7 🎗 Nhân dịp kỷ niệm 78 năm Ngày Thương binh – Liệt sĩ (27/7/1947 – 27/7/2025), sáng ngày 25/7, ', '/uploads/tin-su-kien/76be55ec934e9a11.jpg', '2025-07-25');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'trung-tam-ung-dung-tien-bo-khoa-hoc-va-cong-nghe-casta-lam-viec-voi-cong-ty-pharos-marine-inc-han-quoc-phat-trien-mo-hinh-thu-nghiem-giao-thong-thuy-than-thien-moi-truong-tai-khu-v', N'Trung tâm Ứng dụng tiến bộ khoa học và công nghệ (CASTA) làm việc với Công ty PHAROS MARINE. INC. (Hàn Quốc): Phát triển mô hình thử nghiệm  giao thông thủy thân thiện môi trường tại khu vực ĐBSCL', N'<p>Ngày 19/4/2025 vừa qua, Trung tâm Ứng dụng tiến bộ khoa học và công nghệ đã có buổi làm việc với Công ty PHAROS MARINE. INC., doanh nghiệp startup công nghệ đến từ Hàn Quốc chuyên nghiên cứu và cung cấp các giải pháp truyền động điện ứng dụng cho tàu thuyền thân thiện với môi trường. Cuộc gặp là bước khởi đầu quan trọng trong tiến trình hợp tác giữa CASTA và Công ty PHAROS MARINE. INC thực hiện Dự án Phát triển mô hình thử nghiệm giao thông thủy thân thiện môi trường tại khu vực Đồng bằng sông Cửu Long.</p><p>Tham dự buổi làm việc, về phía <strong>Công ty PHAROS MARINE. INC. </strong>có Ông Lee Seulkie - CEO Công ty PHAROS MARINE INC, Bà An KyungJo - Trưởng phòng Kinh doanh Công ty PHAROS MARINE. INC, Ông Lee Sunjae - Nhà Nghiên cứu Công ty PHAROS MARINE INC và Ông Lee Jong Hyuk - CEO Công ty SINASEAN VIỆT NAM SINASEAN KOREA. </p><figure class="image"><img src="/uploads/tin-su-kien/4ca41039a12a8202.jpg"><figcaption>Đoàn làm việc phía <strong>Công ty PHAROS MARINE. INC. (Hàn Quốc)</strong> </figcaption></figure><p>Về phía <strong>Trung tâm Ứng dụng tiến bộ khoa học và công nghệ</strong>, buổi làm việc có sự tham dự của Ông Nghiêm Phong Vũ - Giám đốc Trung tâm, Bà Đoàn Thị Hồng Quyên - Phó Giám đốc Trung tâm, cùng đại diện các phòng chuyên môn như Ông Trần Thế Duy - Phụ trách Phòng Khoa học - Hợp tác quốc tế, Ông Nguyễn Thành Đon - Kỹ sư Phòng thí nghiệm Cơ khí - Tự động hóa - Vật liệu mới, Bà Mai Trương Ngọc Ngân - Chuyên viên Phòng Khoa học - Hợp tác quốc tế.</p><figure class="image"><img style="aspect-ratio:3936/2624;" src="/uploads/tin-su-kien/5d1f3ca9fe1aa64e.jpg" width="3936" height="2624"><figcaption>Đoàn làm việc phía <strong>Trung tâm Ứng dụng tiến bộ khoa học và công nghệ</strong></figcaption></figure><p><strong> </strong>Tại buổi làm việc, hai bên đã thảo luận sâu về công tác phối hợp triển khai dự án, bao gồm các nội dung chuyển giao mô hình ứng dụng, hợp tác kỹ thuật, đào tạo, phát triển sản phẩm công nghệ xanh trên diện rộng. Theo dự kiến, dự án sẽ được thực hiện theo ba giai đoạn chính. <strong>Giai đoạn đầu tiên</strong> là chương trình thí điểm, trong đó PHAROS MARINE. INC. sẽ chuyển giao 100 bộ truyền động điện nhằm thay thế động cơ xăng dầu cho các phương tiện thủy nhỏ tại thành phố Cần Thơ. <strong>Giai đoạn hai</strong> tập trung vào việc xây dựng và lắp đặt các trạm sạc điện, phục vụ cho hệ thống truyền động hiện có. <strong>Giai đoạn ba</strong> hướng đến mở rộng quy mô ứng dụng, bao gồm cả việc áp dụng công nghệ này cho tàu thuyền có tải trọng lớn hơn và mở rộng địa bàn triển khai ra các tỉnh thành khác.</p><p>Trong quá trình trao đổi, Công ty PHAROS MARINE. INC. đánh giá cao vị trí của CASTA trong ứng dụng khoa học, phát triển và chuyển giao công nghệ và bày tỏ sự quan tâm đặc biệt đến tiềm năng hợp tác với CASTA trong chuyển giao công nghệ xanh tại Việt Nam, đặc biệt là khu vực Đồng bằng sông Cửu Long – nơi đang chịu nhiều tác động của biến đổi khí hậu và cần giải pháp giao thông bền vững. Trước mắt, Công ty đề xuất CASTA đóng vai trò đơn vị tiếp nhận, quản lý và phân phối 100 bộ truyền động điện đến các đối tượng thụ hưởng; đồng thời tư vấn, lựa chọn các vị trí phù hợp để lắp đặt trạm sạc điện, hỗ trợ Công ty khảo sát, tìm hiểu vị trí lắp đặt,…</p><p>Về phần mình, Trung tâm Ứng dụng tiến bộ khoa học và công nghệ hoan nghênh Công ty PHAROS MARINE. INC có kế hoạch phát triển và ứng dụng công nghệ xanh tại thành phố Cần Thơ, nhấn mạnh tinh thần chủ động, cầu thị và sẵn sàng phối hợp, hỗ trợ doanh nghiệp trong và ngoài nước ứng dụng, chuyển giao các giải pháp công nghệ tiên tiến vào thực tiễn, đặc biệt là các công công nghệ xanh, thân thiện với môi trường. </p><p>Đặc biệt, Trung tâm bày tỏ sự sẵn sàng hỗ trợ quảng bá sản phẩm công nghệ xanh của Công ty tại Sàn giao dịch công nghệ, cũng như triển khai các hoạt động chuyển giao, thử nghiệm và ứng dụng sản phẩm vào thực tiễn. Trên cơ sở đó, Trung tâm đề xuất hai hình thức hợp tác chính: (1) Trung tâm là đơn vị tiếp nhận và xây dựng kế hoạch thực hiện chuyển giao cho các đối tượng thụ hưởng, hoặc (2) Trung tâm trở thành đối tác chính thức của Công ty thực hiện các hoạt động quảng bá, giới thiệu, tuyên truyền, giới thiệu về bộ hệ thống truyền động điện dành cho các phương tiện giao thông thủy; quản lý thiết bị; tư vấn lắp đặt các trạm sạc điện,….trên cơ sở đôi bên cùng có lợi</p><p>Buổi làm việc kết thúc trong không khí vui vẻ và mở ra nhiều triển vọng tích cực cho việc thúc đẩy giao thông thủy sạch – xanh – thân thiện môi trường, phù hợp với xu hướng phát triển bền vững của khu vực Đồng bằng sông Cửu Long.</p><p>Với năng lực sẵn có về nhân lực, thiết bị, cơ sở hạ tầng và sự quyết tâm đổi mới, Trung tâm Ứng dụng tiến bộ khoa học và công nghệ tin tưởng sẽ trở thành đối tác khoa học kỹ thuật đầu mối đồng hành cùng Công ty PHAROS MARINE. INC. để đưa những tiến bộ công nghệ tiên tiến vào thực tiễn cuộc sống, nâng cao chất lượng sống cho cộng đồng, góp phần hiện thực hóa mục tiêu "xanh hóa giao thông" tại Việt Nam.</p><figure class="image"><img style="aspect-ratio:1280/854;" src="/uploads/tin-su-kien/d341fafe83e664ca.jpg" width="1280" height="854"><figcaption>Toàn cảnh buổi làm việc</figcaption></figure><p>Thông tin liên hệ hợp tác:</p><p>Trung tâm Ứng dụng tiến bộ khoa học và công nghệ </p><p>[Địa chỉ: 166 Nguyễn Văn Cừ, Phường An Bình, Quận Ninh Kiều, Thành phố Cần Thơ | trungtamungdung@cantho.gov.vn | 0292 3907 037 | https://ttud.com.vn/]</p>', N'Kim Anh', N'Ngày 19/4/2025 vừa qua, Trung tâm Ứng dụng tiến bộ khoa học và công nghệ đã có buổi làm việc với Công ty PHAROS MARINE. INC., doanh nghiệp startup công nghệ đến từ Hàn Quốc chuyên nghiên cứu và cung c', '/uploads/tin-su-kien/1afce51d3b90c4f4.jpg', '2025-06-21');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'hoi-thao-khoa-hoc-ung-dung-cong-nghe-nang-cao-chat-luong-va-kha-nang-canh-tranh-cua-san-pham-dac-thu-dia-phuong-thuc-day-doi-moi-sang-tao-dua-cong-nghe-den-gan-hon-voi-nguoi-nong-d', N'Hội thảo khoa học “Ứng dụng công nghệ nâng cao chất lượng và khả năng cạnh tranh của sản phẩm đặc thù địa phương” Thúc đẩy đổi mới sáng tạo, đưa công nghệ đến gần hơn với người nông dân', N'<p><i>Cần Thơ, ngày 17/6/2025</i> – Trước yêu cầu ngày càng cao của thị trường và bối cảnh hội nhập kinh tế sâu rộng, việc ứng dụng khoa học công nghệ trong sản xuất nông nghiệp và phát triển sản phẩm đặc thù địa phương không chỉ là xu thế mà đã trở thành yêu cầu tất yếu để nâng cao chất lượng, giá trị gia tăng và năng lực cạnh tranh. Nhằm thúc đẩy quá trình này, Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ Cần Thơ đã tổ chức hội thảo khoa học với chủ đề: <strong>“Ứng dụng công nghệ nâng cao chất lượng và khả năng cạnh tranh của sản phẩm đặc thù địa phương”</strong>, thu hút sự quan tâm và tham dự của hơn 100 đại biểu đến từ các tỉnh, thành khu vực Đồng bằng sông Cửu Long.</p><p>Hội thảo được tổ chức tại trụ sở Trung tâm (số 166 Nguyễn Văn Cừ, quận Ninh Kiều, TP. Cần Thơ), với sự tham dự của các chuyên gia, nhà khoa học, doanh nghiệp, cơ quan quản lý, hợp tác xã và nông dân sản xuất. Đây là dịp để các bên chia sẻ kinh nghiệm, cập nhật các giải pháp công nghệ mới và thảo luận về việc đưa công nghệ vào thực tiễn sản xuất – chế biến – phân phối sản phẩm đặc thù.</p><p><strong>Công nghệ – Chìa khóa nâng cao giá trị nông sản</strong></p><p>Ba tham luận chính tại hội thảo đã làm nổi bật vai trò then chốt của công nghệ trong chuỗi giá trị sản phẩm đặc thù.</p><p>PGS.TS. Nguyễn Duy Đạt (Trường Đại học Thương mại) nhấn mạnh vai trò của chuyển đổi số trong chiến lược thương mại hóa sản phẩm, từ xây dựng thương hiệu đến kênh phân phối. Ông cho rằng, trong thời đại số, sản phẩm đặc thù không chỉ cần “ngon” mà còn cần “thông minh” – thể hiện qua truy xuất nguồn gốc, bao bì hiện đại và khả năng tiếp cận thị trường số.</p><figure class="image"><img style="aspect-ratio:1920/2560;" src="/uploads/tin-su-kien/d18848dbd6bc3a63.jpg" width="1920" height="2560"><figcaption><strong>PGS.TS. Nguyễn Duy Đạt</strong></figcaption></figure><p>ThS. Nguyễn Thanh Việt (Đại học Nguyễn Tất Thành) trình bày ứng dụng công nghệ <strong>sấy thăng hoa</strong> trong chế biến trái cây đặc sản miền Tây, giúp giữ nguyên hương vị, màu sắc, dinh dưỡng và kéo dài thời hạn sử dụng – từ đó tăng giá trị và mở rộng khả năng xuất khẩu.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/158a8f99051ca0b1.jpg" width="2560" height="1920"><figcaption><strong>ThS. Nguyễn Thanh Việt</strong></figcaption></figure><p>Ông Trần Quốc Toàn (Công ty Orgen, thương hiệu SASAKI) giới thiệu hệ thống <strong>sấy lạnh thông minh tích hợp AI</strong>, đã được ứng dụng hiệu quả trên nhiều loại nông sản như xoài, sầu riêng, chuối… với ưu điểm tiêu thụ điện năng thấp, bảo toàn dưỡng chất và dễ vận hành cho quy mô vừa và nhỏ.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/a9d7b8da3edca946.jpg" width="2560" height="1920"><figcaption><strong>Ông Trần Quốc Toàn</strong></figcaption></figure><p><strong>Ghi nhận khó khăn thực tiễn của người nông dân</strong></p><p>Phần thảo luận đã thu hút nhiều ý kiến chia sẻ từ người dân và đại diện các hợp tác xã. Hầu hết đều cho rằng việc ứng dụng công nghệ còn gặp nhiều rào cản như chi phí cao, quy mô sản xuất nhỏ lẻ, thiếu mô hình mẫu và đặc biệt là hạn chế trong tiếp cận thông tin và kỹ thuật.</p><p>Nhiều người nông dân hiện đang phải “kiêm nhiệm” nhiều vai trò: vừa sản xuất, vừa lo tiêu thụ, vừa mong muốn cải tiến công nghệ nhưng lại thiếu kiến thức chuyên môn và nguồn lực đầu tư. Trong khi đó, công nghệ từ các viện, trường dù nhiều, nhưng chưa thực sự đến được với người cần.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/e8c615e82bada310.jpg" width="2560" height="1920"><figcaption><strong>Các diễn giả trao đổi và thảo luận</strong></figcaption></figure><p><strong>Trung tâm Ứng dụng KH&amp;CN Cần Thơ cam kết đồng hành</strong></p><p>Phát biểu tại hội thảo, <strong>ông Nghiêm Phong Vũ – Giám đốc Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ Cần Thơ</strong> – đã thẳng thắn nhìn nhận những hạn chế hiện nay trong công tác nghiên cứu và chuyển giao công nghệ. Ông cho rằng <strong>một trong những thiếu sót lớn là chưa đưa được các quy trình công nghệ tiên tiến nhưng chi phí thấp, dễ áp dụng đến tận tay người sản xuất</strong>.</p><p>Ông Vũ ghi nhận sâu sắc <strong>những trăn trở thực tế của người dân</strong>, khi họ vừa phải đảm đương sản xuất, vừa phải tìm đầu ra cho sản phẩm, trong khi mong muốn ứng dụng công nghệ lại vấp phải rào cản về kiến thức, chi phí và thiếu sự hỗ trợ thường xuyên. Ông nhấn mạnh rằng, các viện nghiên cứu, trường đại học và trung tâm công nghệ cần đổi mới cách làm, <strong>đồng hành sát thực tiễn và “nói ngôn ngữ của nông dân”</strong> nhiều hơn để công nghệ thực sự trở thành công cụ phục vụ sản xuất.</p><p>Đáng chú ý, <strong>ông Vũ cũng đề nghị người dân cần chủ động hơn trong việc “đặt hàng” công nghệ</strong>, bởi họ chính là những người hiểu rõ nhất nhu cầu thực tế của sản xuất. “Nhiều nhà khoa học làm việc trong phòng thí nghiệm, thiếu va chạm thực tiễn nên không nắm được nhu cầu cụ thể của bà con. Kết quả là không ít công trình nghiên cứu dù công phu nhưng lại không sử dụng được rộng rãi,” ông nói.</p><p><strong>"Hiện Trung tâm đang tiếp nhận và lưu trữ rất nhiều quy trình ứng dụng công nghệ trong sản xuất nông nghiệp, thủy hải sản từ các viện, trường. Toàn bộ thông tin được cập nhật trên website của Trung tâm. Trung tâm luôn sẵn sàng tư vấn, hỗ trợ và chuyển giao miễn phí hoặc với chi phí hợp lý cho bà con nông dân có nhu cầu"</strong> ông Vũ khẳng định.</p><figure class="image"><img style="aspect-ratio:1920/2560;" src="/uploads/tin-su-kien/b075068e9d32167c.jpg" width="1920" height="2560"><figcaption><strong>Ông Nghiêm Phong Vũ - Giám đốc Trung tâm Ứng dụng tiến bộ khoa học và công nghệ</strong></figcaption></figure><p><strong>Thúc đẩy hợp tác, rút ngắn khoảng cách nghiên cứu – thực tiễn</strong></p><p>Hội thảo lần này không chỉ là nơi chia sẻ kiến thức, mà còn là <strong>cầu nối giữa nhà nghiên cứu, nhà quản lý và người sản xuất</strong>, nhằm rút ngắn khoảng cách giữa khoa học và thực tiễn, mở rộng cơ hội chuyển giao công nghệ thiết thực, phù hợp điều kiện sản xuất của từng địa phương.</p><p>Trong bối cảnh biến đổi khí hậu, biến động thị trường và yêu cầu ngày càng cao từ người tiêu dùng, <strong>việc ứng dụng công nghệ không còn là sự lựa chọn, mà là con đường tất yếu để sản phẩm nông nghiệp đặc thù phát triển bền vững và vươn ra thị trường lớn</strong>.</p><p>Hội thảo kết thúc với nhiều kỳ vọng, rằng sự đồng hành chặt chẽ giữa các bên – đặc biệt là từ các trung tâm ứng dụng công nghệ – sẽ mở ra những hướng đi mới, giúp nông dân vững tin đổi mới và chủ động tiếp cận khoa học công nghệ trong thời đại số.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/3b691ca86ef64e32.jpg" width="2560" height="1920"><figcaption><strong>Toàn cảnh Hội thảo</strong></figcaption></figure>', N'Kim Anh', N'Cần Thơ, ngày 17/6/2025 – Trước yêu cầu ngày càng cao của thị trường và bối cảnh hội nhập kinh tế sâu rộng, việc ứng dụng khoa học công nghệ trong sản xuất nông nghiệp và phát triển sản phẩm đặc thù đ', '/uploads/tin-su-kien/7dff31477f7bc417.jpg', '2025-06-17');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'su-kien-trien-lam-sang-tao-khoa-hoc-cong-nghe-sinh-vien', N'Sự kiện: “Triển lãm sáng tạo khoa học - công nghệ sinh viên”', N'<p>Kỷ niệm 50 năm ngày thống nhất đất nước (30/4/1975 - 30/4/2025), hướng tới chào mừng Ngày Khoa học và Công nghệ Việt Nam (18/5), Trung tâm Ứng dụng tiến bộ khoa học và công nghệ chủ trì tổ chức Sự kiện: <strong>“Triển lãm sáng tạo khoa học - công nghệ sinh viên”</strong>.</p><p><strong>Thời gian:</strong> vào <strong>ngày 16 - 17/5/2025</strong></p><p><strong>Địa điểm:</strong> Sàn giao dịch công nghệ - Trung tâm Ứng dụng tiến bộ KH&amp;CN (Số 166 Nguyễn Văn Cừ, An Bình, Ninh Kiều, Cần Thơ)</p><p>Mục đích của Sự kiện là mang lại cho các sinh viên đam mê nghiên cứu một “sân chơi” trình diễn, trình bày các ý tưởng sáng tạo trong khoa học, công nghệ; trưng bày, tôn vinh các sản phẩm nghiên cứu khoa học đạt chất lượng xuất sắc của sinh viên, nhóm sinh viên, cán bộ giảng viên từ đó khích lệ sinh viên phát huy tiềm năng của mình trong lĩnh vực nghiên cứu khoa học; lan tỏa tình yêu khoa học tới cộng đồng, phát triển những ý tưởng sáng tạo, nuôi dưỡng khát vọng cống hiến tri thức, sức trẻ phục vụ cộng đồng. Sự kiện cũng sẽ tạo cơ hội gặp gỡ, hợp tác giữa các nhà khoa học trẻ, doanh nghiệp, chính quyền địa phương và nhà đầu tư, thúc đẩy chuyển giao công nghệ và thương mại hóa sản phẩm.</p><p>Với <strong>quy mô trên 2000 m²</strong>, sự kiện quy tụ <strong>hơn 55 gian hàng</strong> đến từ các trường đại học, viện nghiên cứu, tổ chức KH&amp;CN và các doanh nghiệp. Các hoạt động chính bao gồm:</p><p>🔹 <strong>Trưng bày và giới thiệu sản phẩm KH&amp;CN</strong>: Nơi hội tụ những ý tưởng sáng tạo, mô hình công nghệ mới, sản phẩm ứng dụng thực tế thuộc các lĩnh vực: cơ khí – tự động hóa, công nghệ sinh học, môi trường, CNTT, nông nghiệp công nghệ cao,…</p><p>🔹 <strong>Gặp gỡ các chuyên gia</strong>: Diễn ra xuyên suốt triển lãm với sự tham gia của các chuyên gia, nhà khoa học và đại diện doanh nghiệp, nhằm chia sẻ góc nhìn thực tiễn và giải pháp phát triển nghiên cứu trong sinh viên.</p><p>🔹 <strong>Quảng bá – Livestream giới thiệu sản phẩm</strong>: Lần đầu tiên, triển lãm áp dụng mô hình livestream trực tiếp để quảng bá và thương mại hóa sản phẩm ngay tại sự kiện, giúp sinh viên tiếp cận thị trường và người tiêu dùng một cách hiệu quả.</p><p>Đây là cơ hội hiếm có để khám phá và trải nghiệm thế giới khoa học công nghệ sinh viên đầy sáng tạo, năng động và thực tiễn. Đừng bỏ lỡ – hãy đến và lan tỏa tinh thần đổi mới sáng tạo cùng chúng tôi!</p><figure class="image"><img style="aspect-ratio:1108/488;" src="/uploads/tin-su-kien/b4f35313f51992f9.jpg" width="1108" height="488"></figure>', N'', N'Kỷ niệm 50 năm ngày thống nhất đất nước (30/4/1975 - 30/4/2025), hướng tới chào mừng Ngày Khoa học và Công nghệ Việt Nam (18/5), Trung tâm Ứng dụng tiến bộ khoa học và công nghệ chủ trì tổ chức Sự kiệ', '/uploads/tin-su-kien/22ef15618458fae5.jpg', '2025-06-17');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'buoi-lam-viec-giua-trung-tam-ung-dung-tien-bo-khoa-hoc-va-cong-nghe-tp-can-tho-va-vien-cong-nghe-tien-tien-doanh-nghiep-anh-duong', N'Buổi Làm Việc Giữa Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ TP. Cần Thơ và Viện Công nghệ Tiên tiến - Doanh nghiệp Ánh Dương', N'<p>Vào sáng ngày 02 tháng 6 năm 2025, tại phòng họp Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ TP. Cần Thơ (số 166 Nguyễn Văn Cừ, quận Ninh Kiều), đã diễn ra buổi làm việc giữa Trung tâm và đoàn công tác đến từ Viện Công nghệ Tiên tiến và Doanh nghiệp Ánh Dương. Buổi gặp mặt nhằm trao đổi, thảo luận về khả năng hợp tác trong các lĩnh vực đào tạo, nghiên cứu và chuyển giao công nghệ.</p><p>Về phía Trung tâm, buổi làm việc có sự tham dự của bà Đoàn Thị Hồng Quyên – Phó Giám đốc Trung tâm (chủ trì), cùng các cán bộ phụ trách lĩnh vực khoa học và công nghệ sinh học. Đại diện Viện Công nghệ Tiên tiến và Doanh nghiệp Ánh Dương đã giới thiệu về đơn vị, lĩnh vực hoạt động, các công nghệ và sản phẩm sẵn sàng chuyển giao, đặc biệt nhấn mạnh đến công nghệ PDMRV – một giải pháp ứng dụng trong quản lý thông tin cây xanh đô thị đang được đăng ký bảo hộ sở hữu trí tuệ.</p><p>Hai bên đã trao đổi tích cực về các nội dung hợp tác tiềm năng, bao gồm: đào tạo nguồn nhân lực trình độ cao, chuyển giao công nghệ trong các lĩnh vực như vật liệu mới, hóa sinh dược, sinh thái môi trường, và đa dạng sinh học; liên kết thực hiện đề tài nghiên cứu ứng dụng, trong đó có thử nghiệm đối với giống cây đậu dầu.</p><p>Ngoài ra, đại diện Trung tâm đã hướng dẫn đoàn tham quan cơ sở vật chất, các phòng thí nghiệm, nhà xưởng và sàn giao dịch công nghệ, tạo điều kiện để đối tác có cái nhìn trực quan về năng lực và tiềm lực triển khai tại địa phương.</p><p>Buổi làm việc kết thúc trong tinh thần hợp tác cởi mở và xây dựng. Trung tâm Ứng dụng sẽ báo cáo lãnh đạo để đề xuất các định hướng hợp tác cụ thể. Viện Công nghệ Tiên tiến và Doanh nghiệp Ánh Dương bày tỏ mong muốn thiết lập mối quan hệ hợp tác lâu dài, cùng hướng đến mục tiêu phát triển bền vững và nâng cao hiệu quả ứng dụng khoa học công nghệ vào thực tiễn.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/a3ec69f4ec4766f7.jpg" width="2560" height="1920"><figcaption>Đoàn đi tham quan cơ sở vật chất tại Trung tâm</figcaption></figure>', N'Kim Anh', N'Vào sáng ngày 02 tháng 6 năm 2025, tại phòng họp Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ TP. Cần Thơ (số 166 Nguyễn Văn Cừ, quận Ninh Kiều), đã diễn ra buổi làm việc giữa Trung tâm và đoàn cô', '/uploads/tin-su-kien/5efb0a295f849bc3.jpg', '2025-06-02');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'tap-huan-huong-dan-truy-xuat-nguon-goc-hang-hoa-san-pham-nang-cao-nang-luc-doanh-nghiep-trong-thoi-ky-hoi-nhap', N'Tập huấn hướng dẫn truy xuất nguồn gốc hàng hóa sản phẩm: nâng cao năng lực doanh nghiệp trong thời kỳ hội nhập', N'<p>Nhằm hỗ trợ các doanh nghiệp nâng cao năng lực quản lý chất lượng và đáp ứng yêu cầu của thị trường trong và ngoài nước, sáng ngày 27/5/2025,Trung tâm Ứng dụng tiến bộ khoa học và công nghệ đã tổ chức buổi <strong>Tập huấn hướng dẫn thực hiện truy xuất nguồn gốc hàng hóa, sản phẩm</strong> cho các đơn vị doanh nghiệp, hợp tác xã và cơ sở sản xuất trên địa bàn.</p><p>Buổi tập huấn thu hút sự tham gia của hơn 20 đại diện doanh nghiệp hoạt động trong các lĩnh vực nông nghiệp, thực phẩm, thủy sản, công nghiệp chế biến... với sự chia sẻ và hướng dẫn trực tiếp từ các chuyên gia.</p><p>Nội dung tập huấn tập trung vào các vấn đề cốt lõi như:</p><ul><li><strong>Tổng quan về truy xuất nguồn gốc</strong>: Khái niệm, vai trò và ý nghĩa trong bảo đảm chất lượng, an toàn thực phẩm và nâng cao uy tín sản phẩm.</li><li><strong>Hướng dẫn xây dựng hệ thống truy xuất nguồn gốc</strong>: Các bước thiết lập, từ vận hành hệ thống, nhật ký sản xuất, thu hoạch, chế biến đến phân phối.</li><li><strong>Ứng dụng công nghệ số trong truy xuất nguồn gốc</strong>: Giới thiệu các phần mềm, nền tảng điện tử hỗ trợ doanh nghiệp số hóa quy trình quản lý và minh bạch thông tin sản phẩm.</li><li><strong>Thực hành và giải đáp thắc mắc</strong>: Các doanh nghiệp được hướng dẫn trực tiếp cách tạo và quản lý mã QR, kết nối dữ liệu sản phẩm và xử lý các tình huống thực tế.</li></ul><p>Phát biểu tại buổi tập huấn, đại diện Ban tổ chức nhấn mạnh:</p><p>“Truy xuất nguồn gốc không chỉ là công cụ kiểm soát chất lượng mà còn là điều kiện bắt buộc để hàng hóa Việt Nam tiếp cận các thị trường khó tính như EU, Hoa Kỳ, Nhật Bản. Việc các doanh nghiệp chủ động triển khai hệ thống truy xuất sẽ góp phần nâng cao sức cạnh tranh, xây dựng thương hiệu uy tín và phát triển bền vững.</p><figure class="image"><img style="aspect-ratio:2560/1920;" src="/uploads/tin-su-kien/2aaa7a48f80ee982.png" width="2560" height="1920"></figure><p>Kết thúc buổi tập huấn, nhiều đại diện doanh nghiệp đánh giá cao tính thiết thực và tính ứng dụng cao của chương trình. Nhiều đơn vị bày tỏ mong muốn được tiếp tục đồng hành cùng các cơ quan quản lý và chuyên gia để triển khai hiệu quả hệ thống truy xuất nguồn gốc trong thời gian tới.</p><figure class="image"><img style="aspect-ratio:2048/1536;" src="/uploads/tin-su-kien/db66a3a8c5189bfe.png" width="2048" height="1536"></figure>', N'Kim Anh', N'Nhằm hỗ trợ các doanh nghiệp nâng cao năng lực quản lý chất lượng và đáp ứng yêu cầu của thị trường trong và ngoài nước, sáng ngày 27/5/2025,Trung tâm Ứng dụng tiến bộ khoa học và công nghệ đã tổ chức', '/uploads/tin-su-kien/c7b4bd7638af1de9.jpg', '2025-05-27');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'trung-tam-chung-nhan-halal-quoc-gia-trao-chung-nhan-halal-cho-npd-viet-nam', N'Trung tâm Chứng nhận Halal Quốc gia trao chứng nhận Halal cho NPD Việt Nam', N'<figure class="image"><img src="/uploads/tin-su-kien/8ff3f5c859bc3533.jpg" alt="" width="600"><figcaption><i>Ông Ramlan - Giám đốc Halcert trao chứng nhận Halal cho 6 sản phẩm thuần tự nhiên của công ty.</i></figcaption></figure><p>Tại sự kiện, ông Ramlan - Giám đốc Halcert chúc mừng Công ty cổ phần NPD Việt Nam nhận được chứng nhận Halal cho 6 sản phẩm thuần tự nhiên của công ty. Ông cho biết đây là dấu mốc quan trọng cho chiến lược kinh doanh của công ty tiến xa hơn ra thế giới, nâng cao vị thế chất lượng sản phẩm của Việt Nam.</p><p>Bà Trần Thị Luyến - Tổng Giám đốc NDP Việt Nam cho biết, là doanh nghiệp kinh doanh trong lĩnh vực gia vị thực dưỡng, NDP Việt Nam không chỉ dừng lại ở thị trường nội địa mà mong muốn ghi dấu ấn trên bản đồ gia vị toàn cầu. Việc được cấp giấy chứng nhận Halal đã chứng minh con đường đi của NPD Việt Nam là hoàn toàn đúng đắn.</p><p>"Đặc biệt, phương châm ăn tinh - uống tỉnh - sống tình hướng đến chăm sóc sức khoẻ toàn diện, đưa giá trị thảo mộc thuần tự nhiên về đúng với trị giá của mình", bà chia sẻ.</p><p>Theo Tổ chức Hợp tác Hồi giáo (OIC), người Hồi giáo đã chi 2.000 tỷ USD cho việc mua sắm thực phẩm, quần áo, du lịch, dược phẩm và phong cách sống trong năm 2023. Dự kiến vào năm 2025, chi tiêu của người Hồi giáo sẽ đạt 2.800 tỷ USD, riêng thị trường thực phẩm Halal Đông Nam Á ước đạt 230 tỷ USD.</p><p>Được biết, Việt Nam có nhiều điều kiện thuận lợi để phát triển ngành Halal do vị trí địa lý thuận lợi, có thế mạnh trong phát triển các lĩnh vực nông nghiệp, thực phẩm, du lịch, đặc biệt là đã tham gia ký kết các hiệp định thương mại tự do thế hệ mới... Do đó, cơ hội cho doanh nghiệp Việt Nam khi tham gia vào thị trường Halal toàn cầu là rất lớn.</p><p>Việt Nam đã có nhiều doanh nghiệp được cấp chứng nhận Halal và cung cấp sản phẩm sang các nước hồi giáo. Tuy nhiên, việc xuất khẩu sản phẩm Halal của Việt Nam còn rất khiêm tốn so với tiềm năng và lợi thế.</p><p><em>Nguồn: <a href="https://vietq.vn/trung-tam-chung-nhan-halal-quoc-gia-trao-chung-nhan-halal-cho-npd-viet-nam-d233683.html" target="_blank" rel="noopener">https://vietq.vn/trung-tam-chung-nhan-halal-quoc-gia-trao-chung-nhan-halal-cho-npd-viet-nam-d233683.html</a></em></p>', N'Thanh Hiền', N'Ông Ramlan - Giám đốc Halcert trao chứng nhận Halal cho 6 sản phẩm thuần tự nhiên của công ty. Tại sự kiện, ông Ramlan - Giám đốc Halcert chúc mừng Công ty cổ phần NPD Việt Nam nhận được chứng nhận Ha', '/uploads/tin-su-kien/8c2642a061b90f90.jpg', '2025-05-27');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'printing-technology-and-creative-packaging-elevating-the-image-of-local-products', N'Printing Technology and Creative Packaging – Elevating the Image of Local Products', N'<p>In the food and specialty product business, packaging plays a crucial role in purchasing decisions. A high-quality product with bland packaging can easily be overlooked on supermarket shelves or online platforms. On the other hand, well-designed, eye-catching packaging that reflects local identity can serve as a powerful bridge, allowing consumers to sense the value of the product even before tasting it. To achieve this, printing technology and creative packaging design are essential components.</p><figure class="image"><img style="aspect-ratio:800/479;" src="/uploads/tin-su-kien/51addbedebed1540.jpg" width="800" height="479"></figure><p>Today, many traditional craft villages and small-scale producers have begun investing in packaging, thanks to the support of modern digital printing technologies. Unlike traditional offset printing (which requires large print runs and longer lead times), digital printing allows for small-batch production with flexible changes in content, color, and imagery. As a result, products like fruit preserves, <i>bánh tét lá cẩm</i>, or herbal teas can feature customized packaging for specific holidays or customer segments—without incurring excessive costs.</p><p>Creative packaging goes beyond aesthetics—it must also tell a story. A packet of Tay Ninh shrimp salt, for instance, becomes much more valuable when it communicates its origin, regional identity, production process, and unique characteristics, compared to a similar product packed in a plain plastic bag. Modern printing technology enables the integration of QR codes, NFC tags, or AR images that link users to websites, videos, or immersive storytelling experiences—an engaging and effective way to bring a product’s narrative to life.</p><p>Moreover, eco-friendly packaging is increasingly becoming a market requirement. Many producers are now using recycled paper boxes, biodegradable corn-starch bags, or packaging made from sugarcane pulp and pressed banana leaves. Advances in bio-material manufacturing make it possible to produce packaging that is not only attractive and safe but also leaves a positive impression on international consumers—especially in markets with high environmental responsibility standards.</p><p>Anti-counterfeit packaging is another vital aspect of brand protection for specialty products. Hidden printing, encrypted codes, or electronic labels can help verify product authenticity and prevent imitation. This is especially critical for well-known regional brands such as Phu Quoc fish sauce, Binh Phuoc cashews, or Buon Ma Thuot coffee.</p><p>Packaging is not just the “clothing” of a product—it is the face of a local brand. When packaging is thoughtfully designed and enhanced with the right technology, local specialty products gain a professional image, making them more likely to win the trust and affection of consumers both at home and abroad.</p>', N'Kim Anh', N'In the food and specialty product business, packaging plays a crucial role in purchasing decisions. A high-quality product with bland packaging can easily be overlooked on supermarket shelves or onlin', '/uploads/tin-su-kien/7d87357e5f0f6c8e.jpg', '2025-05-26');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'chao-mung-ngay-so-huu-tri-tue-the-gioi-26-4-2025', N'CHÀO MỪNG NGÀY SỞ HỮU TRÍ TUỆ THẾ GIỚI 26/4/2025', N'<p><strong><img src="/uploads/tin-su-kien/0d2ee18394984af6.png" alt="🎵" width="16" height="16"> CHÀO MỪNG NGÀY SỞ HỮU TRÍ TUỆ THẾ GIỚI 26/4/2025 <img src="/uploads/tin-su-kien/0d2ee18394984af6.png" alt="🎵" width="16" height="16"></strong></p><p>Chủ đề: Sở hữu trí tuệ và Âm nhạc – Cảm nhận nhịp điệu của sáng tạo</p><p>Từ những giai điệu thân quen len lỏi trong từng khoảnh khắc đời sống, đến những bản hòa âm rực rỡ khuấy động tâm hồn – âm nhạc chính là tiếng nói sáng tạo mạnh mẽ và đầy cảm xúc. Và chính quyền sở hữu trí tuệ đã và đang là bệ phóng vững chắc để những ý tưởng âm nhạc ấy có thể lan tỏa khắp thế giới.</p><p>Âm nhạc không chỉ là nghệ thuật – nó còn là sức mạnh gắn kết các ngành công nghiệp. Từ điện ảnh, truyền thông, công nghệ, đến thời trang, game và thương mại điện tử – quyền sở hữu trí tuệ đã mở ra những cánh cửa hợp tác sáng tạo và thúc đẩy đổi mới trong mọi lĩnh vực. Nhịp điệu của âm nhạc là mạch sống nuôi dưỡng trí tưởng tượng, còn sở hữu trí tuệ là nền tảng bảo vệ và phát triển những mạch sống ấy.</p><p><img src="/uploads/tin-su-kien/0c23726e63034054.png" alt="🌍" width="16" height="16"> Ngày Sở hữu trí tuệ thế giới năm nay là dịp để chúng ta:</p><p>Tôn vinh các nhà sáng tạo, nhà soạn nhạc, nghệ sĩ biểu diễn và doanh nhân – những người tiên phong trong hành trình kiến tạo không gian âm nhạc hiện đại.</p><p>Khám phá vai trò của quyền sở hữu trí tuệ trong việc thúc đẩy phát triển ngành công nghiệp âm nhạc bền vững và mang lại lợi ích cho cộng đồng toàn cầu.</p><p>Thắp sáng niềm đam mê, đổi mới và sáng tạo – những yếu tố tạo nên một tương lai âm nhạc giàu bản sắc, sôi động và công bằng hơn.</p><p><img src="/uploads/tin-su-kien/49771645e6e3ab5f.png" alt="🎶" width="16" height="16"> Hãy cùng chúng tôi tham gia Lễ kỷ niệm World IP Day 2025!</p><p>Cùng nhau, chúng ta tôn vinh âm nhạc – ngôn ngữ toàn cầu của cảm xúc.</p><p>Cùng nhau, chúng ta tôn vinh những con người đang định hình tương lai bằng chính nhịp điệu của trí tuệ.</p><p><img src="/uploads/tin-su-kien/635f499751a8d638.png" alt="📅" width="16" height="16"> Ngày 26 tháng 4 năm 2025</p><p><img src="/uploads/tin-su-kien/0aa0b8bd43942280.png" alt="🌐" width="16" height="16"> Hãy sẵn sàng để cảm nhận… nhịp điệu của sở hữu trí tuệ!</p><p><a href="https://www.facebook.com/hashtag/worldipday?__eep__=6&amp;__cft__[0]=AZXU0s0kEMPGZzlawdFNn0GITDu2Qgi2JqO2bzOkfLn6qPNyDDx9cDNTtl6QG_pzGqvCVj5u1YiKF9hSRNfRYyMVfxJh7RAZw7qu6k9K_hQ-gaw1XSf9hnNvWbBU8eVXHXGbZOlkwxrhGqKxWK0oV7mg7z50nCVr51kyKuCVy78TVvN_ns7IJQ1nYvh63ulEdYE&amp;__tn__=*NK-R"><strong>#WorldIPDay</strong></a> <a href="https://www.facebook.com/hashtag/ipday2025?__eep__=6&amp;__cft__[0]=AZXU0s0kEMPGZzlawdFNn0GITDu2Qgi2JqO2bzOkfLn6qPNyDDx9cDNTtl6QG_pzGqvCVj5u1YiKF9hSRNfRYyMVfxJh7RAZw7qu6k9K_hQ-gaw1XSf9hnNvWbBU8eVXHXGbZOlkwxrhGqKxWK0oV7mg7z50nCVr51kyKuCVy78TVvN_ns7IJQ1nYvh63ulEdYE&amp;__tn__=*NK-R"><strong>#IPDay2025</strong></a> <a href="https://www.facebook.com/hashtag/s%E1%BB%9Fh%E1%BB%AFutr%C3%ADtu%E1%BB%87v%C3%A0%C3%A2mnh%E1%BA%A1c?__eep__=6&amp;__cft__[0]=AZXU0s0kEMPGZzlawdFNn0GITDu2Qgi2JqO2bzOkfLn6qPNyDDx9cDNTtl6QG_pzGqvCVj5u1YiKF9hSRNfRYyMVfxJh7RAZw7qu6k9K_hQ-gaw1XSf9hnNvWbBU8eVXHXGbZOlkwxrhGqKxWK0oV7mg7z50nCVr51kyKuCVy78TVvN_ns7IJQ1nYvh63ulEdYE&amp;__tn__=*NK-R"><strong>#SởHữuTríTuệVàÂmNhạc</strong></a> <a href="https://www.facebook.com/hashtag/celebratecreativity?__eep__=6&amp;__cft__[0]=AZXU0s0kEMPGZzlawdFNn0GITDu2Qgi2JqO2bzOkfLn6qPNyDDx9cDNTtl6QG_pzGqvCVj5u1YiKF9hSRNfRYyMVfxJh7RAZw7qu6k9K_hQ-gaw1XSf9hnNvWbBU8eVXHXGbZOlkwxrhGqKxWK0oV7mg7z50nCVr51kyKuCVy78TVvN_ns7IJQ1nYvh63ulEdYE&amp;__tn__=*NK-R"><strong>#CelebrateCreativity</strong></a></p><figure class="image"><img style="aspect-ratio:1133/638;" src="/uploads/tin-su-kien/c015c68ce289069c.png" width="1133" height="638"></figure>', N'Kim Anh', N'CHÀO MỪNG NGÀY SỞ HỮU TRÍ TUỆ THẾ GIỚI 26/4/2025 Chủ đề: Sở hữu trí tuệ và Âm nhạc – Cảm nhận nhịp điệu của sáng tạo Từ những giai điệu thân quen len lỏi trong từng khoảnh khắc đời sống, đến những bản', '/uploads/tin-su-kien/76ed83ac108cf91d.png', '2025-05-26');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'trieu-tap-tuyen-dung-vien-chuc-nam-2024-cua-trung-tam-ung-dung-tien-bo-khoa-hoc-va-cong-nghe-can-tho', N'Triệu tập tuyển dụng viên chức năm 2024 của Trung tâm Ứng dụng tiến bộ Khoa học và công nghệ Cần Thơ', N'<figure class="image"><img style="aspect-ratio:1005/1421;" src="/uploads/tin-su-kien/6aaf79b322de4e07.jpg" width="1005" height="1421"></figure><figure class="image"><img style="aspect-ratio:991/1410;" src="/uploads/tin-su-kien/083cb4a52fe8f42e.jpg" width="991" height="1410"></figure><figure class="image"><img style="aspect-ratio:1097/2064;" src="/uploads/tin-su-kien/f082bb3e79f80735.jpg" width="1097" height="2064"></figure>', N'', N'', '/uploads/tin-su-kien/629bd9bd50288812.jpg', '2025-05-24');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'giao-luu-bong-da-chao-mung-135-nam-ngay-sinh-chu-tich-ho-chi-minh-va-ngay-khoa-hoc-va-cong-nghe-viet-nam-18-5', N'Giao lưu bóng đá chào mừng 135 năm ngày sinh Chủ tịch Hồ Chí Minh và ngày Khoa học và Công nghệ Việt Nam 18/5', N'<p>Hòa trong không khí thiêng liêng, cả nước hướng về <strong>kỷ niệm 135 năm ngày sinh Chủ tịch Hồ Chí Minh (19/5/1890 – 19/5/2025)</strong> – vị lãnh tụ vĩ đại của dân tộc, người đã dành cả cuộc đời vì độc lập, tự do và hạnh phúc của nhân dân; đồng thời chào mừng <strong>ngày Khoa học và Công nghệ Việt Nam 18/5</strong>, Sở Khoa học và công nghệ Cần Thơ đã tổ chức <strong>sự kiện giao lưu bóng đá</strong> với mục tiêu kết nối, sẻ chia và lan tỏa những giá trị tích cực trong lao động, học tập, sáng tạo và rèn luyện thể chất.</p><p>Sự kiện diễn ra vào ngày 17/5/2025, tại sân bóng đá Trung tâm Ứng dụng tiến bộ khoa học và công nghệ, quy tụ 8 đội bóng cũng như hơn 100 công đoàn viên chức và người lao động đến từ các đơn vị Sở khoa học và Công nghệ Cần Thơ, Sóc Trăng và Hậu Giang, là dịp để các công đoàn viên và người lao động cùng hòa mình trong tinh thần thể thao rèn luyện sức khỏe, gắn kết cộng đồng và khơi dậy khát vọng cống hiến. </p><p>Giao lưu bóng đá lần này không chỉ là sân chơi lành mạnh mà còn mang ý nghĩa giáo dục sâu sắc. Đó là tinh thần "Khỏe để học tập, lao động và cống hiến", là sự tiếp nối tư tưởng của Chủ tịch Hồ Chí Minh về việc rèn luyện thể chất song song với phát triển trí tuệ. Trong mỗi trận đấu, dù là cầu thủ hay cổ động viên, ai nấy đều thể hiện tinh thần nhiệt huyết, đoàn kết, trung thực và tôn trọng lẫn nhau – những giá trị nền tảng trong khoa học và trong cuộc sống.</p><p>Các trận đấu diễn ra trong không khí hào hứng và đầy kịch tính, thể hiện tinh thần thể thao cao thượng, trung thực và đoàn kết. Mỗi cầu thủ đều thi đấu hết mình, cống hiến những pha bóng đẹp mắt, mang lại nhiều cảm xúc cho khán giả. Sau một ngày tranh tài sôi nổi, giải đấu đã khép lại thành công tốt đẹp với những pha bóng đẹp, những nụ cười rạng rỡ và sự kết nối bền chặt giữa các đơn vị. Ban Tổ chức đã trao các giải thưởng cho các đội thi đấu xuất sắc, đồng thời biểu dương tinh thần tham gia tích cực, sôi nổi của tất cả các tập thể và cá nhân.</p><p>Thông qua hoạt động giao lưu bóng đá lần này, Trung tâm Ứng dụng tiến bộ khoa học và công nghệ mong muốn tiếp tục lan tỏa tinh thần Hồ Chí Minh – sống giản dị, rèn luyện kiên trì, hành động vì cộng đồng – và thúc đẩy phong trào thể dục thể thao, nghiên cứu sáng tạo trong đội ngũ cán bộ, giảng viên, sinh viên và người lao động. Đây chính là nền tảng để xây dựng môi trường làm việc, học tập và nghiên cứu khoa học ngày càng chuyên nghiệp, nhân văn và hiệu quả.</p><p><strong>Giao lưu thể thao – Kết nối trí tuệ – Lan tỏa giá trị.</strong></p><figure class="image"><img style="aspect-ratio:2592/1728;" src="/uploads/tin-su-kien/f348fbd048238d70.jpg" width="2592" height="1728"></figure><figure class="image"><img style="aspect-ratio:2592/1728;" src="/uploads/tin-su-kien/cbcd2ce424892e19.jpg" width="2592" height="1728"></figure><figure class="image"><img style="aspect-ratio:2560/1922;" src="/uploads/tin-su-kien/7397b7dca02e6ca4.jpg" width="2560" height="1922"></figure><figure class="image"><img style="aspect-ratio:5184/3456;" src="/uploads/tin-su-kien/ccc55526ed60df67.JPG" width="5184" height="3456"></figure><figure class="image"><img style="aspect-ratio:5184/3456;" src="/uploads/tin-su-kien/60aa88d47ebac3ce.JPG" width="5184" height="3456"></figure><figure class="image"><img style="aspect-ratio:5184/3456;" src="/uploads/tin-su-kien/76e3931fefa1109a.JPG" width="5184" height="3456"></figure>', N'Kim Anh', N'Hòa trong không khí thiêng liêng, cả nước hướng về kỷ niệm 135 năm ngày sinh Chủ tịch Hồ Chí Minh (19/5/1890 – 19/5/2025) – vị lãnh tụ vĩ đại của dân tộc, người đã dành cả cuộc đời vì độc lập, tự do v', '/uploads/tin-su-kien/611d63d6eb923ed8.jpg', '2025-05-19');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'chao-mung-ngay-khoa-hoc-va-cong-nghe-viet-nam-18-5-2025', N'CHÀO MỪNG NGÀY KHOA HỌC VÀ CÔNG NGHỆ VIỆT NAM 18/5/2025', N'<p><img src="/uploads/tin-su-kien/c70dbfe01a98ec41.png" alt="🎉" width="16" height="16"> CHÀO MỪNG NGÀY KHOA HỌC VÀ CÔNG NGHỆ VIỆT NAM 18/5/2025</p><p><img src="/uploads/tin-su-kien/cf4d8b11b5f24b24.png" alt="🔬" width="16" height="16"> Phát triển khoa học – công nghệ và đổi mới sáng tạo phục vụ phát triển bền vững đất nước</p><p>Ngày Khoa học và Công nghệ Việt Nam (18/5) là ngày hội lớn nhằm tôn vinh trí tuệ và sự cống hiến của đội ngũ những người làm công tác khoa học, công nghệ, đổi mới sáng tạo trên cả nước. Đồng thời, đây cũng là dịp để toàn xã hội cùng nhìn nhận lại những thành tựu đã đạt được trong lĩnh vực KH&amp;CN, cùng lan tỏa niềm đam mê nghiên cứu, khơi dậy tinh thần sáng tạo trong mọi lĩnh vực của đời sống.</p><p><img src="/uploads/tin-su-kien/0c23726e63034054.png" alt="🌍" width="16" height="16"> Năm 2025 – Cơ hội và thách thức mới</p><p>Trong bối cảnh toàn cầu hóa và chuyển đổi số đang diễn ra mạnh mẽ, Việt Nam đang đứng trước cơ hội lớn để bứt phá. Tuy nhiên, đi kèm là những thách thức về công nghệ, nhân lực, môi trường và phát triển bền vững.</p><p>Do đó, vai trò của khoa học, công nghệ và đổi mới sáng tạo càng trở nên cốt lõi, là chìa khóa để mở ra những giải pháp tối ưu, đột phá cho các vấn đề lớn của đất nước.</p><p><img src="/uploads/tin-su-kien/3cb0484981a40776.png" alt="🎯" width="16" height="16"> Bộ KH&amp;CN lựa chọn chủ đề năm 2025: “Phát triển khoa học – công nghệ và đổi mới sáng tạo phục vụ phát triển bền vững đất nước” với mong muốn ngành KH&amp;CN Việt Nam sẽ có đóng góp thiết thực, mạnh mẽ hơn, khẳng định được vai trò quan trọng trong quá trình xây dựng đất nước, phục hồi nền kinh tế.</p><p><img src="/uploads/tin-su-kien/da1a41562eb9755c.png" alt="🌱" width="16" height="16"> Tại Cần Thơ và khu vực ĐBSCL</p><p>Vùng đất giàu tiềm năng về nông nghiệp, thủy sản và đổi mới sinh thái này đang từng bước trở thành trung tâm đổi mới sáng tạo của khu vực phía Nam. Các trường đại học, viện nghiên cứu, doanh nghiệp và tổ chức KH&amp;CN tại đây đang không ngừng thúc đẩy nghiên cứu, ứng dụng và thương mại hóa kết quả KH&amp;CN.</p><p>Trong đó, nổi bật là các hoạt động hỗ trợ sinh viên, nhà khoa học trẻ thông qua các sự kiện như:</p><p><img src="/uploads/tin-su-kien/c650eb2267f12e5e.png" alt="✨" width="16" height="16"> Triển lãm Sáng tạo KH&amp;CN sinh viên</p><p><img src="/uploads/tin-su-kien/c650eb2267f12e5e.png" alt="✨" width="16" height="16"> Diễn đàn kết nối công nghệ - khởi nghiệp đổi mới sáng tạo</p><p><img src="/uploads/tin-su-kien/c650eb2267f12e5e.png" alt="✨" width="16" height="16"> Các chương trình tập huấn, kết nối doanh nghiệp, xúc tiến chuyển giao công nghệ</p><p><img src="/uploads/tin-su-kien/11a6192f5544284c.png" alt="🌟" width="16" height="16"> Hướng tới tương lai</p><p>Khoa học không chỉ là những công trình nghiên cứu, mà còn là những giải pháp cụ thể giúp nâng cao chất lượng sống, bảo vệ môi trường, phát triển kinh tế và kiến tạo xã hội bền vững.</p><p>Ngày Khoa học và Công nghệ không chỉ là dịp để tri ân, mà còn là lời kêu gọi mỗi cá nhân, đặc biệt là thế hệ trẻ, hãy dấn thân, đổi mới và hành động.</p><p><img src="/uploads/tin-su-kien/46c0ecf77cbc7dfb.png" alt="📢" width="16" height="16"> Trung tâm Ứng dụng Tiến bộ Khoa học và Công nghệ Cần Thơ tự hào là đơn vị kết nối giữa nghiên cứu và ứng dụng, giữa nhà khoa học và doanh nghiệp, giữa ý tưởng và thị trường. Chúng tôi cam kết tiếp tục đồng hành, hỗ trợ và thúc đẩy hệ sinh thái đổi mới sáng tạo tại địa phương và khu vực.</p><p><img src="/uploads/tin-su-kien/3e2368f0cc1faa41.png" alt="🙏" width="16" height="16"> Xin gửi lời tri ân sâu sắc đến tất cả những người đang ngày đêm đóng góp cho sự phát triển KH&amp;CN nước nhà. Chúc mừng Ngày Khoa học và Công nghệ Việt Nam 18/5!</p><figure class="image"><img style="aspect-ratio:1000/500;" src="/uploads/tin-su-kien/675734d0813da5c2.png" width="1000" height="500"></figure>', N'Kim Anh', N'CHÀO MỪNG NGÀY KHOA HỌC VÀ CÔNG NGHỆ VIỆT NAM 18/5/2025 Phát triển khoa học – công nghệ và đổi mới sáng tạo phục vụ phát triển bền vững đất nước Ngày Khoa học và Công nghệ Việt Nam (18/5) là ngày hội ', '/uploads/tin-su-kien/817c29b2d62d3a21.png', '2025-05-18');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'ung-dung-cong-nghe-sinh-hoc-nang-cao-gia-tri-san-pham-duoc-lieu-ban-dia', N'Ứng dụng công nghệ sinh học nâng cao giá trị sản phẩm dược liệu bản địa', N'<p>Việt Nam là một trong những quốc gia có nguồn tài nguyên dược liệu phong phú, với hàng nghìn loài cây thuốc quý như sâm Ngọc Linh, trà hoa vàng, đinh lăng, hà thủ ô, ba kích… Phân bố trải rộng khắp các vùng núi, trung du và đồng bằng, những loài dược liệu này không chỉ là bài thuốc quý mà còn là tài nguyên kinh tế to lớn cho các cộng đồng bản địa. Tuy nhiên, giá trị của dược liệu vẫn chưa được khai thác tương xứng với tiềm năng. Và chính công nghệ sinh học đang mở ra hướng đi mới để nâng cao chất lượng, bảo tồn nguồn gen và phát triển bền vững ngành dược liệu địa phương.</p><p>Một trong những ứng dụng nổi bật của công nghệ sinh học là nhân giống cây thuốc quý bằng phương pháp nuôi cấy mô tế bào. Ví dụ điển hình là sâm Ngọc Linh – một loài sâm chỉ có ở Việt Nam, giá thị trường có thể lên tới hàng trăm triệu đồng mỗi kg. Trước đây, việc nhân giống chủ yếu dựa vào hạt, rất chậm và phụ thuộc vào điều kiện tự nhiên. Nhờ công nghệ nuôi cấy mô, các nhà khoa học có thể nhân giống vô tính với tốc độ nhanh, đồng thời đảm bảo cây con giữ nguyên đặc tính quý của cây mẹ. Điều này không chỉ giúp phục hồi nguồn gen quý mà còn cung cấp giống sạch bệnh cho người trồng.</p><figure class="image"><img style="aspect-ratio:640/425;" src="/uploads/tin-su-kien/78e23acc57a182ea.webp" width="640" height="425"><figcaption>Ảnh minh hoạ</figcaption></figure><p>Bên cạnh nhân giống, công nghệ sinh học còn hỗ trợ trong việc chiết xuất hoạt chất từ dược liệu để sản xuất thực phẩm chức năng, mỹ phẩm và dược phẩm. Thay vì chỉ phơi khô và bán nguyên liệu thô, giờ đây các địa phương có thể áp dụng công nghệ chiết xuất tinh dầu, polyphenol, flavonoid hay saponin – những hoạt chất quý giá có trong thảo dược. Các dây chuyền này có thể được đầu tư theo mô hình hợp tác xã hoặc liên kết với doanh nghiệp, tạo ra sản phẩm tinh chế có giá trị cao gấp nhiều lần so với bán thô.</p><p>Công nghệ còn giúp kiểm nghiệm và tiêu chuẩn hóa chất lượng dược liệu – điều kiện tiên quyết để bước chân vào thị trường quốc tế. Nhiều loại cây thuốc dù rất tốt nhưng do không có hồ sơ chất lượng, không kiểm soát được dư lượng thuốc bảo vệ thực vật hoặc sai lệch về hoạt chất nên không thể xuất khẩu. Việc áp dụng công nghệ phân tích phổ, sắc ký lỏng hiệu năng cao (HPLC) hoặc thiết bị kiểm tra DNA giúp xác định thành phần hoạt chất chính xác, đồng thời loại bỏ các mẫu giả mạo, kém chất lượng.</p><p>Không thể không nhắc đến việc xây dựng vùng trồng dược liệu đạt chuẩn GACP-WHO (thực hành tốt trồng trọt và thu hái theo hướng dẫn của Tổ chức Y tế Thế giới). Các công nghệ IoT, cảm biến đất, theo dõi thời tiết, phần mềm quản lý nông trại… đang được đưa vào những vùng trồng sâm, nghệ, chè vằng hay cà gai leo ở nhiều địa phương. Việc quản lý được toàn bộ quá trình từ trồng đến thu hái giúp sản phẩm dược liệu minh bạch, an toàn, và đặc biệt là tạo lòng tin với thị trường cao cấp như Nhật Bản, châu Âu, Mỹ.</p><p>Dẫu vậy, thách thức lớn nhất hiện nay là phần lớn người trồng dược liệu vẫn canh tác theo kinh nghiệm, thiếu hiểu biết về quy trình kỹ thuật. Sự tham gia của doanh nghiệp khoa học – công nghệ và viện nghiên cứu vào liên kết chuỗi là giải pháp cần thiết. Đồng thời, nhà nước cần có chính sách bảo tồn nguồn gen, quy hoạch vùng trồng và đầu tư phòng thí nghiệm kiểm nghiệm tại các địa phương trọng điểm.</p><p>Dược liệu không chỉ là sản phẩm kinh tế mà còn là di sản văn hóa và tri thức bản địa quý giá. Khi công nghệ sinh học được ứng dụng đúng cách, những cây thuốc tưởng chừng chỉ có giá trị trong phạm vi làng xã sẽ có thể bước ra thế giới như một biểu tượng của sức khỏe tự nhiên. Đó là sự kết hợp giữa cổ truyền và hiện đại, giữa bản sắc địa phương và năng lực công nghệ – con đường bền vững để nâng tầm giá trị dược liệu Việt Nam.</p>', N'', N'Việt Nam là một trong những quốc gia có nguồn tài nguyên dược liệu phong phú, với hàng nghìn loài cây thuốc quý như sâm Ngọc Linh, trà hoa vàng, đinh lăng, hà thủ ô, ba kích… Phân bố trải rộng khắp cá', '/uploads/tin-su-kien/f130dabf51d3acfe.webp', '2025-05-13');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'bao-cao-chuyen-de-hoc-tap-va-lam-theo-tam-guong-dao-duc-ho-chi-minh-hoc-va-lam-theo-phong-cach-noi-di-doi-voi-lam-cua-chu-tich-ho-chi-minh', N'Báo cáo chuyên đề học tập và làm theo tấm gương đạo đức Hồ Chí Minh: Học và làm theo phong cách “Nói đi đôi với làm” của Chủ tịch Hồ Chí Minh', N'<p>“Nói đi đôi với làm” trong tư tưởng Hồ Chí Minh là sự thống nhất, sự gắn liền giữa nhận thức với hành động; lời nói và việc làm phải tương xứng với nhau, phải phù hợp với nhau, không được mâu thuẫn, trái ngược. Để xảy ra tình huống mâu thuẫn, trái ngược này là mắc vào một lỗi lớn, không chỉ là lỗi về tư duy, mà còn là lỗi lớn hơn, nặng hơn về đạo đức; do đó, nói đi đôi với làm là tiêu chí về đức tính trung thực. Ngược lại, nói không đi đôi với làm là bằng chứng của sự giả dối, dối trá, trước hết là thói vô trách nhiệm và thiếu vắng lòng tự trọng. </p><p>Suy ngẫm và trải nghiệm từ các sự kiện, việc làm, ứng xử với người, với việc, ngay cả <i>với chính mình</i>, chúng ta ngày càng tự ý thức rằng, hóa ra nói đi đôi với làm là chỗ khó nhất ở đời, để thực hiện được không chỉ cần sự hiểu biết, có lý trí, nghị lực và quyết tâm, mà còn cần có tình cảm, đạo đức trong sáng, hướng thiện. Vì theo Chủ tịch Hồ Chí Minh, trong đời thường ta gọi đó là <i>sự tử tế, lương thiện.</i> Nói đi đôi với làm đòi hỏi mỗi người phải thường xuyên biết tự vấn lương tâm, biết tự trọng mình và tôn trọng người khác, cao nhất là <i>trọng dân, vì dân</i>.</p><figure class="image"><img style="aspect-ratio:1200/630;" src="/uploads/tin-su-kien/b03cc1bf1f4fcd36.webp" width="1200" height="630"><figcaption><i>Chủ tịch Hồ Chí Minh dùng thử máy cấy lúa cải tiến tại Trại thí nghiệm trồng lúa Sở Nông lâm Hà Nội (ngày 16-7-1960). (Ảnh tư liệu).</i></figcaption></figure><p>Thống nhất giữa lý luận và thực tiễn là một trong những nguyên tắc cơ bản của chủ nghĩa Mác - Lênin. Nguyên tắc này đã được Chủ tịch Hồ Chí Minh vận dụng sáng tạo vào điều kiện Việt Nam và trở thành phương châm “Nói đi đôi với làm”, đã trở thành lẽ sống, phương châm làm việc, nguyên tắc hoạt động của Người. “Nói đi đôi với làm” là nguyên tắc đầu tiên trong ba nguyên tắc đạo đức cách mạng theo quan niệm của chủ tịch Hồ Chí Minh: Nói thì phải làm, xây đi cùng với chống và tu dưỡng đạo đức suốt đời. “Nói thì phải làm” là thể hiện sự thống nhất giữa lý luận và thực tiễn, tư tưởng và hành động, nhận thức và việc làm. Cụ thể:</p><p><strong>Thứ nhất, nói đi đôi với làm là nói phải đúng chủ trương, chính sách của Ðảng và Nhà nước, không được xuyên tạc, nói sai.</strong> Mỗi đảng viên phải nắm vững đường lối cách mạng của Ðảng trong toàn bộ tiến trình cách mạng và được cụ thể hóa trong từng giai đoạn. Nắm vững đường lối cách mạng để thực hiện cho đúng, để tuyên truyền, giáo dục, vận động Nhân dân làm cho đúng. Phải rèn luyện bản lĩnh vững vàng để có niềm tin vào mục tiêu lý tưởng cách mạng của Ðảng đó là: bảo vệ sự nghiệp cách mạng, nền độc lập dân tộc và xây dựng xã hội tự do, ấm no, hạnh phúc cho Nhân dân. Ðể nói đúng quan điểm, đường lối của Ðảng, mỗi đảng viên phải nghiêm túc nghiên cứu, học tập lý luận chủ nghĩa Mác - Lênin, tư tưởng Hồ Chí Minh.</p><p><strong>Thứ hai, nói đi đôi với làm là không được “nói một đằng làm một nẻo”.</strong> Theo chủ tịch Hồ Chí Minh, lời nói cần đi đôi với việc làm, nói được làm được, sẽ mang lại những hiệu quả lớn, được nhiều người hưởng ứng và làm theo. Không được “nói nhiều làm ít” hoặc “nói mà không làm”. Chủ tịch Hồ Chí Minh cho rằng, để chống việc “nói một đằng, làm một nẻo”, mỗi đảng viên còn cần phải xác định rõ trách nhiệm của mình. Mỗi người, mỗi ngành, mỗi giới, mỗi tầng lớp Nhân dân đều có những công việc, nhiệm vụ cụ thể. Khi nói phải gắn với những công việc, nhiệm vụ cụ thể, không chung chung, qua loa, đại khái dẫn đến nói chung, ai nói cũng được, nghe thì hay, nhưng không biết thực hiện thế nào, kết quả ra sao.</p><p><strong>Thứ ba là, không được hứa mà không làm.</strong> Lời hứa chỉ có giá trị khi đi liền với việc làm cụ thể. “Làm” ở đây chính là hành động, là hoạt động thực tiễn, là tổ chức thực hiện, đưa chủ trương, đường lối của Ðảng, chính sách, pháp luật của Nhà nước vào cuộc sống, từ việc nhỏ đến việc lớn, mang ý nghĩa thiết thực. Ðối với mỗi đảng viên “cần phải óc nghĩ, mắt trông, tai nghe, chân đi, miệng nói, tay làm. Chứ không phải chỉ nói suông, chỉ ngồi viết mệnh lệnh… phải thật thà nhúng tay vào việc”.</p><p>Trong suốt cuộc đời mình, Người đã thực hiện một cách nghiêm túc và đầy đủ nói đi đôi với làm. Người quan niệm: Muốn hướng dẫn nhân dân, mình phải làm mực thước cho người ta bắt chước; tự mình phải chính trước, mới giúp người khác chính, mình không chính mà muốn người khác chính là vô lý. Trong cuộc đời của Chủ tịch Hồ Chí Minh đã có bao nhiêu câu chuyện cảm động về việc nêu gương, nói đi đôi với làm, tự mình làm trước.</p><p>Năm 1945, trước nạn đói trên miền Bắc, Người đề xuất toàn dân tiết kiệm gạo để giúp đồng bào bị đói và Người kêu gọi: "Tôi xin đề nghị với đồng bào cả nước, và tôi xin thực hành trước: Cứ 10 ngày nhịn ăn một bữa, mỗi tháng nhịn 3 bữa, đem gạo đó (mỗi bữa một bơ) để cứu dân nghèo”.</p><p>Những năm Hồ Chí Minh sống và làm việc tại Phủ Chủ tịch, khi kinh tế khó khăn, đời sống nhân dân còn nghèo khó, mọi người ăn cơm độn ngô, khoai, sắn, Người đề nghị nhà bếp: Cán bộ, nhân dân ăn độn bao nhiêu phần trăm, nấu cơm độn cho Người từng ấy, giống như cán bộ, nhân dân. Trong các chuyến đi thăm các địa phương, nhất là các chuyến đi trong ngày, Người thường mang theo cơm nắm với muối vừng vì không muốn phiền hà đến cơ sở.</p><p>Về chỗ ở, Người khước từ ở ngôi nhà sang trọng của Toàn quyền Ðông Dương trước đây mà chỉ ở ngôi nhà của người công nhân phục vụ; đi dép lốp, mặc áo vá vai, dùng chiếc ô tô cũ, mà coi đó là “cái phúc của dân, đừng bỏ cái phúc đó đi”. Mùa hè nóng bức, Hồ Chí Minh dùng chiếc quạt lá cọ, “để dành điện phục vụ cho sản xuất, dành điện phục vụ sinh hoạt cho nhân dân”.</p><p>Trong sự nghiệp cách mạng ở nước ta, Đảng ta luôn giữ vững bản lĩnh chính trị, bản chất cách mạng và khoa học; kiên định chủ nghĩa Mác - Lênin, tư tưởng Hồ Chí Minh; mục tiêu độc lập dân tộc và chủ nghĩa xã hội; thường xuyên tự đổi mới, tự chỉnh đốn và ngày càng lớn mạnh. Dưới sự lãnh đạo đúng đắn, sáng suốt của Đảng; sự quản lý điều hành của Nhà nước, Nhân dân ta đã giành được hết thắng lợi này đến thắng lợi khác, lập nên những kỳ tích trong thế kỷ XX, XXI. Đặc biệt, sau 39 năm tiến hành công cuộc “Đổi mới 1986”, từ một đất nước nghèo nàn, có cơ sở vật chất - kỹ thuật, kết cấu hạ tầng kinh tế - xã hội lạc hậu, trình độ thấp, đến nay, Việt Nam đã vươn lên trở thành nước đang phát triển, có thu nhập trung bình; văn hóa, xã hội tiếp tục phát triển, đời sống vật chất và tinh thần của Nhân dân được cải thiện; công tác xây dựng Đảng và hệ thống chính trị có bước đột phá; khối đại đoàn kết toàn dân tộc không ngừng được củng cố; chính trị, xã hội ổn định, quốc phòng - an ninh, độc lập, chủ quyền được giữ vững. Đó là kết quả, sự nỗ lực phấn đấu không ngừng của toàn Đảng, toàn dân, toàn quân, trong đó có sự hy sinh quên mình đóng góp quan trọng của đội ngũ cán bộ, đảng viên đặc biệt là sự ủng hộ và đặt niềm tin tuyệt đối của Nhân dân vào vai trò lãnh đạo của Đảng, của chính quyền Nhà nước.</p><p>Hiện nay công cuộc đổi mới toàn diện đất nước do Đảng ta khởi xướng và lãnh đạo đang đứng trước những thời cơ vận hội to lớn, đồng thời đang phải đối mặt với những thách thức, nguy cơ phức tạp, khó lường. Bối cảnh đó đã, đang đặt ra những nhiệm vụ to lớn, nặng nề cho mỗi đảng viên. Hơn bất cứ lúc nào, sự nghiệp xây dựng và bảo vệ Tổ quốc Việt Nam xã hội chủ nghĩa hôm nay đang đòi hỏi chúng ta phải nêu cao ý chí tiến công, phát huy bản lĩnh, trí tuệ Việt Nam để tranh thủ thời cơ, vượt qua nguy cơ nhằm nhanh chóng hoàn thành mục tiêu “Dân giàu, nước mạnh, dân chủ, công bằng, văn minh”.</p><p>Năm 2025, để việc học tập và làm theo tư tưởng, đạo đức, phong cách Hồ Chí Minh trở nên thiết thực, hiệu quả hơn nữa, mỗi chúng ta trên cương vị công tác của mình hãy bắt đầu bằng những việc làm tốt, dù nhỏ hay lớn nhưng có ích cho xã hội, quê hương, đất nước. Nói một cách khác, học tập và làm theo tư tưởng, đạo đức, phong cách Hồ Chí Minh về “Nói đi đôi với làm” chính là thực hiện nguyên tắc bảo đảm sự sống còn của niềm tin, lòng dân đối với Đảng, với chính quyền và cán bộ, đảng viên, công chức, viên chức.</p><p>Để thực hiện tốt phương châm “Nói đi đôi với làm” của Chủ tịch Hồ Chí Minh, mỗi đảng viên cần thực hiện tốt những nội dung sau:</p><p><strong>Thứ nhất, trực tiếp tham gia vào công tác tuyên truyền, giáo dục lý luận chính trị, đi đầu, gương mẫu trong học tập và rèn luyện đạo đức cách mạng.</strong></p><p>Mỗi đảng viên phải thực sự trở thành tấm gương sáng cho mọi người noi theo. Điều này càng đòi hỏi mỗi người từ việc nhỏ đến lớn, từ việc riêng đến việc chung, từ trong cuộc sống đến công việc thường ngày luôn luôn phải nỗ lực thực hiện tốt phương châm “Nói đi đôi với làm”.</p><p>Hồ Chí Minh dạy cán bộ, đảng viên: “Trước mặt quần chúng, không phải ta cứ viết lên trán chữ “cộng sản” mà ta được họ yêu mến. Quần chúng chỉ yêu mến những người có đủ tư cách, đạo đức. Muốn hướng dẫn nhân dân, mình phải làm mực thước cho người ta bắt chước”.</p><p>Thường xuyên học tập và làm theo tư tưởng, đạo đức, phong cách Hồ Chí Minh; Tự soi, tự sửa; Thực hiện nghiêm yêu cầu về rèn luyện phẩm chất chính trị, đạo đức cách mạng của cán bộ, đảng viên mà Đại hội XI của Đảng đã đề ra: “Mỗi cán bộ, đảng viên không ngừng tu dưỡng, rèn luyện đạo đức cách mạng, thực sự là một tấm gương về phẩm chất, đạo đức, lối sống. Cán bộ cấp trên phải gương mẫu trước cán bộ cấp dưới, đảng viên và Nhân dân”.</p><p>Nói đi đôi với làm để hướng dẫn nhân dân làm theo, đặc biệt là với thế hệ trẻ. Nói đi đôi với làm phải gắn với nêu cao tinh thần trách nhiệm và chống chủ nghĩa cá nhân. Chỉ trên cơ sở này, cán bộ, đảng viên mới thu phục được quần chúng, mới cảm hóa, lôi kéo họ tạo thành phong trào thực tiễn rộng lớn để xây dựng, phát triển đất nước, thực hiện nghị quyết của Ðảng</p><p>Thực hiện nghiêm túc các nội dung theo Nghị quyết Trung ương 4 khóa XI, khóa XII, Kết luận số 21-KL/TW ngày 25/10/2021 của Ban Chấp hành Trung ương Đảng khóa XIII; Kết luận số 01-KL/TW ngày 18/5/2021 của Bộ Chính trị, đăng ký các nội dung học tập và làm theo Bác, xây dựng chương trình hành động cá nhân gắn với nhiệm vụ được phân công và nội dung “3 xây - 3 chống” theo Nghị quyết số 22-NQ/TU ngày 15/7/2023 và Nghị định số 73/2023/NĐ-CP của Chính phủ quy định về khuyến khích, bảo vệ cán bộ năng động, sáng tạo, dám nghĩ, dám làm, dám chịu trách nhiệm vì lợi ích chung. Tích cực tuyên truyền để thấy được vai trò lãnh đạo của Đảng, Nhà nước là “tận tâm, tận lực phụng sự Tổ quốc và Nhân dân”, “trung thành tuyệt đối với lợi ích của giai cấp, của Nhân dân, của dân tộc”, “ngoài lợi ích của giai cấp, của Nhân dân, của dân tộc, Đảng ta không còn lợi ích gì khác”.</p><p><strong>Thứ hai, người đảng viên phải thực hiện tốt công tác tự phê bình và phê bình.</strong></p><p>Kiên quyết thực hiện đúng phương châm “Nói đi đôi với làm”, đã nói phải làm, đã làm phải chịu. Đó là tinh thần tự phê bình và phê bình. Tăng cường công tác kiểm tra, giám sát, sớm phát hiện những biểu hiện sai lệch trong cách nói, cách làm trong công việc. Tăng cường tính tự phê bình và phê bình trong đội ngũ cán bộ, đảng viên. Tăng cường tổ chức thực hiện, kiểm tra, sơ kết, tổng kết việc thực hiện Nghị quyết.</p><p><strong>Thứ ba, người đảng viên phải tiếp tục đổi mới phong cách, lề lối làm việc.</strong></p><p>Mỗi đảng viên, không ngừng nỗ lực phấn đấu thực hiện tốt việc học tập và làm theo tư tưởng, đạo đức, phong cách Hồ Chí Minh, góp phần thiết thực trong thực hành phong cách làm việc của Chủ tịch Hồ Chí Minh: “Nói đi đôi với làm”.</p><p><strong>Thứ tư, người đảng viên phải có cái tâm, cái đức trong sáng.</strong> </p><p>Đó là cái tâm yêu nghề, sống với nghề. Có như thế thì chất lượng công việc mới ngày càng được củng cố và nâng cao.</p><p>Học tập và vận dụng tư tưởng đạo đức, phong cách Hồ Chí Minh về “nói đi đôi với làm”, chúng ta không học tập một cách máy móc, tùy vào lĩnh vực cụ thể mà chúng ta vận dụng một cách sáng tạo góp phần nâng cao chất lượng công việc và tu dưỡng, rèn luyện đạo đức cách mạng.</p><p>Trong quá trình công tác, mỗi đảng viên cần mạnh dạn đấu tranh với những biểu hiện sợ sai, sợ trách nhiệm, không dám làm của đội ngũ cán bộ, đảng viên trong quá trình thực thi nhiệm vụ. Đồng thời, khuyến khích, bảo vệ các cá nhân năng động, sáng tạo, dám nghĩ, dám làm, dám chịu trách nhiệm vì lợi ích chung.</p><p>Hiện nay, Nghị quyết 57-NQ/TW ngày 22/12/2024 của Bộ Chính trị có tính định hướng chiến lược rõ ràng, đặt khoa học, công nghệ và đổi mới sáng tạo vào vị trí trung tâm của quá trình phát triển đất nước. Điều này không chỉ thể hiện sự công nhận mà còn khích lệ, động viên giới trí thức, nhà khoa học cảm thấy tự hào và ý thức trách nhiệm cao hơn, tạo động lực để tiếp tục nỗ lực nghiên cứu và sáng tạo, đóng góp trực tiếp vào sự phát triển khoa học và công nghệ của quốc gia. Hành động “Nói đi đôi với làm” và “Dám nghĩ - Dám nói - Dám làm - Dám chịu trách nhiệm - Dám đổi mới, sáng tạo - Dám đương đầu với khó khăn, thử thách - Dám hành động vì lợi ích chung” của đội ngũ đảng viên sẽ càng dễ thực hiên hơn, góp phần xây dựng tổ chức Đảng tại cơ sở vững mạnh, đạt nhiều kết quả to lớn trong kỷ nguyên mới, kỷ nguyên vươn mình.</p>', N'Nhi Bình', N'“Nói đi đôi với làm” trong tư tưởng Hồ Chí Minh là sự thống nhất, sự gắn liền giữa nhận thức với hành động; lời nói và việc làm phải tương xứng với nhau, phải phù hợp với nhau, không được mâu thuẫn, t', '/uploads/tin-su-kien/12b1b7da5783df09.webp', '2025-05-10');
INSERT INTO #NewsSeed (QueryString, Title, Contents, Author, Description, Image, PublishedDate) VALUES (N'thong-bao-trieu-tap-thi-sinh-tham-du-vong-2-xet-tuyen-phong-van-vien-chuc', N'Thông báo Triệu tập thí sinh tham dự vòng 2 xét tuyển (phỏng vấn) viên chức', N'<figure class="image"><img style="aspect-ratio:1125/1554;" src="/uploads/tin-su-kien/297f718e53d94dce.png" width="1125" height="1554"></figure><figure class="image"><img style="aspect-ratio:1125/1554;" src="/uploads/tin-su-kien/75e9108046312c10.png" width="1125" height="1554"></figure><figure class="image"><img style="aspect-ratio:1125/1554;" src="/uploads/tin-su-kien/7ea1e6a3c141e9c0.png" width="1125" height="1554"></figure><figure class="image"><img style="aspect-ratio:1125/1554;" src="/uploads/tin-su-kien/8e125bead6ea359e.png" width="1125" height="1554"></figure>', N'', N'', '/uploads/tin-su-kien/0a7b430c042e459a.webp', '2025-05-09');
INSERT INTO Contents
