/*
Seeds news/event articles scraped from https://ttud.com.vn/su-kien (2025 onward,
44 articles) into Contents (MenuId=44, "Tin sự kiện"). Imported as StatusId=1
(draft) for human review before publish, since several articles are republished
from Báo Cần Thơ with source attribution kept in the body/via source note.
Images downloaded to wwwroot/uploads/tin-su-kien/. Idempotent — guarded by
QueryString, safe to re-run.
*/

SET QUOTED_IDENTIFIER ON;
GO

DECLARE @Now DATETIME = GETDATE();

CREATE TABLE #NewsSeed (
    QueryString NVARCHAR(300),
    Title NVARCHAR(MAX),
    Contents NVARCHAR(MAX),
    Author NVARCHAR(MAX),
    Description NVARCHAR(500),
    Image VARCHAR(300),
    PublishedDate DATE
);


     PublishedDate, LanguageId, Domain, SiteId, Created, Modified, IsHot, Viewed)
SELECT
    s.Title, s.QueryString, s.Description, s.Contents, s.Author, 1, 44, s.Image,
    s.PublishedDate, 1, 'VN', 1, @Now, @Now, 0, 0
FROM #NewsSeed s
WHERE NOT EXISTS (SELECT 1 FROM Contents c WHERE c.QueryString = s.QueryString AND c.MenuId = 44);

DROP TABLE #NewsSeed;
GO